import crypto from "node:crypto";
import type { NextRequest } from "next/server";
import { getServerSession } from "next-auth";

import { authOptions } from "../shared/infrastructure/auth";
import { prisma } from "../shared/infrastructure/db";
import { logger } from "../shared/infrastructure/logger";
import { redisClient } from "../shared/infrastructure/redis";
import { getIp, getUa } from "../shared/lib/request-context";

type Props = {
  req: NextRequest;
};

export async function createContext({ req }: Props) {
  const ip = getIp(req);
  const userAgent = getUa(req);
  const requestInfo = { ip, userAgent };

  const authHeader = req.headers.get("authorization");
  if (typeof authHeader === "string" && authHeader.startsWith("Bearer ")) {
    const token = authHeader.split(" ")[1];
    if (token != null && token.startsWith("dxnx_")) {
      const hashedToken = crypto.createHash("sha256").update(token).digest("hex");

      const keyRecord = await prisma.apiKey.findUnique({
        include: { user: true },
        where: { hashedKey: hashedToken },
      });

      if (keyRecord?.revoked === false) {
        prisma.apiKey
          .update({
            data: { lastUsed: new Date() },
            where: { id: keyRecord.id },
          })
          .catch((error) =>
            logger.error({
              error:
                error instanceof Error ? { message: error.message, stack: error.stack } : error,
              keyId: keyRecord.id,
              msg: "Failed to update api key lastUsed",
            })
          );

        return {
          prisma,
          redis: redisClient,
          req,
          requestInfo,
          session: {
            expires: new Date(Date.now() + 1000 * 60 * 60 * 24).toISOString(),
            user: keyRecord.user,
          },
        };
      }
    }
  }

  const session = await getServerSession(authOptions);
  return {
    prisma,
    redis: redisClient,
    req,
    requestInfo,
    session,
  };
}

export type Context = Awaited<ReturnType<typeof createContext>>;

import { NotifyType, Status, Visibility } from "@prisma/client";
import { z } from "zod";

type ValidatePairType = { repoName?: string; repoOwner?: string };

export const PaginationSchema = z.object({
  cursor: z.coerce.number().int().min(1).max(1_000_000).nullish(),
  limit: z.coerce.number().int().min(1).max(100).default(10),
  search: z.string().trim().max(1000).optional(),
});

export const RepoFilterSchema = PaginationSchema.extend({
  owner: z.string().trim().min(1).max(39).optional(),
  sortBy: z.enum(["name", "updatedAt", "createdAt"]).default("updatedAt"),
  sortOrder: z.enum(["asc", "desc"]).default("desc"),
  status: z.enum(Status).optional(),
  visibility: z.enum(Visibility).optional(),
});

export type RepoFiltersInput = z.infer<typeof RepoFilterSchema>;

const repoIdentityFields = {
  repoName: z.string().trim().min(1).max(255).optional(),
  repoOwner: z.string().trim().min(1).max(39).optional(),
};

const validateRepoPair = (data: ValidatePairType, ctx: z.RefinementCtx) => {
  if ((data.repoName == null) !== (data.repoOwner == null)) {
    const message = "repoName and repoOwner must be provided together";
    ctx.addIssue({ code: "custom", message, path: ["repoName"] });
    ctx.addIssue({ code: "custom", message, path: ["repoOwner"] });
  }
};

export const NotificationsFilterSchema = PaginationSchema.extend({
  ...repoIdentityFields,
  isRead: z.boolean().optional(),
  type: z.enum(NotifyType).optional(),
}).superRefine(validateRepoPair);

export type NotificationsFilterInput = z.infer<typeof NotificationsFilterSchema>;

export const NotificationsBulkFilterSchema = z
  .object({
    ...repoIdentityFields,
    search: z.string().trim().max(1000).optional(),
    type: z.enum(NotifyType).optional(),
  })
  .superRefine(validateRepoPair);

export type NotificationsBulkFilterInput = z.infer<typeof NotificationsBulkFilterSchema>;

export const OpenApiErrorResponses = {
  400: "Invalid request",
  401: "Authorization required",
  403: "Insufficient permissions",
  404: "Resource not found",
  409: "Resource conflict",
  422: "Data validation error",
  429: "Too many requests",
  500: "Internal server error",
  503: "Service temporarily unavailable",
} as const;

import { z } from "zod";

import { analyticsService } from "@/server/entities/analyze/api/analytics.service";
import { StatusSchema } from "@/generated/zod";

import { OpenApiErrorResponses } from "../contracts";
import { createTRPCRouter, protectedProcedure } from "../trpc";

export const analyticsRouter = createTRPCRouter({
  getDashboardStats: protectedProcedure
    .meta({
      openapi: {
        description: "Returns aggregated metrics, global scores, and language distribution.",
        errorResponses: OpenApiErrorResponses,
        method: "GET",
        path: "/analytics",
        protect: true,
        summary: "Get rich dashboard statistics",
        tags: ["analytics"],
      },
    })
    .input(z.void())
    .output(
      z.object({
        analysisStats: z.object({
          failed: z.number(),
          pending: z.number(),
          success: z.number(),
          total: z.number(),
        }),
        highlights: z.object({
          mostCritical: z.object({ name: z.string(), score: z.number() }).nullable(),
          topPerformer: z.object({ name: z.string(), score: z.number() }).nullable(),
        }),
        languages: z.array(
          z.object({
            color: z.string(),
            name: z.string(),
            value: z.number(),
          })
        ),
        overview: z.object({
          avgComplexityScore: z.number(),
          avgHealthScore: z.number(),
          avgOnboardingScore: z.number(),
          avgSecurityScore: z.number(),
          avgTechDebtScore: z.number(),
          criticalRepoCount: z.number(),
          docsCount: z.number(),
          repoCount: z.number(),
          totalLoc: z.number(),
        }),
        recentActivity: z.array(
          z.object({
            createdAt: z.date(),
            id: z.string(),
            progress: z.number(),
            repoName: z.string(),
            repoOwner: z.string(),
            status: StatusSchema,
          })
        ),
      })
    )
    .query(async ({ ctx }) => {
      return analyticsService.getDashboardStats(ctx.db);
    }),

  getTrends: protectedProcedure
    .input(z.void())
    .output(
      z.array(
        z.object({
          complexity: z.number(),
          date: z.string(),
          fullDate: z.string(),
          health: z.number(),
          onboarding: z.number(),
          security: z.number(),
          techDebt: z.number(),
        })
      )
    )
    .query(async ({ ctx }) => {
      return analyticsService.getTrends(ctx.db);
    }),
});

import { z } from "zod";

import { CreateApiKeySchema } from "@/shared/api/schemas/api-key";

import { apiKeyService } from "@/server/entities/api-key/api/api-key.service";
import { ApiKeySchema } from "@/generated/zod";

import { OpenApiErrorResponses } from "../contracts";
import { createTRPCRouter, protectedProcedure } from "../trpc";

export const apiKeyRouter = createTRPCRouter({
  create: protectedProcedure
    .meta({
      openapi: {
        description: "Generates a new API Key. The full key is shown only once.",
        errorResponses: OpenApiErrorResponses,
        method: "POST",
        path: "/api-keys",
        protect: true,
        summary: "Create API Key",
        tags: ["api-keys"],
      },
    })
    .input(CreateApiKeySchema)
    .output(z.object({ key: z.string(), message: z.string() }))
    .mutation(async ({ ctx, input }) => {
      return apiKeyService.create(ctx.db, Number(ctx.session.user.id), input);
    }),

  list: protectedProcedure
    .meta({
      openapi: {
        description: "Returns all active and revoked API keys for the current user.",
        errorResponses: OpenApiErrorResponses,
        method: "GET",
        path: "/api-keys",
        protect: true,
        summary: "List API Keys",
        tags: ["api-keys"],
      },
    })
    .input(z.void())
    .output(
      z.object({
        active: z.array(ApiKeySchema),
        archived: z.array(ApiKeySchema),
      })
    )
    .query(async ({ ctx }) => {
      return apiKeyService.list(ctx.db);
    }),

  revoke: protectedProcedure
    .meta({
      openapi: {
        description: "Permanently revokes an API key. It can no longer be used for authentication.",
        errorResponses: OpenApiErrorResponses,
        method: "DELETE",
        path: "/api-keys/{id}",
        protect: true,
        summary: "Revoke API Key",
        tags: ["api-keys"],
      },
    })
    .input(z.object({ id: z.uuid() }))
    .output(z.object({ message: z.string(), success: z.boolean() }))
    .mutation(async ({ ctx, input }) => {
      return apiKeyService.revoke(ctx.db, input.id);
    }),

  touch: protectedProcedure
    .meta({
      openapi: {
        description: "Updates the lastUsed timestamp for the specified API key.",
        errorResponses: OpenApiErrorResponses,
        method: "PATCH",
        path: "/api-keys/{id}/touch",
        protect: true,
        summary: "Touch API Key",
        tags: ["api-keys"],
      },
    })
    .input(z.object({ id: z.uuid() }))
    .output(z.object({ success: z.boolean() }))
    .mutation(async ({ ctx, input }) => {
      return apiKeyService.touch(ctx.db, input.id);
    }),

  update: protectedProcedure
    .meta({
      openapi: {
        description: "Updates the name or description of an existing API key.",
        errorResponses: OpenApiErrorResponses,
        method: "PATCH",
        path: "/api-keys/{id}",
        protect: true,
        summary: "Update API Key",
        tags: ["api-keys"],
      },
    })
    .input(z.intersection(CreateApiKeySchema, z.object({ id: z.uuid() })))
    .output(z.object({ message: z.string(), success: z.boolean() }))
    .mutation(async ({ ctx, input }) => {
      return apiKeyService.update(ctx.db, input.id, input);
    }),
});

