import { z } from "zod";

import { handlePrismaError } from "@/server/shared/lib/handle-error";

import { OpenApiErrorResponses } from "../contracts";
import { createTRPCRouter, publicProcedure } from "../trpc";

export const healthRouter = createTRPCRouter({
  check: publicProcedure
    .meta({
      openapi: {
        description:
          "Checks the current status and availability of the service. Returns basic operational information to confirm that the service is running correctly.",
        errorResponses: OpenApiErrorResponses,
        method: "GET",
        path: "/health",
        summary: "Service health check",
        tags: ["health"],
      },
    })
    .input(z.void())
    .output(
      z.object({
        status: z.string(),
      })
    )
    .query(async ({ ctx }) => {
      try {
        await ctx.prisma.$queryRaw`SELECT 1`;
        return { status: "ok" };
      } catch (error) {
        handlePrismaError(error, {
          defaultConflict: "Service temporarily unavailable",
        });
      }
    }),
});

import { createTRPCRouter } from "../trpc";
import { analyticsRouter } from "./analytics.router";
