  documentFile: protectedProcedure
    .input(
      z.object({
        content: z.string(),
        language: z.string().default("Russian"),
        nodeId: z.string().optional(),
        path: z.string(),
        repoId: z.string(),
      })
    )
    .mutation(async ({ ctx, input }) => {
      return repoAnalysisService.documentFile(ctx.db, Number(ctx.session.user.id), input);
