import "server-only";

import { cache } from "react";
import { headers } from "next/headers";
import { NextRequest } from "next/server";

import { TRPC_PREFIX } from "@/shared/constants/env.client";
import { IS_DEV } from "@/shared/constants/env.flags";

import { createContext } from "./context";
import { appRouter } from "./routers";
import { createCallerFactory } from "./trpc";

const caller = createCallerFactory(appRouter);

export const api = cache(async () => {
  const heads = new Headers(await headers());
  heads.set("x-trpc-source", "rsc");

  const protocol = IS_DEV ? "http" : "https";
  const host = heads.get("host") ?? "localhost:3000";

  const ctx = await createContext({
    req: new NextRequest(`${protocol}://${host}${TRPC_PREFIX}`, { headers: heads }),
  });

  return caller(ctx);
});

import type { UserRole } from "@prisma/client";
import { initTRPC, TRPCError } from "@trpc/server";
import { enhance } from "@zenstackhq/runtime";
import superjson from "superjson";
import type { OpenApiMeta } from "trpc-to-openapi";

import { IS_PROD } from "@/shared/constants/env.flags";

import type { DbClient } from "../shared/infrastructure/db";
import { logger } from "../shared/infrastructure/logger";
import { buildRequestStore, requestContext, resolveRequestId } from "../shared/lib/request-context";
import type { Context } from "./context";

export const t = initTRPC
  .context<Context>()
  .meta<OpenApiMeta>()
  .create({
    errorFormatter({ ctx, error, shape }) {
      const publicErrors = [
        "BAD_REQUEST",
        "CONFLICT",
        "UNAUTHORIZED",
        "FORBIDDEN",
        "TOO_MANY_REQUESTS",
        "NOT_FOUND",
      ];

      const isPublicError = publicErrors.includes(error.code);

      return {
        ...shape,
        data: {
          ...shape.data,
          requestId: resolveRequestId(ctx?.req, requestContext.getStore()?.requestId),
          stack: IS_PROD ? undefined : error.stack,
          zodError: error.code === "BAD_REQUEST" ? error.cause : null,
        },
        message:
          IS_PROD && !isPublicError
            ? "An unexpected error occurred, please try again later."
            : error.message,
      };
    },
    transformer: superjson,
  });

const withZenStack = t.middleware(async ({ ctx, next }) => {
  const sessionUser = ctx.session?.user;
  const userId = sessionUser == null ? undefined : Number(sessionUser.id);

  const userRole = sessionUser?.role == null ? undefined : (sessionUser.role as UserRole);

  const protectedDb = enhance(ctx.prisma, {
    user: userId == null ? undefined : { id: userId, role: userRole },
  }) as unknown as DbClient;

  return next({
    ctx: {
      ...ctx,
      db: protectedDb,
    },
  });
});

const contextMiddleware = t.middleware(async ({ ctx, next, path, type }) => {
  const sessionUser = ctx.session?.user;

  const store = buildRequestStore({
    method: type,
    path,
    req: ctx.req,
    userId: sessionUser?.id == null ? undefined : Number(sessionUser.id),
    userRole: sessionUser?.role,
  });

  return requestContext.run(store, () => next({ ctx }));
});

const loggerMiddleware = t.middleware(async ({ next, path, type }) => {
  const start = performance.now();
  const result = await next();
  const durationMs = Number((performance.now() - start).toFixed(2));

  const meta = { durationMs, path, type };

  if (result.ok) {
    logger.info({ ...meta, msg: `tRPC [${type}] ok: ${path}` });
  } else {
    logger.error({
      ...meta,
      code: result.error.code,
      message: result.error.message,
      msg: `tRPC [${type}] error: ${path}`,
      stack: result.error.code === "INTERNAL_SERVER_ERROR" ? result.error.stack : undefined,
    });
    if (IS_PROD) {
      await logger.flush();
    }
  }
  return result;
});

export const createTRPCRouter = t.router;
export const createCallerFactory = t.createCallerFactory;
export const publicProcedure = t.procedure
  .use(contextMiddleware)
  .use(loggerMiddleware)
  .use(withZenStack);

const isAuthed = t.middleware(({ ctx, next }) => {
  if (ctx.session?.user == null) {
    throw new TRPCError({ code: "UNAUTHORIZED", message: "You are not logged in" });
  }

  return next({
    ctx: {
      session: { ...ctx.session, user: ctx.session.user },
    },
  });
});

export const protectedProcedure = publicProcedure.use(isAuthed);

const isAdmin = t.middleware(({ ctx, next }) => {
  if (ctx.session?.user.role !== "ADMIN") {
    throw new TRPCError({ code: "FORBIDDEN", message: "Admin rights required" });
  }

  return next({ ctx });
});

export const adminProcedure = protectedProcedure.use(isAdmin);

import { z } from "zod";

import type { DbClient } from "@/server/shared/infrastructure/db";

const LanguageMetricSchema = z.object({
  color: z.string(),
  lines: z.number(),
  name: z.string(),
});

const MetricsJsonSchema = z.object({
  languages: z.array(LanguageMetricSchema).optional(),
  totalLoc: z.number().optional(),
});

export const analyticsService = {
  async getDashboardStats(db: DbClient) {
    const [
      repoCount,
      docsCount,
      analysisStats,
      aggregates,
      recentAnalyses,
      reposWithMetrics,
      worstRepo,
      bestRepo,
      criticalRepoCount,
    ] = await Promise.all([
      db.repo.count(),

      db.document.count(),

      db.analysis.groupBy({
        _count: { status: true },
        by: ["status"],
      }),

      db.analysis.aggregate({
        _avg: {
          complexityScore: true,
          onboardingScore: true,
          score: true,
          securityScore: true,
          techDebtScore: true,
        },
        where: { status: "DONE" },
      }),

      db.analysis.findMany({
        include: { repo: { select: { name: true, owner: true } } },
        orderBy: { createdAt: "desc" },
        take: 5,
      }),

      db.repo.findMany({
        select: {
          analyses: {
            orderBy: { createdAt: "desc" },
            select: { metricsJson: true },
            take: 1,
            where: { status: "DONE" },
          },
        },
      }),
      db.analysis.findFirst({
        orderBy: { score: "asc" },
        select: { repo: { select: { name: true } }, score: true },
        where: { score: { gt: 0, lt: 50 }, status: "DONE" },
      }),

      db.analysis.findFirst({
        orderBy: { score: "desc" },
        select: { repo: { select: { name: true } }, score: true },
        where: { status: "DONE" },
      }),
      db.repo.count({
        where: {
          analyses: {
            some: {
              score: { gt: 0, lt: 50 },
              status: "DONE",
            },
          },
        },
      }),
    ]);

    const statsMap = analysisStats.reduce(
      (acc, curr) => {
        acc[curr.status] = curr._count.status;
        return acc;
      },
      {} as Record<string, number>
    );

    const langMap = new Map<string, { color: string; lines: number }>();
    let globalTotalLoc = 0;

    reposWithMetrics.forEach((repo) => {
      const metrics = repo.analyses[0]?.metricsJson;
      if (metrics == null) return;

      const parsed = MetricsJsonSchema.safeParse(metrics);
      if (parsed.success) {
        globalTotalLoc += parsed.data.totalLoc ?? 0;
        parsed.data.languages?.forEach((lang) => {
          const current = langMap.get(lang.name) || { color: lang.color, lines: 0 };
          langMap.set(lang.name, {
            color: lang.color,
            lines: current.lines + lang.lines,
          });
        });
      }
    });

    const sortedLanguages = Array.from(langMap.entries())
      .map(([name, data]) => ({ color: data.color, name, value: data.lines }))
      .sort((a, b) => b.value - a.value);

    const topLanguages = sortedLanguages.slice(0, 5);
    const otherLines = sortedLanguages.slice(5).reduce((acc, curr) => acc + curr.value, 0);

    if (otherLines > 0) {
      topLanguages.push({ color: "#808080", name: "Other", value: otherLines });
    }

    return {
      analysisStats: {
        failed: statsMap["FAILED"] ?? 0,
        pending: (statsMap["PENDING"] ?? 0) + (statsMap["NEW"] ?? 0),
        success: statsMap["DONE"] ?? 0,
        total: Object.values(statsMap).reduce((a, b) => a + b, 0),
      },
      highlights: {
        mostCritical:
          worstRepo == null ? null : { name: worstRepo.repo.name, score: worstRepo.score ?? 0 },
        topPerformer:
          bestRepo == null ? null : { name: bestRepo.repo.name, score: bestRepo.score ?? 0 },
      },
      languages: topLanguages,
      overview: {
        avgComplexityScore: Math.round(aggregates._avg.complexityScore ?? 0),
        avgHealthScore: Math.round(aggregates._avg.score ?? 0),
        avgOnboardingScore: Math.round(aggregates._avg.onboardingScore ?? 0),
        avgSecurityScore: Math.round(aggregates._avg.securityScore ?? 0),
        avgTechDebtScore: Math.round(aggregates._avg.techDebtScore ?? 0),
        criticalRepoCount,
        docsCount,
        repoCount,
        totalLoc: globalTotalLoc,
      },
      recentActivity: recentAnalyses.map((a) => ({
        createdAt: a.createdAt,
        id: a.publicId,
        progress: a.progress,
        repoName: a.repo.name,
        repoOwner: a.repo.owner,
        status: a.status,
      })),
    };
  },

  async getTrends(db: DbClient) {
    const thirtyDaysAgo = new Date();
    thirtyDaysAgo.setDate(thirtyDaysAgo.getDate() - 30);

    const analyses = await db.analysis.findMany({
      orderBy: { createdAt: "asc" },
      select: {
        complexityScore: true,
        createdAt: true,
        onboardingScore: true,
        score: true,
        securityScore: true,
        techDebtScore: true,
      },
      where: {
        createdAt: { gte: thirtyDaysAgo },
        status: "DONE",
      },
    });

    const dateFormatter = new Intl.DateTimeFormat("en-US", {
      day: "numeric",
      month: "short",
      timeZone: "UTC",
    });

    const grouped = new Map<
      string,
      {
        compSum: number;
        count: number;
        debtSum: number;
        healthSum: number;
        onbSum: number;
        secSum: number;
      }
    >();

    analyses.forEach((a) => {
      const dateKey = a.createdAt.toISOString().slice(0, 10);

      if (!grouped.has(dateKey)) {
        grouped.set(dateKey, {
          compSum: 0,
          count: 0,
          debtSum: 0,
          healthSum: 0,
          onbSum: 0,
          secSum: 0,
        });
      }

      const entry = grouped.get(dateKey)!;
      entry.healthSum += a.score ?? 0;
      entry.secSum += a.securityScore ?? 0;
      entry.compSum += a.complexityScore ?? 0;
      entry.onbSum += a.onboardingScore ?? 0;
      entry.debtSum += a.techDebtScore ?? 0;
      entry.count += 1;
    });

    return Array.from(grouped.entries()).map(([fullDate, data]) => ({
      complexity: Math.round(data.compSum / data.count),
      date: dateFormatter.format(new Date(`${fullDate}T00:00:00.000Z`)),
      fullDate,
      health: Math.round(data.healthSum / data.count),
      onboarding: Math.round(data.onbSum / data.count),
      security: Math.round(data.secSum / data.count),
      techDebt: Math.round(data.debtSum / data.count),
    }));
  },
};

import type {
  LatestCompletedAnalysis,
  RepoWithLatestAnalysisAndDocs,
} from "@/server/shared/infrastructure/repo-snapshots";
import { getLanguageColor } from "@/server/shared/lib/language-metadata";
import { hasText } from "@/server/shared/lib/string-utils";

import { buildStructureMapPayload, buildStructureNodePayload } from "../lib/graph-navigator";
import { buildNodeExplainPayload } from "../lib/node-explainer";
import {
  coerceAnalysisPayload,
  dedupeLatestDocsByType,
  normalizeWriterStatuses,
  toDocSummary,
} from "../lib/payload";

export const repoDetailsPresenter = {
  toAvailableDocs(repo: Pick<RepoWithLatestAnalysisAndDocs, "analyses" | "documents">) {
    const latestAnalysis = coerceAnalysisPayload(repo.analyses[0]);
    return dedupeLatestDocsByType(repo.documents).map((doc) =>
      toDocSummary(doc, latestAnalysis?.aiResult ?? null)
    );
  },

  toDetailedMetrics(analysis: LatestCompletedAnalysis | null) {
    const payload = coerceAnalysisPayload(analysis);
    if (payload == null) return null;

    const { aiResult, metrics } = payload;
    const findings = aiResult.findings ?? [];
    const facts = aiResult.repository_facts ?? [];

    return {
      architecture: {
        analysisCoverage: metrics.analysisCoverage,
        configInventory: metrics.configInventory,
        dependencyCycles: metrics.dependencyCycles,
        dependencyHotspots: metrics.dependencyHotspots,
        entrypoints: metrics.entrypoints,
        graphReliability: metrics.graphReliability ?? null,
        hotspotFiles: metrics.hotspotFiles,
        orphanModules: metrics.orphanModules,
        routeInventory: metrics.routeInventory ?? null,
      },
      onboarding: {
        guide: aiResult.onboarding_guide,
        score: metrics.onboardingScore,
        teamRoles: metrics.teamRoles,
      },
      quality: {
        analysisCoverage: metrics.analysisCoverage,
        busFactor: metrics.busFactor,
        complexity: metrics.complexityScore,
        dependencyCycles: metrics.dependencyCycles.length,
        docDensity: metrics.docDensity,
        duplicationPercentage: metrics.duplicationPercentage,
        health: metrics.healthScore,
        modularity: metrics.modularityIndex,
        security: metrics.securityScore,
        techDebt: metrics.techDebtScore,
      },
      recommendations: {
        bottlenecks: aiResult.mainBottlenecks ?? [],
        performance: aiResult.sections.performance,
        refactoringTargets: aiResult.refactoring_targets,
        techDebt: aiResult.sections.tech_debt,
      },
      reference: {
        apiStructure: aiResult.sections.api_structure,
        dataFlow: aiResult.sections.data_flow,
        swagger: aiResult.swaggerYaml ?? null,
      },
      risks: {
        facts,
        findings,
        hotspotFiles: metrics.hotspotFiles,
        topRisks: findings.slice(0, 5),
      },
      security: {
        findings: metrics.securityFindings,
        risks: aiResult.sections.security_audit.risks,
        score: aiResult.sections.security_audit.score,
        securityScanStatus: metrics.securityScanStatus,
        vulnerabilities: aiResult.vulnerabilities ?? [],
      },
    };
  },

  toNodeExplain(repo: RepoWithLatestAnalysisAndDocs, nodeId: string) {
    return buildNodeExplainPayload(repo, nodeId);
  },

  toOverview(repo: RepoWithLatestAnalysisAndDocs) {
    const payload = coerceAnalysisPayload(repo.analyses[0]);
    if (payload == null) return null;

    const { aiResult, metrics } = payload;
    const docs = this.toAvailableDocs(repo);

    return {
      docs: {
        availableCount: docs.length,
        availableTypes: docs.map((doc) => doc.type),
        hasSwagger: hasText(aiResult.swaggerYaml),
        items: docs,
        writers: normalizeWriterStatuses(aiResult),
      },
      languages: metrics.languages,
      maintenance: metrics.maintenanceStatus,
      mostComplexFiles: metrics.mostComplexFiles,
      repo: {
        defaultBranch: repo.defaultBranch,
        description: repo.description,
        forks: repo.forks,
        id: repo.publicId,
        language: repo.language,
        languageColor: getLanguageColor(repo.language),
        license: repo.license,
        name: repo.name,
        openIssues: repo.openIssues,
        owner: repo.owner,
        ownerAvatarUrl: repo.ownerAvatarUrl,
        pushedAt: repo.pushedAt,
        size: repo.size,
        stars: repo.stars,
        topics: repo.topics,
        url: repo.url,
        visibility: repo.visibility,
      },
      scores: {
        complexity: metrics.complexityScore,
        health: metrics.healthScore,
        onboarding: metrics.onboardingScore,
        security: metrics.securityScore,
        techDebt: metrics.techDebtScore,
      },
      signals: {
        analysisCoverage: metrics.analysisCoverage,
        apiSurface: metrics.apiSurface,
        busFactor: metrics.busFactor,
        dependencyCycles: metrics.dependencyCycles.length,
        docDensity: metrics.docDensity,
        duplicationPercentage: metrics.duplicationPercentage,
      },
      stats: {
        configFiles: metrics.configFiles,
        fileCount: metrics.fileCount,
        linesOfCode: metrics.totalLoc,
        totalSizeKb: metrics.totalSizeKb,
        totalSizeLabel: `${metrics.totalSizeKb} KB`,
      },
      summary: aiResult.executive_summary,
      teamRoles: metrics.teamRoles,
      topRisks: (aiResult.findings ?? []).slice(0, 3),
    };
  },

  toStructureMap(repo: RepoWithLatestAnalysisAndDocs) {
    return buildStructureMapPayload(repo);
  },

  toStructureNode(repo: RepoWithLatestAnalysisAndDocs, nodeId: string) {
    return buildStructureNodePayload(repo, nodeId);
  },
};

import { unstable_cache } from "next/cache";
import type { DocType } from "@prisma/client";
import { TRPCError } from "@trpc/server";

import { highlightCode } from "@/shared/lib/shiki";

import type { DbClient } from "@/server/shared/infrastructure/db";
import {
  getLatestCompletedAnalysis,
  getRepoWithLatestAnalysisAndDocs,
} from "@/server/shared/infrastructure/repo-snapshots";
import { markdownToHtml } from "@/server/shared/lib/markdown-to-html";

import { createAnalyzeContextBuilder } from "../lib/analyze-context-builder";
import {
  buildInteractiveBriefNodePayload,
  buildInteractiveBriefPanel,
  buildInteractiveBriefPayload,
} from "../lib/brief";
import { repoDetailsPresenter } from "./repo-details.presenter";

type ExplainPayload = NonNullable<
  ReturnType<ReturnType<typeof createAnalyzeContextBuilder>["getNodeExplain"]>
>;
type StructureNodePayload = NonNullable<
  ReturnType<ReturnType<typeof createAnalyzeContextBuilder>["getStructureNode"]>
>;

function toBriefPanelInput(params: {
  explain: NonNullable<
    ReturnType<ReturnType<typeof createAnalyzeContextBuilder>["getNodeExplain"]>
  >;
  structureNode: NonNullable<
    ReturnType<ReturnType<typeof createAnalyzeContextBuilder>["getStructureNode"]>
  >;
}) {
  return {
    explain: mapExplainBase(params.explain),
    structureNode: mapStructureNodeBase(params.structureNode),
  };
}

function toInteractiveBriefNodePayloadInput(params: {
  explain: ExplainPayload;
  structureNode: StructureNodePayload;
}) {
  return {
    explain: {
      analysisRef: params.explain.analysisRef ?? null,
      ...mapExplainBase(params.explain),
    },
    structureNode: {
      analysisRef: params.structureNode.analysisRef ?? null,
      ...mapStructureNodeBase(params.structureNode),
    },
  };
}

export const repoDetailsService = {
  async getAvailableDocs(db: DbClient, repoId: string) {
    const repo = await loadRepoOrThrow(db, repoId);
    return repoDetailsPresenter.toAvailableDocs(repo);
  },

  async getDetailedMetrics(db: DbClient, repoId: string) {
    const analysis = await getLatestCompletedAnalysis(db, repoId);
    return repoDetailsPresenter.toDetailedMetrics(analysis);
  },

  async getDocumentContent(db: DbClient, repoId: string, type: DocType) {
    const doc = await db.document.findFirst({
      orderBy: { createdAt: "desc" },
      where: {
        repo: { publicId: repoId },
        type,
      },
    });

    if (doc == null) throw new TRPCError({ code: "NOT_FOUND" });

    const html = await unstable_cache(
      async () => markdownToHtml(doc.content),
      [`doc-html-${doc.publicId}`],
      {
        revalidate: false,
        tags: ["docs", doc.publicId],
      }
    )();

    return { html, id: doc.publicId };
  },

  async getHistory(db: DbClient, repoId: string) {
    const history = await db.analysis.findMany({
      orderBy: { createdAt: "desc" },
      select: {
        commitSha: true,
        createdAt: true,
        message: true,
        publicId: true,
        score: true,
        status: true,
      },
      where: { repo: { publicId: repoId } },
    });

    return history.map((h) => ({
      commitSha: h.commitSha,
      createdAt: h.createdAt,
      id: h.publicId,
      message: h.message,
      score: h.score,
      status: h.status,
    }));
  },

  async getInteractiveBrief(db: DbClient, repoId: string) {
    const repo = await loadRepoOrThrow(db, repoId);
    const analyzeContext = createAnalyzeContextBuilder(repo);
    const overview = repoDetailsPresenter.toOverview(repo);
    const structure = analyzeContext.getStructureMap();

    if (structure == null || overview == null) return null;

    const defaultNodeId = structure.selection.defaultNodeId;
    const panel =
      defaultNodeId == null
        ? null
        : (() => {
            const structureNode = analyzeContext.getStructureNode(defaultNodeId);
            const explain = analyzeContext.getNodeExplain(defaultNodeId);
            if (structureNode == null || explain == null) return null;

            return buildInteractiveBriefPanel(toBriefPanelInput({ explain, structureNode }));
          })();

    return buildInteractiveBriefPayload({
      analysisRef: structure.analysisRef,
      capabilities: {
        canDocumentFile: true,
        canDrillDown: true,
        canExplainNodes: true,
        canHighlightFiles: true,
        canQuickAudit: true,
      },
      defaultNodeId,
      docsSummary: {
        availableCount: overview.docs.availableCount,
        availableTypes: overview.docs.availableTypes,
        hasSwagger: overview.docs.hasSwagger,
      },
      overview: {
        architectureStyle: structure.overview.architectureStyle,
        primaryEntrypoints: structure.overview.primaryEntrypoints,
        primaryModules: structure.overview.primaryModules,
        purpose: structure.overview.purpose,
        repositoryKind: structure.overview.repositoryKind,
        stack: structure.overview.stack,
      },
      panel,
      structure: {
        edges: structure.graph.edges,
        groups: structure.graph.groups,
        nodes: structure.graph.nodes,
      },
    });
  },

  async getInteractiveBriefNode(db: DbClient, repoId: string, nodeId: string) {
    const analyzeContext = await loadAnalyzeContextBuilderOrThrow(db, repoId);
    const structureNode = analyzeContext.getStructureNode(nodeId);
    const explain = analyzeContext.getNodeExplain(nodeId);

    if (structureNode == null || explain == null) return null;

    return buildInteractiveBriefNodePayload(
      toInteractiveBriefNodePayloadInput({ explain, structureNode })
    );
  },

  async getNodeExplain(db: DbClient, repoId: string, nodeId: string) {
    const analyzeContext = await loadAnalyzeContextBuilderOrThrow(db, repoId);
    return analyzeContext.getNodeExplain(nodeId);
  },

  async getOverview(db: DbClient, repoId: string) {
    const repo = await loadRepoOrThrow(db, repoId);
    return repoDetailsPresenter.toOverview(repo);
  },

  async getStructureMap(db: DbClient, repoId: string) {
    const analyzeContext = await loadAnalyzeContextBuilderOrThrow(db, repoId);
    return analyzeContext.getStructureMap();
  },

  async getStructureNode(db: DbClient, repoId: string, nodeId: string) {
    const analyzeContext = await loadAnalyzeContextBuilderOrThrow(db, repoId);
    return analyzeContext.getStructureNode(nodeId);
  },

  async highlightFile(content: string, path: string) {
    const ext = path.split(".").pop() ?? "txt";
    const html = await highlightCode(content, ext);
    return { html };
  },
};

async function loadRepoOrThrow(db: DbClient, repoId: string) {
  const repo = await getRepoWithLatestAnalysisAndDocs(db, repoId);
  if (repo == null) throw new TRPCError({ code: "NOT_FOUND" });
  return repo;
}

async function loadAnalyzeContextBuilderOrThrow(db: DbClient, repoId: string) {
  return createAnalyzeContextBuilder(await loadRepoOrThrow(db, repoId));
}

function mapExplainBase(explain: ExplainPayload) {
  return {
    confidence: explain.confidence,
    nextSuggestedPaths: explain.nextSuggestedPaths,
    relationships: explain.relationships,
    role: explain.role,
    sourcePaths: explain.sourcePaths,
    summary: explain.summary,
    whyImportant: explain.whyImportant,
  };
}

function mapStructureNodeBase(structureNode: StructureNodePayload) {
  return {
    breadcrumbs: structureNode.breadcrumbs.map((item) => ({
      id: item.id,
      label: item.label,
      path: item.path,
    })),
    canDrillDeeper: structureNode.canDrillDeeper,
    children: structureNode.children,
    edges: structureNode.edges,
    inspect: structureNode.inspect,
    node: structureNode.node,
  };
}

import {
  toAnalysisRef,
  type AnalysisRef,
  type RepoWithLatestAnalysisAndDocs,
} from "@/server/shared/infrastructure/repo-snapshots";

import {
  buildStructureMapPayloadFromContext,
  buildStructureNodePayloadFromContext,
  type StructureMapPayload,
  type StructureNodePayload,
} from "./graph-navigator";
import { buildNodeExplainPayloadFromContext, type NodeExplainPayload } from "./node-explainer";
import { buildStructureContext } from "./structure-context";
import type { StructureContext } from "./structure-shared";

type AnalyzeEntityContext = {
  analysisRef: AnalysisRef | null;
  repo: RepoWithLatestAnalysisAndDocs;
  structureContext: null | StructureContext;
};

export class AnalyzeContextBuilder {
  private readonly analysisRef: AnalysisRef | null;
  private readonly explainByNodeId = new Map<string, NodeExplainPayload | null>();
  private readonly nodeById = new Map<string, null | StructureNodePayload>();
  private structureContext: null | StructureContext | undefined;
  private structureMap: null | StructureMapPayload | undefined;

  constructor(private readonly repo: RepoWithLatestAnalysisAndDocs) {
    this.analysisRef = toAnalysisRef(repo.analyses[0]);
  }

  getAnalysisRef() {
    return this.analysisRef;
  }

  getEntityContext(): AnalyzeEntityContext {
    return {
      analysisRef: this.analysisRef,
      repo: this.repo,
      structureContext: this.getStructureContext(),
    };
  }

  getStructureContext() {
    if (this.structureContext === undefined) {
      this.structureContext = buildStructureContext(this.repo);
    }

    return this.structureContext;
  }

  getStructureMap() {
    if (this.structureMap === undefined) {
      const context = this.getStructureContext();
      this.structureMap =
        context == null ? null : buildStructureMapPayloadFromContext(context, this.analysisRef);
    }

    return this.structureMap;
  }

  getStructureNode(nodeId: string) {
    if (!this.nodeById.has(nodeId)) {
      const context = this.getStructureContext();
      this.nodeById.set(
        nodeId,
        context == null
          ? null
          : buildStructureNodePayloadFromContext(context, this.analysisRef, nodeId)
      );
    }

    return this.nodeById.get(nodeId) ?? null;
  }

  getNodeExplain(nodeId: string) {
    if (!this.explainByNodeId.has(nodeId)) {
      const context = this.getStructureContext();
      const structureNode = this.getStructureNode(nodeId);
      this.explainByNodeId.set(
        nodeId,
        context == null || structureNode == null
          ? null
          : buildNodeExplainPayloadFromContext(context, this.analysisRef, nodeId, structureNode)
      );
    }

    return this.explainByNodeId.get(nodeId) ?? null;
  }
}

export function createAnalyzeContextBuilder(repo: RepoWithLatestAnalysisAndDocs) {
  return new AnalyzeContextBuilder(repo);
}

