import type { AIResult } from "@/server/shared/engine/core/analysis-result.schemas";
import { normalizeRepoPath } from "@/server/shared/engine/core/common";
import type { RepoMetrics } from "@/server/shared/engine/core/metrics.types";
import { ProjectPolicy } from "@/server/shared/engine/core/project-policy";
import { unique } from "@/server/shared/lib/array-utils";

import {
  buildGroupKeySet,
  collectGroupsByKind,
  filterMeaningfulEntrypoints,
  getStrongGroups,
} from "./semantics";
import {
  makeStructureNodeId,
  resolveImmediateChildScope,
  type StructureContext,
  type StructureEdgeRelationType,
  type StructureGroupEntry,
} from "./structure-shared";

type StructureNodeSummaryLike = {
  id: string;
  kind: string;
  markers: {
    api: boolean;
    config: boolean;
  };
  nodeType: "file" | "group";
  path: string;
};

function addWeightedEdge(
  edges: Map<
    string,
    { relation: StructureEdgeRelationType; source: string; target: string; weight: number }
  >,
  fromNode: string,
  toNode: string,
  relation: StructureEdgeRelationType,
  weight = 1
) {
  if (fromNode === toNode) return;
  const key = `${fromNode}:${toNode}:${relation}`;
  const current = edges.get(key);
  if (current == null) {
    edges.set(key, { relation, source: fromNode, target: toNode, weight });
    return;
  }
  current.weight += weight;
}
function connectGroupSet(
  edges: Map<
    string,
    { relation: StructureEdgeRelationType; source: string; target: string; weight: number }
  >,
  groups: string[],
  relation: StructureEdgeRelationType,
  weight = 1
) {
  for (let index = 0; index < groups.length; index += 1) {
    const source = groups.at(index);
    if (source == null) continue;

    for (let inner = index + 1; inner < groups.length; inner += 1) {
      const target = groups.at(inner);
      if (target == null) continue;

      addWeightedEdge(edges, source, target, relation, weight);
      addWeightedEdge(edges, target, source, relation, weight);
    }
  }
}
function addGraphPreviewEdges(params: {
  apiPaths: Set<string>;
  edges: Map<
    string,
    { relation: StructureEdgeRelationType; source: string; target: string; weight: number }
  >;
  metrics: RepoMetrics;
}) {
  for (const edge of params.metrics.graphPreviewEdges ?? []) {
    const sourcePath = normalizeRepoPath(edge.fromPath);
    const targetPath = normalizeRepoPath(edge.toPath);

    if (sourcePath === targetPath) continue;
    if (ProjectPolicy.isSensitive(sourcePath) || ProjectPolicy.isSensitive(targetPath)) {
      continue;
    }
    if (ProjectPolicy.isIgnored(sourcePath) || ProjectPolicy.isIgnored(targetPath)) continue;

    const sourceGroup = ProjectPolicy.deriveGroupId(sourcePath);
    const targetGroup = ProjectPolicy.deriveGroupId(targetPath);
    if (sourceGroup === targetGroup) continue;

    const relation: StructureEdgeRelationType =
      params.apiPaths.has(sourcePath) || params.apiPaths.has(targetPath)
        ? "api"
        : ProjectPolicy.isConfigFile(sourcePath) || ProjectPolicy.isConfigFile(targetPath)
          ? "config"
          : "focus";

    addWeightedEdge(params.edges, sourceGroup, targetGroup, relation, Math.max(1, edge.weight));
  }
}
function connectDirectionalGroups(
  edges: Map<
    string,
    { relation: StructureEdgeRelationType; source: string; target: string; weight: number }
  >,
  sources: string[],
  targets: string[],
  relation: StructureEdgeRelationType,
  weight = 1
) {
  for (const source of unique(sources)) {
    for (const target of unique(targets)) {
      addWeightedEdge(edges, source, target, relation, weight);
    }
  }
}
function addSemanticTopologyEdges(
  edges: Map<
    string,
    { relation: StructureEdgeRelationType; source: string; target: string; weight: number }
  >,
  groupMap: Map<string, StructureGroupEntry>,
  primaryEntrypointGroups: string[]
) {
  const groupsByKind = collectGroupsByKind(groupMap);
  const frontendGroups = getStrongGroups(groupsByKind.get("frontend"), groupMap, 3);
  const apiGroups = getStrongGroups(groupsByKind.get("api"), groupMap, 4);
  const backendGroups = getStrongGroups(groupsByKind.get("backend"), groupMap, 4);
  const coreGroups = getStrongGroups(groupsByKind.get("core"), groupMap, 4);
  const dataGroups = getStrongGroups(groupsByKind.get("data"), groupMap, 4);
  const sharedGroups = getStrongGroups(groupsByKind.get("shared"), groupMap, 4);
  const configGroups = getStrongGroups(groupsByKind.get("config"), groupMap, 3);
  const infrastructureGroups = getStrongGroups(groupsByKind.get("infrastructure"), groupMap, 3);

  connectDirectionalGroups(edges, primaryEntrypointGroups, apiGroups, "entrypoint", 4);
  connectDirectionalGroups(edges, primaryEntrypointGroups, backendGroups, "entrypoint", 3);
  connectDirectionalGroups(edges, primaryEntrypointGroups, frontendGroups, "entrypoint", 2);

  connectDirectionalGroups(edges, frontendGroups, apiGroups, "focus", 3);
  connectDirectionalGroups(edges, frontendGroups, sharedGroups, "focus", 2);
  connectDirectionalGroups(edges, apiGroups, backendGroups, "api", 4);
  connectDirectionalGroups(edges, apiGroups, dataGroups, "api", 2);
  connectDirectionalGroups(edges, backendGroups, coreGroups, "focus", 3);
  connectDirectionalGroups(edges, backendGroups, dataGroups, "focus", 3);
  connectDirectionalGroups(edges, backendGroups, sharedGroups, "focus", 2);
  connectDirectionalGroups(edges, coreGroups, dataGroups, "focus", 2);
  connectDirectionalGroups(edges, infrastructureGroups, backendGroups, "config", 2);
  connectDirectionalGroups(edges, infrastructureGroups, dataGroups, "config", 2);
  connectDirectionalGroups(edges, configGroups, backendGroups, "config", 2);
  connectDirectionalGroups(edges, configGroups, apiGroups, "config", 1);
}
export function createStructuralContextEdges(params: {
  aiResult: AIResult;
  apiPaths: Set<string>;
  groupMap: Map<string, StructureGroupEntry>;
  metrics: RepoMetrics;
}) {
  const edges = new Map<
    string,
    { relation: StructureEdgeRelationType; source: string; target: string; weight: number }
  >();
  const docInput = params.metrics.documentationInput;

  const primaryEntrypointGroups = buildGroupKeySet(
    filterMeaningfulEntrypoints(params.metrics.entrypoints),
    params.apiPaths
  );
  const primaryModuleGroups = buildGroupKeySet(
    docInput?.sections.overview.body.primaryModules ?? [],
    params.apiPaths
  );

  for (const source of primaryEntrypointGroups) {
    for (const target of primaryModuleGroups) {
      addWeightedEdge(edges, source, target, "entrypoint", 3);
    }
  }

  addSemanticTopologyEdges(edges, params.groupMap, primaryEntrypointGroups);
  addGraphPreviewEdges({
    apiPaths: params.apiPaths,
    edges,
    metrics: params.metrics,
  });

  connectGroupSet(
    edges,
    buildGroupKeySet(params.metrics.routeInventory?.sourceFiles ?? [], params.apiPaths),
    "api",
    2
  );
  connectGroupSet(
    edges,
    buildGroupKeySet(docInput?.api.publicSurfacePaths ?? [], params.apiPaths),
    "api",
    2
  );
  connectGroupSet(edges, buildGroupKeySet(params.metrics.hotspotFiles, params.apiPaths), "risk", 2);
  connectGroupSet(
    edges,
    buildGroupKeySet(params.metrics.configInventory, params.apiPaths),
    "config",
    1
  );

  for (const cycle of docInput?.architecture.dependencyCycles ?? []) {
    connectGroupSet(edges, buildGroupKeySet(cycle, params.apiPaths), "cycle", 3);
  }

  for (const finding of params.aiResult.findings ?? []) {
    connectGroupSet(
      edges,
      buildGroupKeySet(
        finding.evidence.map((item) => item.path),
        params.apiPaths
      ),
      "risk",
      2
    );
  }

  for (const fact of params.aiResult.repository_facts ?? []) {
    connectGroupSet(
      edges,
      buildGroupKeySet(
        fact.evidence.map((item) => item.path),
        params.apiPaths
      ),
      "focus",
      1
    );
  }

  for (const pathSet of [
    docInput?.sections.onboarding.body.firstLookPaths ?? [],
    docInput?.sections.onboarding.body.apiPaths ?? [],
    docInput?.sections.onboarding.body.configPaths ?? [],
    docInput?.sections.onboarding.body.riskPaths ?? [],
  ]) {
    connectGroupSet(edges, buildGroupKeySet(pathSet, params.apiPaths), "focus", 1);
  }

  return Array.from(edges.values())
    .sort((left, right) => right.weight - left.weight || left.source.localeCompare(right.source))
    .slice(0, 24)
    .map((edge) => ({
      id: `${edge.source}-${edge.target}-${edge.relation}`,
      relation: edge.relation,
      source: edge.source,
      target: edge.target,
      weight: edge.weight,
    }));
}
export function buildDrilldownEdges(params: {
  childNodes: StructureNodeSummaryLike[];
  context: StructureContext;
  parentPath: string;
}) {
  const childIdSet = new Set(params.childNodes.map((child) => child.id));
  const edgeMap = new Map<
    string,
    { relation: StructureEdgeRelationType; source: string; target: string; weight: number }
  >();

  function connectPaths(paths: string[], relation: StructureEdgeRelationType, weight: number) {
    const ids = unique(
      paths
        .map((path) => resolveImmediateChildScope(params.parentPath, normalizeRepoPath(path)))
        .filter((scope): scope is NonNullable<typeof scope> => scope != null)
        .map((scope) => makeStructureNodeId(scope.nodeType, scope.path))
        .filter((id) => childIdSet.has(id))
    );

    for (let index = 0; index < ids.length; index += 1) {
      const source = ids.at(index);
      if (source == null) continue;

      for (let inner = index + 1; inner < ids.length; inner += 1) {
        const target = ids.at(inner);
        if (target == null) continue;

        if (target === source) continue;
        addWeightedEdge(edgeMap, source, target, relation, weight);
        addWeightedEdge(edgeMap, target, source, relation, weight);
      }
    }
  }

  function connectGraphPreviewEdges() {
    for (const edge of params.context.metrics.graphPreviewEdges ?? []) {
      const sourceScope = resolveImmediateChildScope(
        params.parentPath,
        normalizeRepoPath(edge.fromPath)
      );
      const targetScope = resolveImmediateChildScope(
        params.parentPath,
        normalizeRepoPath(edge.toPath)
      );

      if (sourceScope == null || targetScope == null) continue;

      const sourceId = makeStructureNodeId(sourceScope.nodeType, sourceScope.path);
      const targetId = makeStructureNodeId(targetScope.nodeType, targetScope.path);
      if (sourceId === targetId) continue;
      if (!childIdSet.has(sourceId) || !childIdSet.has(targetId)) continue;

      const relation: StructureEdgeRelationType =
        params.context.apiPaths.has(normalizeRepoPath(edge.fromPath)) ||
        params.context.apiPaths.has(normalizeRepoPath(edge.toPath))
          ? "api"
          : ProjectPolicy.isConfigFile(edge.fromPath) || ProjectPolicy.isConfigFile(edge.toPath)
            ? "config"
            : "focus";

      addWeightedEdge(edgeMap, sourceId, targetId, relation, Math.max(1, edge.weight + 1));
      addWeightedEdge(edgeMap, targetId, sourceId, relation, Math.max(1, edge.weight + 1));
    }
  }

  connectPaths(
    [
      ...params.context.meaningfulEntrypoints,
      ...(params.context.docInput?.sections.overview.body.primaryModules ?? []),
    ],
    "entrypoint",
    2
  );
  connectPaths(params.context.metrics.routeInventory?.sourceFiles ?? [], "api", 2);
  connectPaths(params.context.docInput?.api.publicSurfacePaths ?? [], "api", 2);
  connectPaths(params.context.metrics.hotspotFiles, "risk", 2);
  connectPaths(params.context.metrics.configInventory, "config", 1);

  for (const cycle of params.context.docInput?.architecture.dependencyCycles ?? []) {
    connectPaths(cycle, "cycle", 3);
  }

  for (const finding of params.context.aiResult.findings ?? []) {
    connectPaths(
      finding.evidence.map((item) => item.path),
      "risk",
      2
    );
  }

  for (const fact of params.context.aiResult.repository_facts ?? []) {
    connectPaths(
      fact.evidence.map((item) => item.path),
      "focus",
      1
    );
  }

  for (const pathSet of [
    params.context.docInput?.sections.onboarding.body.firstLookPaths ?? [],
    params.context.docInput?.sections.onboarding.body.apiPaths ?? [],
    params.context.docInput?.sections.onboarding.body.configPaths ?? [],
    params.context.docInput?.sections.onboarding.body.riskPaths ?? [],
  ]) {
    connectPaths(pathSet, "focus", 1);
  }

  connectGraphPreviewEdges();

  return Array.from(edgeMap.values())
    .sort((left, right) => right.weight - left.weight || left.source.localeCompare(right.source))
    .slice(0, 24)
    .map((edge) => ({
      id: `${edge.source}-${edge.target}-${edge.relation}`,
      relation: edge.relation,
      source: edge.source,
      target: edge.target,
      weight: edge.weight,
    }));
}

import { normalizeRepoPath } from "@/server/shared/engine/core/common";
import { ProjectPolicy } from "@/server/shared/engine/core/project-policy";
import {
  toAnalysisRef,
  type AnalysisRef,
  type RepoWithLatestAnalysisAndDocs,
} from "@/server/shared/infrastructure/repo-snapshots";
import { unique } from "@/server/shared/lib/array-utils";

import { buildDrilldownEdges } from "./edge-builder";
import { buildInspectPayload } from "./inspect";
import {
  buildGroupKeySet,
  describeGroup,
  getGenericGroupPenalty,
  isMeaningfulChildNode,
  isMeaningfulTopLevelNode,
  rankStructureNode,
  SEMANTIC_META,
  summarizeGroupImportance,
} from "./semantics";
import {
  aggregateEntryForPaths,
  buildBreadcrumbs,
  buildStructureContext,
} from "./structure-context";
import {
  isPathInsideScope,
  makeStructureNodeId,
  parseStructureNodeId,
  resolveImmediateChildScope,
  type StructureContext,
  type StructureGroupEntry,
  type StructureNodeType,
} from "./structure-shared";

const summarizeImportanceHelper = (input: {
  apiCount: number;
  changeCouplingCount: number;
  churnCount: number;
  configCount: number;
  dependencyHotspotCount: number;
  entrypointCount: number;
  frameworkCount: number;
  graphWarningCount: number;
  groupId: string;
  hotspotCount: number;
  orphanCount: number;
  primaryKind: string;
  riskCount: number;
  sampleCount: number;
}) =>
  summarizeGroupImportance({
    ...input,
    primaryKind: input.primaryKind as Parameters<typeof summarizeGroupImportance>[0]["primaryKind"],
  });

export function buildStructureMapPayloadFromContext(
  context: StructureContext,
  analysisRef: AnalysisRef | null
) {
  const summarizeImportance = summarizeImportanceHelper;
  const nodes = buildTopLevelNodes(context);
  const nodeLabelById = new Map(nodes.map((node) => [node.id, node.label] as const));
  const edges = context.rawTopLevelEdges.map((edge) => ({
    ...edge,
    id: `${makeStructureNodeId("group", edge.source)}-${makeStructureNodeId("group", edge.target)}-${edge.relation}`,
    source: makeStructureNodeId("group", edge.source),
    target: makeStructureNodeId("group", edge.target),
  }));

  const inspectByNodeId = Object.fromEntries(
    nodes.map((node) => {
      const entry = context.groupMap.get(node.path)!;
      const outgoing = context.rawTopLevelEdges
        .filter((edge) => edge.source === node.path)
        .sort((left, right) => right.weight - left.weight)
        .map(
          (edge) =>
            nodeLabelById.get(makeStructureNodeId("group", edge.target)) ??
            ProjectPolicy.getGroupLabel(edge.target)
        )
        .slice(0, 5);
      const incoming = context.rawTopLevelEdges
        .filter((edge) => edge.target === node.path)
        .sort((left, right) => right.weight - left.weight)
        .map(
          (edge) =>
            nodeLabelById.get(makeStructureNodeId("group", edge.source)) ??
            ProjectPolicy.getGroupLabel(edge.source)
        )
        .slice(0, 5);

      return [
        node.id,
        buildInspectPayload({
          entry,
          incoming,
          node,
          outgoing,
          semanticLabel: SEMANTIC_META[node.kind].label,
          summarizeImportance,
        }),
      ];
    })
  );

  const defaultNode = selectDefaultTopLevelNode(context, nodes);

  return {
    analysisRef,
    filters: {
      api: nodes.filter((node) => node.markers.api).map((node) => node.id),
      client: nodes.filter((node) => node.markers.client).map((node) => node.id),
      entrypoints: nodes.filter((node) => node.markers.entrypoint).map((node) => node.id),
      server: nodes.filter((node) => node.markers.server).map((node) => node.id),
      shared: nodes.filter((node) => node.markers.shared).map((node) => node.id),
    },
    graph: {
      edges,
      groups: nodes.map((node) => ({
        description: node.description,
        id: node.id,
        label: node.label,
      })),
      nodes,
    },
    inspect: {
      byNodeId: inspectByNodeId,
      defaultNodeId: defaultNode?.id ?? null,
    },
    overview: {
      architectureStyle: context.aiResult.executive_summary.architecture_style,
      primaryEntrypoints: context.meaningfulEntrypoints.slice(0, 6),
      primaryModules: context.docInput?.sections.overview.body.primaryModules.slice(0, 6) ?? [],
      purpose: context.aiResult.executive_summary.purpose,
      repositoryKind: context.docInput?.sections.overview.body.repositoryKind ?? "unknown",
      stack: context.docInput?.sections.overview.body.stackProfile ?? context.metrics.techStack,
    },
    selection: {
      defaultNodeId: defaultNode?.id ?? null,
    },
  };
}
export type StructureMapPayload = NonNullable<
  ReturnType<typeof buildStructureMapPayloadFromContext>
>;

export function buildStructureMapPayload(repo: RepoWithLatestAnalysisAndDocs) {
  const context = buildStructureContext(repo);
  if (context == null) return null;
  const analysisRef = toAnalysisRef(repo.analyses[0]);
  return buildStructureMapPayloadFromContext(context, analysisRef);
}
export function buildTopLevelNodes(context: StructureContext) {
  const nodes = Array.from(context.groupMap.entries())
    .map(([groupId, entry]) =>
      buildStructureNodeSummary({ entry, nodeType: "group", path: groupId })
    )
    .sort(
      (left, right) =>
        rankStructureNode(right) - rankStructureNode(left) || left.label.localeCompare(right.label)
    );

  const prioritized = nodes.filter(isMeaningfulTopLevelNode);
  const fallback = nodes.filter(
    (node) => !prioritized.some((candidate) => candidate.id === node.id)
  );
  return [...prioritized, ...fallback].slice(0, 14);
}
export function selectDefaultTopLevelNode(
  context: StructureContext,
  nodes: ReturnType<typeof buildStructureNodeSummary>[]
) {
  if (nodes.length === 0) return null;

  const firstLookGroups = new Set(
    buildGroupKeySet(
      context.docInput?.sections.onboarding.body.firstLookPaths ?? [],
      context.apiPaths
    )
  );
  const primaryModuleGroups = new Set(
    buildGroupKeySet(
      context.docInput?.sections.overview.body.primaryModules ?? [],
      context.apiPaths
    )
  );
  const entrypointGroups = new Set(
    buildGroupKeySet(context.meaningfulEntrypoints, context.apiPaths)
  );
  const apiGroups = new Set(
    buildGroupKeySet(context.metrics.routeInventory?.sourceFiles ?? [], context.apiPaths)
  );
  const riskGroups = new Set(
    buildGroupKeySet(context.docInput?.sections.onboarding.body.riskPaths ?? [], context.apiPaths)
  );
  const graphWeightByGroup = new Map<string, number>();

  for (const edge of context.rawTopLevelEdges) {
    graphWeightByGroup.set(edge.source, (graphWeightByGroup.get(edge.source) ?? 0) + edge.weight);
    graphWeightByGroup.set(edge.target, (graphWeightByGroup.get(edge.target) ?? 0) + edge.weight);
  }

  const scored = nodes.map((node) => {
    let score = rankStructureNode(node);

    if (firstLookGroups.has(node.path)) score += 28;
    if (primaryModuleGroups.has(node.path)) score += 20;
    if (entrypointGroups.has(node.path)) score += 18;
    if (apiGroups.has(node.path)) score += 14;
    if (riskGroups.has(node.path)) score += 10;

    score += Math.min(14, graphWeightByGroup.get(node.path) ?? 0);

    if (node.kind === "core" || node.kind === "backend" || node.kind === "api") score += 6;
    if (node.kind === "frontend" || node.kind === "data") score += 3;

    score -= getGenericGroupPenalty(node);

    if (node.markers.config && !node.markers.entrypoint && !node.markers.api) score -= 8;
    if (
      node.markers.shared &&
      !node.markers.entrypoint &&
      !node.markers.api &&
      !node.markers.risk
    ) {
      score -= 3;
    }

    return {
      node,
      score,
    };
  });

  return (
    scored.toSorted(
      (left, right) => right.score - left.score || left.node.label.localeCompare(right.node.label)
    )[0]?.node ?? null
  );
}
export function buildStructureNodePayloadFromContext(
  context: StructureContext,
  analysisRef: AnalysisRef | null,
  nodeId: string
) {
  const summarizeImportance = summarizeImportanceHelper;
  const { nodeType, path } = parseStructureNodeId(nodeId);

  if (nodeType === "file") {
    const normalizedPath = normalizeRepoPath(path);
    if (!context.allInterestingPaths.includes(normalizedPath)) return null;

    const entry = aggregateEntryForPaths([normalizedPath], context);
    const node = buildStructureNodeSummary({ entry, nodeType: "file", path: normalizedPath });

    return {
      analysisRef,
      breadcrumbs: buildBreadcrumbs("file", normalizedPath),
      canDrillDeeper: false,
      children: [],
      edges: [],
      inspect: {
        ...buildInspectPayload({
          context,
          currentPath: normalizedPath,
          entry,
          incoming: [],
          node,
          outgoing: [],
          semanticLabel: SEMANTIC_META[node.kind].label,
          summarizeImportance,
        }),
        contains: [],
      },
      node,
    };
  }

  const scopedPaths = context.allInterestingPaths.filter((candidatePath) =>
    isPathInsideScope(candidatePath, path)
  );
  if (scopedPaths.length === 0) return null;

  const entry = aggregateEntryForPaths(scopedPaths, context);
  const node = buildStructureNodeSummary({ entry, nodeType: "group", path });

  const childScopes = new Map<string, { nodeType: StructureNodeType; path: string }>();
  for (const candidatePath of scopedPaths) {
    const scope = resolveImmediateChildScope(path, candidatePath);
    if (scope == null) continue;
    childScopes.set(makeStructureNodeId(scope.nodeType, scope.path), scope);
  }

  const childNodes = Array.from(childScopes.values())
    .map((scope) => {
      const childPaths =
        scope.nodeType === "file"
          ? scopedPaths.filter((candidatePath) => candidatePath === scope.path)
          : scopedPaths.filter((candidatePath) => isPathInsideScope(candidatePath, scope.path));
      const childEntry = aggregateEntryForPaths(childPaths, context);
      return buildStructureNodeSummary({
        entry: childEntry,
        nodeType: scope.nodeType,
        path: scope.path,
      });
    })
    .sort((left, right) => {
      if (left.nodeType !== right.nodeType) return left.nodeType === "group" ? -1 : 1;
      return (
        rankStructureNode(right) - rankStructureNode(left) || left.label.localeCompare(right.label)
      );
    });

  const meaningfulChildren = childNodes.filter(isMeaningfulChildNode);
  const sourceChildren = meaningfulChildren.length > 0 ? meaningfulChildren : childNodes;
  const limitedChildren = [
    ...sourceChildren.filter((child) => child.nodeType === "group").slice(0, 10),
    ...sourceChildren.filter((child) => child.nodeType === "file").slice(0, 6),
  ];
  const edges = buildDrilldownEdges({ childNodes: limitedChildren, context, parentPath: path });

  return {
    analysisRef,
    breadcrumbs: buildBreadcrumbs("group", path),
    canDrillDeeper: limitedChildren.some(
      (child) => child.canDrillDeeper || child.nodeType === "file"
    ),
    children: limitedChildren,
    edges,
    inspect: {
      ...buildInspectPayload({
        context,
        currentPath: path,
        entry,
        incoming: [],
        node,
        outgoing: limitedChildren.map((child) => child.label).slice(0, 5),
        relatedChildPaths: limitedChildren.map((child) => child.path),
        semanticLabel: SEMANTIC_META[node.kind].label,
        summarizeImportance,
      }),
      contains: limitedChildren.map((child) => child.label).slice(0, 8),
    },
    node,
  };
}
export type StructureNodePayload = NonNullable<
  ReturnType<typeof buildStructureNodePayloadFromContext>
>;

export function buildStructureNodePayload(repo: RepoWithLatestAnalysisAndDocs, nodeId: string) {
  const context = buildStructureContext(repo);
  if (context == null) return null;
  const analysisRef = toAnalysisRef(repo.analyses[0]);
  return buildStructureNodePayloadFromContext(context, analysisRef, nodeId);
}
export function buildStructureNodeSummary(params: {
  entry: StructureGroupEntry;
  nodeType: StructureNodeType;
  path: string;
}) {
  const uniquePathsInGroup = unique(params.entry.paths);
  const primaryKind = ProjectPolicy.getPrimarySemanticKind(params.entry.semanticCounts);
  const entrypointCount = unique(params.entry.entrypointDetails.map((item) => item.path)).length;
  const apiCount = unique(params.entry.apiPaths).length;
  const churnCount = unique(params.entry.churnHotspots.map((item) => item.path)).length;
  const changeCouplingCount = unique(
    params.entry.changeCoupling.flatMap((item) => [item.fromPath, item.toPath])
  ).length;
  const configCount = unique(params.entry.configPaths).length;
  const hotspotCount = unique(params.entry.hotspotSignals.map((item) => item.path)).length;
  const dependencyHotspotCount = unique(
    params.entry.dependencyHotspots.map((item) => item.path)
  ).length;
  const graphWarningCount = unique(
    params.entry.graphUnresolvedSamples.map((item) => item.fromPath)
  ).length;
  const orphanCount = unique(params.entry.orphanPaths).length;
  const frameworkCount = unique(params.entry.frameworkNames).length;
  const riskCount = unique(params.entry.riskTitles).length;
  const score =
    entrypointCount * 4 +
    apiCount * 3 +
    riskCount * 2 +
    hotspotCount * 2 +
    churnCount * 2 +
    changeCouplingCount * 2 +
    dependencyHotspotCount * 2 +
    graphWarningCount +
    orphanCount +
    frameworkCount +
    configCount +
    uniquePathsInGroup.length;
  const canDrillDeeper =
    params.nodeType === "group" &&
    uniquePathsInGroup.some((candidatePath) => candidatePath.startsWith(`${params.path}/`));

  return {
    canDrillDeeper,
    description:
      params.nodeType === "group"
        ? describeGroup(params.path, primaryKind)
        : `${params.path}: ${SEMANTIC_META[primaryKind].description}`,
    id: makeStructureNodeId(params.nodeType, params.path),
    kind: primaryKind,
    label:
      params.nodeType === "group"
        ? ProjectPolicy.getGroupLabel(params.path)
        : (params.path.split("/").findLast(Boolean) ?? params.path),
    markers: {
      api: apiCount > 0,
      client: params.entry.semanticCounts.frontend > 0,
      config: configCount > 0,
      entrypoint: entrypointCount > 0,
      risk:
        riskCount > 0 ||
        hotspotCount > 0 ||
        churnCount > 0 ||
        changeCouplingCount > 0 ||
        dependencyHotspotCount > 0 ||
        graphWarningCount > 0 ||
        orphanCount > 0,
      server:
        params.entry.semanticCounts.api > 0 ||
        params.entry.semanticCounts.backend > 0 ||
        params.entry.semanticCounts.core > 0 ||
        params.entry.semanticCounts.data > 0 ||
        params.entry.semanticCounts.infrastructure > 0,
      shared: params.entry.semanticCounts.shared > 0,
    },
    nodeType: params.nodeType,
    path: params.path,
    previewPaths: uniquePathsInGroup.slice(0, 6),
    score,
    stats: {
      apiCount,
      changeCouplingCount,
      churnCount,
      configCount,
      dependencyHotspotCount,
      entrypointCount,
      frameworkCount,
      graphWarningCount,
      hotspotCount,
      orphanCount,
      pathCount: uniquePathsInGroup.length,
      riskCount,
    },
  };
}

import { normalizeRepoPath as normalizePath } from "@/server/shared/engine/core/common";
import { unique } from "@/server/shared/lib/array-utils";

import {
  buildNeighborBucketsForEntry,
  buildNeighborPathsForEntry,
  buildRecommendedActions,
  buildReviewPriority,
  buildSuggestedPathsForEntry,
  type StructureInspectEntryLike as BaseStructureInspectEntryLike,
  type StructureInspectNodeLike as BaseStructureInspectNodeLike,
  type StructureInspectContextLike,
} from "./node-inspection";

type StructureInspectEntryLike = BaseStructureInspectEntryLike & {
  changeCoupling: Array<{ commits: number; fromPath: string; toPath: string }>;
  churnHotspots: Array<{ commitsInWindow: number; path: string }>;
  entrypointDetails: Array<{ path: string; reason?: null | string }>;
  factTitles: string[];
  frameworkNames: string[];
  graphUnresolvedSamples: Array<{ fromPath: string; specifier: string }>;
};

type StructureInspectNodeLike = BaseStructureInspectNodeLike & {
  kind: string;
  label: string;
  path: string;
  previewPaths: string[];
  stats: {
    apiCount: number;
    changeCouplingCount: number;
    churnCount: number;
    configCount: number;
    dependencyHotspotCount: number;
    entrypointCount: number;
    frameworkCount: number;
    graphWarningCount: number;
    hotspotCount: number;
    orphanCount: number;
    pathCount: number;
    riskCount: number;
  };
};

export function buildInspectPayload(params: {
  context?: StructureInspectContextLike;
  currentPath?: string;
  entry: StructureInspectEntryLike;
  incoming: string[];
  node: StructureInspectNodeLike;
  outgoing: string[];
  relatedChildPaths?: string[];
  semanticLabel: string;
  summarizeImportance: (input: {
    apiCount: number;
    changeCouplingCount: number;
    churnCount: number;
    configCount: number;
    dependencyHotspotCount: number;
    entrypointCount: number;
    frameworkCount: number;
    graphWarningCount: number;
    groupId: string;
    hotspotCount: number;
    orphanCount: number;
    primaryKind: string;
    riskCount: number;
    sampleCount: number;
  }) => string;
}) {
  const frameworkHints = unique(params.entry.frameworkNames).slice(0, 5);
  const hotspotHints = unique([
    ...params.entry.hotspotSignals
      .toSorted((left, right) => right.score - left.score)
      .slice(0, 2)
      .map(
        (signal) =>
          `${signal.path} looks hotspot-prone (score ${signal.score}, complexity ${signal.complexity}, churn ${signal.churnScore}).`
      ),
    ...params.entry.dependencyHotspots
      .slice(0, 2)
      .map(
        (hotspot) =>
          `${hotspot.path} is dependency-central (inbound ${hotspot.inbound}, outbound ${hotspot.outbound}, exports ${hotspot.exports}).`
      ),
  ]).slice(0, 4);
  const graphHints = unique([
    ...(params.entry.graphNeighborPaths.length > 0
      ? [`Graph-connected neighbors: ${params.entry.graphNeighborPaths.slice(0, 4).join(", ")}.`]
      : []),
    ...(params.entry.orphanPaths.length > 0
      ? [`Possibly isolated runtime paths: ${params.entry.orphanPaths.slice(0, 3).join(", ")}.`]
      : []),
    ...(params.entry.graphUnresolvedSamples.length > 0
      ? [
          `Dependency resolution is partial here: ${params.entry.graphUnresolvedSamples
            .slice(0, 2)
            .map((sample) => {
              const typedSample = sample as { fromPath: string; specifier: string };
              return `${typedSample.fromPath} -> ${typedSample.specifier}`;
            })
            .join("; ")}.`,
        ]
      : []),
  ]).slice(0, 3);
  const relatedPaths = unique([
    ...params.entry.entrypointDetails.map((item) => normalizePath(item.path)),
    ...params.entry.apiPaths,
    ...params.entry.publicSurfacePaths,
    ...params.entry.hotspotSignals.map((item) => normalizePath(item.path)),
    ...params.entry.dependencyHotspots.map((item) => normalizePath(item.path)),
    ...params.entry.graphNeighborPaths,
    ...params.entry.orphanPaths,
    ...params.entry.configPaths,
    ...params.entry.changeCoupling.flatMap((item) => [
      normalizePath(item.fromPath),
      normalizePath(item.toPath),
    ]),
  ]).slice(0, 8);
  const gitHints = unique([
    ...params.entry.churnHotspots
      .slice(0, 2)
      .map(
        (hotspot) =>
          `${hotspot.path} changed frequently in recent history (${(hotspot as unknown as { commitsInWindow: number }).commitsInWindow} commits in window).`
      ),
    ...params.entry.changeCoupling
      .slice(0, 2)
      .map(
        (pair) =>
          `${pair.fromPath} and ${pair.toPath} often change together (${(pair as unknown as { commits: number }).commits} coupled commits).`
      ),
  ]).slice(0, 4);
  const nextSuggestedPaths =
    params.context == null
      ? []
      : buildSuggestedPathsForEntry({
          context: params.context,
          currentPath: params.currentPath ?? params.node.path,
          entry: params.entry,
          relatedChildPaths: params.relatedChildPaths ?? [],
        });
  const neighborPaths = buildNeighborPathsForEntry({
    currentPath: params.currentPath ?? params.node.path,
    entry: params.entry,
    relatedChildPaths: params.relatedChildPaths ?? [],
  });
  const neighborBuckets = buildNeighborBucketsForEntry({
    currentPath: params.currentPath ?? params.node.path,
    entry: params.entry,
    relatedChildPaths: params.relatedChildPaths ?? [],
  });
  const reviewPriority = buildReviewPriority({
    entry: params.entry,
    node: params.node,
  });

  return {
    apiHints:
      params.node.stats.apiCount === 0
        ? []
        : [
            `API-facing paths in this area: ${params.node.stats.apiCount}.`,
            ...(params.entry.publicSurfacePaths.length > 0
              ? [
                  `Public surface paths: ${unique(params.entry.publicSurfacePaths).slice(0, 3).join(", ")}.`,
                ]
              : []),
            ...(params.entry.graphNeighborPaths.length > 0
              ? [`Graph neighbors: ${params.entry.graphNeighborPaths.slice(0, 3).join(", ")}.`]
              : []),
          ],
    configHints: unique(params.entry.configPaths).slice(0, 5),
    dependsOn: unique(params.outgoing),
    entrypointReason: params.entry.entrypointDetails[0]?.reason ?? null,
    factTitles: unique(params.entry.factTitles).slice(0, 5),
    frameworkHints,
    gitHints,
    graphHints,
    hotspotHints,
    kind: params.semanticLabel,
    neighborBuckets,
    neighborPaths,
    nextSuggestedPaths,
    recommendedActions: buildRecommendedActions({
      entry: params.entry,
      node: params.node,
    }),
    relatedPaths,
    reviewPriority,
    samplePaths: params.node.previewPaths,
    title: params.node.label,
    usedBy: unique(params.incoming),
    whyImportant: params.summarizeImportance({
      apiCount: params.node.stats.apiCount,
      changeCouplingCount: params.node.stats.changeCouplingCount,
      churnCount: params.node.stats.churnCount,
      configCount: params.node.stats.configCount,
      dependencyHotspotCount: params.node.stats.dependencyHotspotCount,
      entrypointCount: params.node.stats.entrypointCount,
      frameworkCount: params.node.stats.frameworkCount,
      graphWarningCount: params.node.stats.graphWarningCount,
      groupId: params.node.path,
      hotspotCount: params.node.stats.hotspotCount,
      orphanCount: params.node.stats.orphanCount,
      primaryKind: params.node.kind,
      riskCount: params.node.stats.riskCount,
      sampleCount: params.node.stats.pathCount,
    }),
  };
}

import { normalizeRepoPath } from "@/server/shared/engine/core/common";
import {
  toAnalysisRef,
  type AnalysisRef,
  type RepoWithLatestAnalysisAndDocs,
} from "@/server/shared/infrastructure/repo-snapshots";
import { unique } from "@/server/shared/lib/array-utils";

import { buildStructureNodePayload, type StructureNodePayload } from "./graph-navigator";
import { SEMANTIC_META } from "./semantics";
import { collectScopedSignals } from "./signals";
import {
  aggregateEntryForPaths,
  buildStructureContext,
  collectNodeScopePaths,
} from "./structure-context";
import { parseStructureNodeId, type StructureContext } from "./structure-shared";

export function buildNodeExplainPayloadFromContext(
  context: StructureContext,
  analysisRef: AnalysisRef | null,
  nodeId: string,
  drilldown: StructureNodePayload
) {
  const { nodeType, path } = parseStructureNodeId(nodeId);
  const scopedPaths = collectNodeScopePaths(context, nodeType, path);
  if (scopedPaths.length === 0) return null;

  const entry = aggregateEntryForPaths(scopedPaths, context);
  const signals = collectScopedSignals(scopedPaths, context);
  const role = buildNodeRole(drilldown.node, SEMANTIC_META[drilldown.node.kind].label);

  const sourcePaths = unique([
    ...scopedPaths,
    ...signals.facts.flatMap((fact) => fact.evidence.map((item) => normalizeRepoPath(item.path))),
    ...signals.findings.flatMap((finding) =>
      finding.evidence.map((item) => normalizeRepoPath(item.path))
    ),
  ]).slice(0, 8);

  const nextSuggestedPaths = drilldown.inspect.nextSuggestedPaths;
  const confidence = buildExplainConfidence({
    findingsCount: signals.findings.length,
    node: drilldown.node,
    sourcePathCount: sourcePaths.length,
  });

  return {
    analysisRef,
    confidence,
    nextSuggestedPaths,
    node: {
      id: drilldown.node.id,
      kind: drilldown.node.kind,
      label: drilldown.node.label,
      nodeType: drilldown.node.nodeType,
      path: drilldown.node.path,
    },
    relationships: {
      apiHints: drilldown.inspect.apiHints,
      apiSurface: drilldown.node.markers.api,
      breadcrumbs: drilldown.breadcrumbs,
      contains: drilldown.inspect.contains,
      dependsOn: drilldown.inspect.dependsOn,
      entrypoint: drilldown.node.markers.entrypoint,
      entrypointReason: drilldown.inspect.entrypointReason,
      factTitles: unique([...entry.factTitles, ...signals.facts.map((fact) => fact.title)]).slice(
        0,
        5
      ),
      frameworkHints: drilldown.inspect.frameworkHints,
      gitHints: drilldown.inspect.gitHints,
      graphHints: drilldown.inspect.graphHints,
      hotspotHints: drilldown.inspect.hotspotHints,
      neighborBuckets: drilldown.inspect.neighborBuckets,
      neighborPaths: drilldown.inspect.neighborPaths,
      recommendedActions: drilldown.inspect.recommendedActions,
      relatedPaths: drilldown.inspect.relatedPaths,
      reviewPriority: drilldown.inspect.reviewPriority,
      riskTitles: unique(signals.findings.map((finding) => finding.title)).slice(0, 5),
      usedBy: drilldown.inspect.usedBy,
    },
    role,
    sourcePaths,
    summary: buildNodeExplainSummary({
      changeCouplingCount: entry.changeCoupling.length,
      churnCount: entry.churnHotspots.length,
      dependencyHotspotCount: entry.dependencyHotspots.length,
      findingsCount: signals.findings.length,
      frameworkCount: entry.frameworkNames.length,
      graphWarningCount: entry.graphUnresolvedSamples.length,
      hotspotCount: entry.hotspotSignals.length,
      node: drilldown.node,
      orphanCount: entry.orphanPaths.length,
      relatedFactCount: signals.facts.length,
      role,
      scopedPathCount: scopedPaths.length,
    }),
    whyImportant: drilldown.inspect.whyImportant,
  };
}
export type NodeExplainPayload = NonNullable<ReturnType<typeof buildNodeExplainPayloadFromContext>>;

export function buildNodeExplainPayload(repo: RepoWithLatestAnalysisAndDocs, nodeId: string) {
  // Build node payload first to keep expensive context construction on the hot path only.
  const drilldown = buildStructureNodePayload(repo, nodeId);
  if (drilldown == null) return null;

  const context = buildStructureContext(repo);
  if (context == null) return null;

  return buildNodeExplainPayloadFromContext(
    context,
    toAnalysisRef(repo.analyses[0]),
    nodeId,
    drilldown
  );
}
type ExplainNodeLike = {
  kind: string;
  label: string;
  markers: {
    api: boolean;
    config: boolean;
    entrypoint: boolean;
    risk: boolean;
    server: boolean;
    shared: boolean;
  };
  nodeType: "file" | "group";
  stats: {
    apiCount: number;
    entrypointCount: number;
  };
};
function buildNodeRole(node: ExplainNodeLike, semanticLabel: string) {
  if (node.nodeType === "file") {
    if (node.markers.entrypoint) return "File with localized entrypoint significance";
    if (node.markers.api) return "File participating in the public API surface";
    if (node.markers.config) return "Configuration-heavy file";
    if (node.markers.shared) return "Shared support file";
    return "File with localized architectural importance";
  }

  if (node.markers.entrypoint && node.markers.server) return "Backend entry area";
  if (node.markers.api) return "API-facing structural zone";
  if (node.markers.config) return "Configuration-heavy area";
  if (node.markers.shared) return "Shared support module";

  return `${semanticLabel} structural area`;
}

export function buildNodeExplainSummary(params: {
  changeCouplingCount: number;
  churnCount: number;
  dependencyHotspotCount: number;
  findingsCount: number;
  frameworkCount: number;
  graphWarningCount: number;
  hotspotCount: number;
  node: ExplainNodeLike;
  orphanCount: number;
  relatedFactCount: number;
  role: string;
  scopedPathCount: number;
}) {
  const lines: string[] = [];

  lines.push(`${params.node.label} acts as a ${params.role.toLowerCase()}.`);

  if (params.node.markers.entrypoint) {
    lines.push("This area includes likely entrypoints, so it influences where execution begins.");
  } else if (params.node.markers.api) {
    lines.push("This area touches the public-facing surface of the repository.");
  } else if (params.node.markers.shared) {
    lines.push("This area is reused across multiple parts of the repository.");
  }

  if (params.node.markers.risk || params.findingsCount > 0) {
    lines.push("Risk-related evidence points here, so changes in this area deserve extra review.");
  } else if (params.node.markers.config) {
    lines.push("Configuration and runtime setup signals make this area operationally important.");
  }

  if (params.hotspotCount > 0 || params.dependencyHotspotCount > 0) {
    lines.push(
      "Hotspot and dependency-centrality signals suggest this node can amplify change impact."
    );
  } else if (params.churnCount > 0 || params.changeCouplingCount > 0) {
    lines.push(
      "Recent git history suggests this node changes often or changes alongside nearby files."
    );
  } else if (params.frameworkCount > 0) {
    lines.push("Framework/runtime hints suggest this area anchors important integration behavior.");
  }

  if (params.graphWarningCount > 0 || params.orphanCount > 0) {
    lines.push(
      "Some dependency evidence around this node is partial or isolated, so manual verification may help."
    );
  }

  if (params.scopedPathCount > 1) {
    lines.push(`The current scope covers ${params.scopedPathCount} meaningful paths.`);
  } else if (params.relatedFactCount > 0) {
    lines.push("Repository facts reinforce the structural importance of this node.");
  }

  return unique(lines).slice(0, 4);
}

function buildExplainConfidence(params: {
  findingsCount: number;
  node: ExplainNodeLike;
  sourcePathCount: number;
}) {
  const strongSignals = [
    params.node.markers.entrypoint,
    params.node.markers.api,
    params.node.markers.risk,
    params.node.stats.apiCount > 0,
    params.node.stats.entrypointCount > 0,
    params.findingsCount > 0,
    params.sourcePathCount >= 3,
  ].filter(Boolean).length;

  if (strongSignals >= 3) return "high" as const;
  if (strongSignals >= 2 || params.node.kind !== "unknown") return "medium" as const;
  return "low" as const;
}

import { normalizeRepoPath } from "@/server/shared/engine/core/common";
import { ProjectPolicy } from "@/server/shared/engine/core/project-policy";
import { unique } from "@/server/shared/lib/array-utils";
import { excludePath } from "@/server/shared/lib/path-operations";

import { isPathInsideScope } from "./structure-shared";

type StructureInspectNodeType = "file" | "group";

type OnboardingDocInputLike = null | {
  sections?: {
    onboarding?: {
      body?: {
        firstLookPaths?: string[];
      };
    };
  };
};

export type StructureInspectContextLike = {
  docInput?: OnboardingDocInputLike;
};

type StructureEntrypointLike = {
  path: string;
};

type StructureHotspotSignalLike = {
  churnScore: number;
  complexity: number;
  path: string;
  score: number;
};

type StructureDependencyHotspotLike = {
  exports: number;
  inbound: number;
  outbound: number;
