function buildContextNote(result: Pick<SyncFileActionMeta, "contextDiagnostics" | "contextMeta">) {
  if (!result.contextDiagnostics.hasContext) {
    return "Generated without selected-node repository context.";
  }

  if (result.contextMeta.graphBacked) {
    if (result.contextDiagnostics.contextStrength === "strong") {
      return "Built with strong graph-backed repository context from the selected node and its neighbors.";
    }
    if (result.contextDiagnostics.contextStrength === "moderate") {
      return "Built with graph-backed repository context from the selected node and nearby structural neighbors.";
    }
    return "Built with light graph-backed node context; verify nearby files before acting on it.";
  }

  if (
    result.contextDiagnostics.contextStrength === "strong" ||
    result.contextDiagnostics.contextStrength === "moderate"
  ) {
    return "Built with node-level repository context, but without resolved graph-neighbor support.";
  }

  return "Built with limited node context; verify neighboring files manually.";
}

function buildPreviewTitle(
  baseTitle: string,
  result: Pick<SyncFileActionMeta, "contextDiagnostics" | "contextMeta">
) {
  if (result.contextMeta.graphBacked) return `${baseTitle} (graph-backed)`;
  if (result.contextDiagnostics.hasContext) return `${baseTitle} (context-aware)`;
  return `${baseTitle} (file-only)`;
}

export function toQuickFileAuditPreview(
  result: QuickFileAuditResult & SyncFileActionMeta
): FileActionPreviewResult {
  const contextNote = buildContextNote(result);

  return {
    action: "quick-file-audit",
    analysisRef: result.analysisRef,
    confidence: result.confidence,
    consistency: result.consistency,
    consistencyNote: result.consistencyNote,
    content: `> ${contextNote}\n\n${formatQuickFileAuditMarkdown(result)}`,
    contextDiagnostics: result.contextDiagnostics,
    contextMeta: result.contextMeta,
    path: result.path,
    summary: `${result.summary} ${contextNote}`,
    title: buildPreviewTitle("Quick file audit", result),
  };
}

export function toDocumentFilePreview(
  result: DocumentFilePreviewResult & SyncFileActionMeta
): FileActionPreviewResult {
  const contextNote = buildContextNote(result);

  return {
    action: "document-file-preview",
    analysisRef: result.analysisRef,
    confidence: result.confidence,
    consistency: result.consistency,
    consistencyNote: result.consistencyNote,
    content: result.documentation,
    contextDiagnostics: result.contextDiagnostics,
    contextMeta: result.contextMeta,
    path: result.path,
    summary: `${result.summary} ${contextNote}`,
    title: buildPreviewTitle("Documentation preview", result),
  };
}

import type { AnalysisRef } from "@/server/shared/infrastructure/repo-snapshots";

import type { NodeContextDiagnostics, NodeContextMeta } from "./repo-node-context";

export type ContentRefInput = {
  analysisId?: string;
  commitSha?: string;
};

export type SyncFileActionMeta = {
  analysisRef: AnalysisRef | null;
  consistency: "matched" | "mismatch" | "unknown";
  consistencyNote: null | string;
  contentRef: ContentRefInput;
  contextDiagnostics: NodeContextDiagnostics;
  contextMeta: NodeContextMeta;
};

export function buildConsistencyState(
  analysisRef: AnalysisRef | null,
  contentRef: ContentRefInput
): {
  consistency: "matched" | "mismatch" | "unknown";
  consistencyNote: null | string;
} {
  if (analysisRef == null) {
    return {
      consistency: "unknown",
      consistencyNote: "No completed analysis snapshot is available for this repository yet.",
    };
  }

  if (contentRef.analysisId == null && contentRef.commitSha == null) {
    return {
      consistency: "unknown",
      consistencyNote:
        "The file action was run without an explicit analysis reference, so snapshot consistency is unknown.",
    };
  }

  const analysisIdMatches =
    contentRef.analysisId == null || contentRef.analysisId === analysisRef.analysisId;
  const commitShaMatches =
    contentRef.commitSha == null || contentRef.commitSha === analysisRef.commitSha;

  if (analysisIdMatches && commitShaMatches) {
    return {
      consistency: "matched",
      consistencyNote: "The file action matches the latest completed analysis snapshot.",
    };
  }

  return {
    consistency: "mismatch",
    consistencyNote:
      "The file action was run against file content that does not match the latest completed analysis snapshot.",
  };
}

export function buildSyncFileActionMeta(params: {
  analysisRef: AnalysisRef | null;
  contentRef: ContentRefInput;
  contextDiagnostics: NodeContextDiagnostics;
  contextMeta: NodeContextMeta;
}) {
  const consistency = buildConsistencyState(params.analysisRef, params.contentRef);

  return {
    analysisRef: params.analysisRef,
    consistency: consistency.consistency,
    consistencyNote: consistency.consistencyNote,
    contentRef: params.contentRef,
    contextDiagnostics: params.contextDiagnostics,
    contextMeta: params.contextMeta,
  } satisfies SyncFileActionMeta;
}

import { createAnalyzeContextBuilder } from "@/server/entities/analyze/lib/analyze-context-builder";
import type { DbClient } from "@/server/shared/infrastructure/db";
import { getRepoWithLatestAnalysisAndDocs } from "@/server/shared/infrastructure/repo-snapshots";

import type { FileActionNodeContext } from "./file-actions";

export type NodeContext = Omit<
  FileActionNodeContext,
  "graphNeighbors" | "neighborPaths" | "nextSuggestedPaths" | "recommendedActions" | "sourcePaths"
> & {
  graphNeighbors: string[];
  neighborPaths: string[];
  nextSuggestedPaths: string[];
  nodeId: string;
  recommendedActions: string[];
  sourcePaths: string[];
};

export type NodeContextMeta = {
  confidence: "high" | "low" | "medium" | null;
  graphBacked: boolean;
  mode: "node" | "none";
  nodeId: null | string;
  source: "node-explain" | "none";
  title: null | string;
};

export type NodeContextDiagnostics = {
  contextStrength: "light" | "moderate" | "none" | "strong";
  graphNeighborCount: number;
  hasContext: boolean;
  neighborPathCount: number;
  nextSuggestedPathCount: number;
  nonEmptyBuckets: string[];
  recommendedActionCount: number;
  sourcePathCount: number;
};

export async function buildNodeContext(
  db: DbClient,
  repoId: string,
  nodeId?: string
): Promise<NodeContext | null> {
  if (nodeId == null) return null;

  const repo = await getRepoWithLatestAnalysisAndDocs(db, repoId);
  if (repo == null) return null;

  const explain = createAnalyzeContextBuilder(repo).getNodeExplain(nodeId);
  if (explain == null) return null;

  return {
    confidence: explain.confidence,
    graphNeighbors: explain.relationships.neighborBuckets.graphNeighbors,
    neighborBuckets: explain.relationships.neighborBuckets,
    neighborPaths: explain.relationships.neighborPaths,
    nextSuggestedPaths: explain.nextSuggestedPaths,
    nodeId: explain.node.id,
    recommendedActions: explain.relationships.recommendedActions,
    reviewPriority: explain.relationships.reviewPriority,
    role: explain.role,
    sourcePaths: explain.sourcePaths,
    summary: explain.summary,
    title: explain.node.label,
    whyImportant: explain.whyImportant,
  };
}

export function buildNodeContextMeta(nodeContext: NodeContext | null): NodeContextMeta {
  if (nodeContext == null) {
    return {
      confidence: null,
      graphBacked: false,
      mode: "none",
      nodeId: null,
      source: "none",
      title: null,
    };
  }

  return {
    confidence: nodeContext.confidence,
    graphBacked: nodeContext.graphNeighbors.length > 0,
    mode: "node",
    nodeId: nodeContext.nodeId,
    source: "node-explain",
    title: nodeContext.title,
  };
}

export function buildNodeContextDiagnostics(
  nodeContext: NodeContext | null
): NodeContextDiagnostics {
  if (nodeContext == null) {
    return {
      contextStrength: "none",
      graphNeighborCount: 0,
      hasContext: false,
      neighborPathCount: 0,
      nextSuggestedPathCount: 0,
      nonEmptyBuckets: [],
      recommendedActionCount: 0,
      sourcePathCount: 0,
    };
  }

  const nonEmptyBuckets = Object.entries(nodeContext.neighborBuckets ?? {})
    .filter(([, paths]) => paths.length > 0)
    .map(([bucket]) => bucket);

  const weightedSignalCount =
    nodeContext.sourcePaths.length +
    nodeContext.graphNeighbors.length +
    nodeContext.neighborPaths.length +
    nodeContext.nextSuggestedPaths.length +
    nodeContext.recommendedActions.length +
    nonEmptyBuckets.length;

  const contextStrength =
    weightedSignalCount >= 12
      ? ("strong" as const)
      : weightedSignalCount >= 7
        ? ("moderate" as const)
        : ("light" as const);

  return {
    contextStrength,
    graphNeighborCount: nodeContext.graphNeighbors.length,
    hasContext: true,
    neighborPathCount: nodeContext.neighborPaths.length,
    nextSuggestedPathCount: nodeContext.nextSuggestedPaths.length,
    nonEmptyBuckets,
    recommendedActionCount: nodeContext.recommendedActions.length,
    sourcePathCount: nodeContext.sourcePaths.length,
  };
}

