  parserCoveragePercent: number;
  parserTiers: {
    heuristicFiles: number;
    treeSitterFiles: number;
    typeScriptAstFiles: number;
  };
  parserTierSummary: {
    heuristic: string[];
    treeSitter: string[];
    typeScriptAst: string[];
  };
