export function calculateTeamRoles(
  contributors: { contributions: number; login: string }[]
): TeamRole[] {
  const total = contributors.reduce((sum, contributor) => sum + contributor.contributions, 0);
  if (total === 0) return [];

  return contributors
    .map((contributor) => {
      const share = (contributor.contributions / total) * 100;
      let role = "Contributor";

      if (share > 50) role = "Project Guardian";
      else if (share > 20) role = "Key Architect";
      else if (share > 5) role = "Active Maintainer";

      return {
        login: contributor.login,
        role,
        share: Math.round(share),
      };
    })
    .sort((left, right) => right.share - left.share);
}

const WINDOW_DAYS = 90;

export async function computeGitChurnHotspots(
  repoRoot: string,
  relativePaths: string[]
): Promise<ChurnHotspot[]> {
  const allowed = new Set(relativePaths.map((p) => normalizeRepoPath(p)));
  if (allowed.size === 0) return [];

  try {
    const git = simpleGit(repoRoot);
    const out = await git.raw([
      "log",
      `--since=${WINDOW_DAYS} days ago`,
      "--name-only",
      "--pretty=format:",
    ]);

    const counts = new Map<string, number>();
    for (const line of out.split(/\r?\n/u)) {
      const trimmed = line.trim();
      if (trimmed.length === 0) continue;
      const norm = normalizeRepoPath(trimmed);
      if (!allowed.has(norm)) continue;
      counts.set(norm, (counts.get(norm) ?? 0) + 1);
    }

    const maxCommits = Math.max(1, ...counts.values());
    return [...counts.entries()]
      .map(([filePath, commitsInWindow]) => ({
        churnScore: Math.round((commitsInWindow / maxCommits) * 100),
        commitsInWindow,
        path: filePath,
      }))
      .sort((a, b) => b.commitsInWindow - a.commitsInWindow);
  } catch (error) {
    logger.debug({
      error,
      msg: "Git churn hotspot calculation skipped after git failure",
      repoRoot,
      trackedPathCount: allowed.size,
    });
    return [];
  }
}

export async function computeChangeCoupling(
  repoRoot: string,
  relativePaths: string[]
): Promise<ChangeCouplingRef[]> {
  const allowed = new Set(relativePaths.map((p) => normalizeRepoPath(p)));
  if (allowed.size === 0) return [];

  try {
    const git = simpleGit(repoRoot);
    const out = await git.raw([
      "log",
      "--since=180 days ago",
      "--name-only",
      "--pretty=format:--commit--",
    ]);

    const pairCounts = new Map<string, number>();
    let currentCommitFiles = new Set<string>();

    const flushCommit = () => {
      const files = Array.from(currentCommitFiles).sort((left, right) => left.localeCompare(right));
      if (files.length < 2) {
        currentCommitFiles = new Set<string>();
        return;
      }

      for (let i = 0; i < files.length; i++) {
        for (let j = i + 1; j < files.length; j++) {
          const left = files[i]!;
          const right = files[j]!;
          const key = `${left}::${right}`;
          pairCounts.set(key, (pairCounts.get(key) ?? 0) + 1);
        }
      }

      currentCommitFiles = new Set<string>();
    };

    for (const line of out.split(/\r?\n/u)) {
      const trimmed = line.trim();
      if (trimmed === "--commit--") {
        flushCommit();
        continue;
      }
      if (trimmed.length === 0) continue;
      const norm = normalizeRepoPath(trimmed);
      if (!allowed.has(norm)) continue;
      if (!ProjectPolicy.isArchitectureRelevant(norm)) continue;
      currentCommitFiles.add(norm);
    }

    flushCommit();

    return [...pairCounts.entries()]
      .map(([key, commits]) => {
        const parts = key.split("::");
        const fromPath = parts[0];
        const toPath = parts[1];
        return { commits, fromPath, toPath };
      })
      .filter(
        (item): item is { commits: number; fromPath: string; toPath: string } =>
          item.fromPath != null && item.toPath != null && item.commits >= 2
      )
      .sort((left, right) => right.commits - left.commits)
      .slice(0, 24);
  } catch (error) {
    logger.debug({
      error,
      msg: "Change coupling calculation skipped after git failure",
      repoRoot,
      trackedPathCount: allowed.size,
    });
    return [];
  }
}

import type { Repo } from "@prisma/client";
import ts from "typescript";

import { getFileExtension } from "../../lib/path-operations";
import { clamp } from "../core/common";
import type { HealthScoreParams } from "../core/metrics.types";
import { MODERN_HEALTH_SCORE } from "../core/scoring-constants";

const COMPLEXITY_AST_EXTENSIONS = new Set([
  ".cjs",
  ".cts",
  ".js",
  ".jsx",
  ".mjs",
  ".mts",
  ".ts",
  ".tsx",
]);

const ONE_C_KEYWORDS = [
  "\\u0415\\u0441\\u043B\\u0438",
  "\\u0418\\u043D\\u0430\\u0447\\u0435",
  "\\u0414\\u043B\\u044F",
  "\\u041A\\u0430\\u0436\\u0434\\u043E\\u0433\\u043E",
  "\\u041F\\u043E\\u043A\\u0430",
  "\\u041F\\u043E\\u043F\\u044B\\u0442\\u043A\\u0430",
  "\\u0418\\u0441\\u043A\\u043B\\u044E\\u0447\\u0435\\u043D\\u0438\\u0435",
];

const CONTROL_FLOW_REGEX = new RegExp(
  `\\b(if|else|elif|for|foreach|while|switch|case|catch|finally|break|continue|default|goto|try|except|rescue|unless|when|${ONE_C_KEYWORDS.join("|")})\\b`,
  "giu"
);

type LegacyHealthScoreInputs = {
  busFactor: number;
  docDensity: number;
  repo: Repo;
};

function getScriptKind(filePath: string) {
  if (filePath.endsWith(".tsx")) return ts.ScriptKind.TSX;
  if (filePath.endsWith(".jsx")) return ts.ScriptKind.JSX;
  if (filePath.endsWith(".js") || filePath.endsWith(".mjs") || filePath.endsWith(".cjs")) {
    return ts.ScriptKind.JS;
  }
  return ts.ScriptKind.TS;
}

function isControlFlowNode(node: ts.Node) {
  return (
    ts.isIfStatement(node) ||
    ts.isForStatement(node) ||
    ts.isForOfStatement(node) ||
    ts.isForInStatement(node) ||
    ts.isWhileStatement(node) ||
    ts.isDoStatement(node) ||
    ts.isSwitchStatement(node) ||
    ts.isCaseClause(node) ||
    ts.isCatchClause(node) ||
    ts.isConditionalExpression(node)
  );
}

function increasesNesting(node: ts.Node) {
  return (
    ts.isIfStatement(node) ||
    ts.isForStatement(node) ||
    ts.isForOfStatement(node) ||
    ts.isForInStatement(node) ||
    ts.isWhileStatement(node) ||
    ts.isDoStatement(node) ||
    ts.isSwitchStatement(node) ||
    ts.isCatchClause(node)
  );
}

function calculateTypeScriptComplexity(filePath: string, content: string) {
  const sourceFile = ts.createSourceFile(
    filePath,
    content,
    ts.ScriptTarget.Latest,
    true,
    getScriptKind(filePath)
  );

  let complexity = 0;
  let maxNesting = 0;

  const visit = (node: ts.Node, nesting: number) => {
    if (isControlFlowNode(node)) {
      complexity += 1 + nesting;
      maxNesting = Math.max(maxNesting, nesting);
    }

    const nextNesting = nesting + (increasesNesting(node) ? 1 : 0);
    ts.forEachChild(node, (child) => visit(child, nextNesting));
  };

  visit(sourceFile, 0);

  return { complexity, maxNesting };
}

function calculateRegexComplexity(content: string) {
  const lines = content.split(/\r?\n/u).filter((line) => line.trim().length > 0);

  let complexity = 0;
  let maxNesting = 0;

  for (const line of lines) {
    const indentMatch = /^(\s+)/u.exec(line);
    const nesting =
      indentMatch?.[1] != null ? Math.floor(indentMatch[1].replaceAll("\t", "    ").length / 2) : 0;
    const keywordCount = Array.from(line.matchAll(CONTROL_FLOW_REGEX)).length;

    complexity += keywordCount * (1 + nesting * 0.5);
    maxNesting = Math.max(maxNesting, nesting);
  }

  return { complexity, maxNesting };
}

function shouldUseAstComplexity(filePath: string) {
  return COMPLEXITY_AST_EXTENSIONS.has(getFileExtension(filePath));
}

export function calculateComplexity(content: string, filePath: string) {
  if (shouldUseAstComplexity(filePath)) {
    return calculateTypeScriptComplexity(filePath, content);
  }

  return calculateRegexComplexity(content);
}

function isModernHealthScoreParams(input: HealthScoreParams | Repo): input is HealthScoreParams {
  return "repo" in input;
}

function calculateLegacyHealthScore(params: LegacyHealthScoreInputs) {
  const { busFactor, docDensity, repo } = params;
  let score = 50;
  const lastPushDate = repo.pushedAt == null ? new Date() : new Date(repo.pushedAt);
  const monthsSincePush = (Date.now() - lastPushDate.getTime()) / (1000 * 60 * 60 * 24 * 30);
  if (monthsSincePush < 1) score += 20;
  else if (monthsSincePush > 6) score -= 30;

  if (busFactor > 2) score += 15;
  if (busFactor === 1) score -= 15;

  if (docDensity > 15) score += 15;
  if (docDensity < 5) score -= 10;

  return clamp(score, 0, 100);
}

function calculateModernHealthScore(params: HealthScoreParams) {
  const {
    busFactor,
    complexityScore,
    dependencyCycles,
    docDensity,
    duplicationPercentage,
    repo,
    securityScore,
    techDebtScore,
  } = params;

  let score = 0;
  score += securityScore * MODERN_HEALTH_SCORE.securityWeight;
  score += techDebtScore * MODERN_HEALTH_SCORE.techDebtWeight;
  score += complexityScore * MODERN_HEALTH_SCORE.complexityWeight;
  score +=
    clamp(
      100 - duplicationPercentage * MODERN_HEALTH_SCORE.duplicationMultiplierForHealth,
      0,
      100
    ) * MODERN_HEALTH_SCORE.duplicationWeight;
  score +=
    clamp(docDensity * MODERN_HEALTH_SCORE.docDensityMultiplierForHealth, 0, 100) *
    MODERN_HEALTH_SCORE.documentationWeight;
  score += clamp(busFactor * 18, 0, 100) * MODERN_HEALTH_SCORE.busFactorWeight;
  score += clamp(100 - dependencyCycles * 18, 0, 100) * MODERN_HEALTH_SCORE.cyclesWeight;

  const lastPushDate = repo.pushedAt != null ? new Date(repo.pushedAt) : new Date();
  const daysSincePush = (Date.now() - lastPushDate.getTime()) / (1000 * 60 * 60 * 24);
  if (daysSincePush < MODERN_HEALTH_SCORE.activityDaysThresholdRecent) {
    score += MODERN_HEALTH_SCORE.recentActivityBonus;
  } else if (daysSincePush < MODERN_HEALTH_SCORE.activityDaysThresholdActive) {
    score += MODERN_HEALTH_SCORE.activeActivityBonus;
  }

  return clamp(Math.round(score), 0, 100);
}

function toLegacyHealthScoreInputs(
  repo: Repo,
  legacyBusFactor?: number,
  legacyDocDensity?: number
): LegacyHealthScoreInputs {
  return {
    busFactor: legacyBusFactor ?? 0,
    docDensity: legacyDocDensity ?? 0,
    repo,
  };
}

export function calculateHealthScore(
  repoOrParams: HealthScoreParams | Repo,
  legacyBusFactor?: number,
  legacyDocDensity?: number
): number {
  if (isModernHealthScoreParams(repoOrParams)) {
    return calculateModernHealthScore(repoOrParams);
  }

  return calculateLegacyHealthScore(
    toLegacyHealthScoreInputs(repoOrParams, legacyBusFactor, legacyDocDensity)
  );
}

import type { RepositoryFile } from "../core/discovery.types";
import { ProjectPolicy } from "../core/project-policy";

export function calculateApproximateDuplication(files: RepositoryFile[]): number {
  const hashes = new Set<string>();
  let duplicatedLines = 0;

  for (const file of files) {
    if (ProjectPolicy.isTestFile(file.path) || ProjectPolicy.isConfigFile(file.path)) continue;

    const cleanLines = file.content
      .split(/\r?\n/u)
      .map((line) => line.trim())
      .filter(
        (line) =>
          line.length > 5 && !line.startsWith("/") && !line.startsWith("*") && !line.startsWith("#")
      );

    const WINDOW_SIZE = 6;
    for (let i = 0; i <= cleanLines.length - WINDOW_SIZE; i++) {
      const block = cleanLines
        .slice(i, i + WINDOW_SIZE)
        .join("|")
        .toLowerCase();

      const hash = Buffer.from(block).toString("base64");

      if (hashes.has(hash)) {
        duplicatedLines += WINDOW_SIZE;
        i += WINDOW_SIZE - 1;
      } else {
        hashes.add(hash);
      }
    }
  }

  return duplicatedLines;
}

import { dumpDebug } from "../../lib/debug-logger";
import { buildEvidence, clamp } from "../core/common";
import type { ArtifactBuildParams, ArtifactBuildResult } from "../core/metrics.types";
import {
  buildReferenceEvidencePaths,
  getPrimaryArchitectureModules,
  getPrimaryEntrypointPaths,
} from "./report-helpers";
import { buildRiskSectionBody } from "./risk-model";

const FINDING_SEVERITY_WEIGHT = { CRITICAL: 4, HIGH: 3, LOW: 1, MODERATE: 2 } as const;
const MAX_FACT_EVIDENCE = 15;
const MAX_FACTS = 50;
const MAX_FINDING_EVIDENCE = 15;
const MAX_FINDINGS = 30;

type ArtifactFact = ArtifactBuildResult["facts"][number];
type ArtifactFinding = ArtifactBuildResult["findings"][number];
type ArtifactContext = {
  busFactor: ArtifactBuildParams["busFactor"];
  evidence: ArtifactBuildParams["evidence"];
  metrics: ArtifactBuildParams["metrics"];
  moduleMap: ReturnType<typeof getPrimaryArchitectureModules>;
  primaryEntrypoints: ReturnType<typeof getPrimaryEntrypointPaths>;
  publicSurfacePaths: string[];
  referenceEvidence: string[];
  riskFindings: ArtifactFinding[];
  riskHotspotPaths: string[];
  teamRoles: ArtifactBuildParams["teamRoles"];
};

function compactArtifacts<T>(items: Array<null | T>): T[] {
  return items.filter((item): item is T => item != null);
}

function buildOwnershipEvidence(teamRoles: ArtifactBuildParams["teamRoles"]) {
  return teamRoles.map((role) => ({
    note: `${role.role} (${role.share}%)`,
    path: `github:contributors/${role.login}`,
  }));
}

function buildSecurityEvidence(metrics: ArtifactBuildParams["metrics"]) {
  return metrics.securityFindings.map((finding) => ({
    line: finding.line,
    note: finding.message,
    path: finding.path,
  }));
}

function buildPublicInterfaceEvidence(context: ArtifactContext) {
  const { evidence, primaryEntrypoints, publicSurfacePaths } = context;
  const paths =
    evidence.routeInventory.sourceFiles.length > 0
      ? evidence.routeInventory.sourceFiles
      : publicSurfacePaths.length > 0
        ? publicSurfacePaths
        : primaryEntrypoints;

  return buildEvidence(paths, "Public interface evidence");
}

function buildOverlapEvidence(paths: string[]) {
  return buildEvidence(paths, "High churn + structural centrality");
}

function buildPrimaryArchitectureEvidence(context: ArtifactContext) {
  return buildEvidence(
    context.moduleMap.slice(0, 10).map((module) => module.path),
    "Primary runtime module"
  );
}

function buildReferenceRootsEvidence(context: ArtifactContext) {
  return buildEvidence(
    context.referenceEvidence.length > 0
      ? context.referenceEvidence
      : context.metrics.mostComplexFiles
  );
}

function buildCoverageEvidence(context: ArtifactContext): ArtifactFact["evidence"] {
  const { analysisCoverage } = context.metrics;
  return [
    {
      note: `TypeScript AST: ${analysisCoverage.languagesByMode.typeScriptAst.join(", ") || "none"}`,
      path: "analysis://coverage/typescript-ast",
    },
    {
      note: `Tree-sitter: ${analysisCoverage.languagesByMode.treeSitter.join(", ") || "none"}`,
      path: "analysis://coverage/tree-sitter",
    },
    {
      note: `Heuristic fallback: ${analysisCoverage.languagesByMode.heuristic.join(", ") || "none"}`,
      path: "analysis://coverage/heuristic",
    },
  ];
}

function buildCoreFacts(context: ArtifactContext): ArtifactFact[] {
  const { evidence, metrics } = context;
  return [
    {
      category: "quality",
      confidence: "high",
      detail: `${metrics.fileCount} files, ${metrics.totalLoc} lines, ${metrics.languages.length} detected languages.`,
      evidence: buildReferenceRootsEvidence(context),
      id: "codebase-shape",
      title: "Codebase footprint is measured from repository contents",
    },
    {
      category: "configuration",
      confidence: "high",
      detail:
        evidence.configs.length > 0
          ? `${metrics.configFiles} configuration files were indexed for runtime and build context.`
          : "No dedicated configuration files were recognized by the analyzer.",
      evidence: buildEvidence(
        evidence.configs.map((config) => config.path),
        "Configuration inventory"
      ),
      id: "configuration-inventory",
      title: "Configuration inventory is explicit",
    },
    {
      category: "quality",
      confidence: metrics.analysisCoverage.parserCoveragePercent >= 70 ? "high" : "medium",
      detail: `Structural parsing covers ${metrics.analysisCoverage.parserCoveragePercent}% of analyzed files (${metrics.analysisCoverage.typeScriptAstFiles} via TypeScript AST, ${metrics.analysisCoverage.treeSitterFiles} via Tree-sitter, ${metrics.analysisCoverage.heuristicFiles} heuristic only).`,
      evidence: buildCoverageEvidence(context),
      id: "analysis-coverage",
      title: "Analysis depth is explicit per parser tier",
    },
  ];
}

function buildArchitectureFacts(context: ArtifactContext): ArtifactFact[] {
  const { evidence, moduleMap, primaryEntrypoints, referenceEvidence } = context;
  const facts: ArtifactFact[] = [];

  if (primaryEntrypoints.length > 0) {
    facts.push({
      category: "architecture",
      confidence: "high",
      detail: `Likely primary entrypoints/public surfaces: ${primaryEntrypoints.join(", ")}.`,
      evidence: buildEvidence(primaryEntrypoints, "Entrypoint"),
      id: "entrypoints",
      title: "Entrypoints are identified from repository structure",
    });
  }

  const graphReliability = evidence.dependencyGraph;
  if (graphReliability.unresolvedImportSpecifiers > 0) {
    facts.push({
      category: "architecture",
      confidence: "medium",
      detail: `${graphReliability.unresolvedImportSpecifiers} internal import paths could not be mapped to analyzed files; ${graphReliability.resolvedEdges} dependency edges resolved. Partial graph is common with path aliases or sparse file selection.`,
      evidence: graphReliability.unresolvedSamples.map((u) => ({
        note: `unresolved import: ${u.specifier}`,
        path: u.fromPath,
      })),
      id: "graph-reliability",
      title: "Import graph resolution is incomplete",
    });
  }

  facts.push({
    category: "architecture",
    confidence: evidence.dependencyCycles.length > 0 ? "high" : "medium",
    detail:
      evidence.dependencyCycles.length > 0
        ? `${evidence.dependencyCycles.length} dependency cycle groups were detected in the local dependency graph.`
        : "No dependency cycles were detected in the local dependency graph.",
    evidence: buildEvidence(
      evidence.dependencyCycles.length > 0
        ? (evidence.dependencyCycles[0] ?? [])
        : referenceEvidence,
      evidence.dependencyCycles.length > 0 ? "Dependency cycle" : "Graph roots"
    ),
    id: "dependency-cycles",
    title:
      evidence.dependencyCycles.length > 0
        ? "The dependency graph contains cycles"
        : "The dependency graph is acyclic in analyzed files",
  });

  if (moduleMap.length > 0) {
    facts.push({
      category: "architecture",
      confidence: "high",
      detail: `Primary architectural contour centers on ${moduleMap.length} runtime-relevant modules; non-runtime files stay in secondary evidence instead of dominating the report.`,
      evidence: buildPrimaryArchitectureEvidence(context),
      id: "primary-architecture-contour",
      title: "Primary architecture is separated from secondary repository evidence",
    });
  }

  return facts;
}

function buildFrameworkFacts(context: ArtifactContext): ArtifactFact[] {
  if (context.evidence.frameworkFacts.length === 0) {
    return [];
  }

  const topFrameworks = context.evidence.frameworkFacts.slice(0, 8);
  return [
    {
      category: "architecture",
      confidence: topFrameworks.some((fact) => fact.confidence >= 90) ? "high" : "medium",
      detail: `Detected framework/runtime profile: ${topFrameworks.map((fact) => fact.name).join(", ")}.`,
      evidence: topFrameworks.map((fact) => ({
        note: `${fact.category} (${fact.confidence}%)`,
        path: fact.sources[0] ?? "analysis://frameworks",
      })),
      id: "framework-profile",
      title: "Framework and runtime stack is inferred from layered evidence",
    },
  ];
}

function buildApiFacts(context: ArtifactContext): ArtifactFact[] {
  const facts: ArtifactFact[] = [
    {
      category: "api",
      confidence: "medium",
      detail:
        context.metrics.apiSurface > 0
          ? `${context.metrics.apiSurface} API surface signals were detected from routes, handlers, controllers, or exported entry procedures.`
          : "No clear API surface was detected from the selected files.",
      evidence: buildPublicInterfaceEvidence(context),
      id: "api-surface",
      title: "Public interface footprint is tracked",
    },
  ];

  const openapiInventory = context.metrics.openapiInventory;
  if (openapiInventory != null && openapiInventory.sourceFiles.length > 0) {
    facts.push({
      category: "api",
      confidence: openapiInventory.pathPatterns.length > 0 ? "high" : "medium",
      detail: `OpenAPI/Swagger-like documents found in ${openapiInventory.sourceFiles.length} file(s); ~${openapiInventory.estimatedOperations} HTTP operations (heuristic count).`,
      evidence: openapiInventory.sourceFiles.map((path) => ({
        note: "Spec candidate",
        path,
      })),
      id: "openapi-inventory",
      title: "Machine-readable API specs are indexed",
    });
  }

  return facts;
}

function buildOperationalFacts(context: ArtifactContext): ArtifactFact[] {
  const { metrics, teamRoles } = context;
  const facts: ArtifactFact[] = [];

  if (metrics.churnHotspots != null && metrics.churnHotspots.length > 0) {
    facts.push({
      category: "delivery",
      confidence: "medium",
      detail: `Recent git activity (last ~90 days, when history exists) clusters on: ${metrics.churnHotspots
        .map((candidate) => `${candidate.path} (${candidate.commitsInWindow} touches)`)
        .join(", ")}.`,
      evidence: metrics.churnHotspots.map((candidate) => ({
        note: `${candidate.commitsInWindow} commits in window`,
        path: candidate.path,
      })),
      id: "git-churn-hotspots",
      title: "Change frequency highlights active files",
    });
  }

  if (teamRoles.length > 0) {
    const leadRole = teamRoles[0]!;
    facts.push({
      category: "ownership",
      confidence: "medium",
      detail: `${leadRole.login} currently owns about ${leadRole.share}% of visible contribution share.`,
      evidence: buildOwnershipEvidence(teamRoles),
      id: "ownership-distribution",
      title: "Knowledge distribution is estimated from contributor share",
    });
  }

  return facts;
}

function buildSecurityFacts(context: ArtifactContext): ArtifactFact[] {
  if (context.metrics.securityFindings.length === 0) {
    return [];
  }

  return [
    {
      category: "security",
      confidence: "high",
      detail: `${context.metrics.securityFindings.length} secret or sensitive-pattern signals were raised during static scanning.`,
      evidence: buildSecurityEvidence(context.metrics),
      id: "security-signals",
      title: "Static secret scanning produced concrete signals",
    },
  ];
}

function buildManualFindings(context: ArtifactContext): ArtifactFinding[] {
  return compactArtifacts([
    buildOwnershipFinding(context),
    buildSecurityFinding(context),
    buildDuplicationFinding(context),
    buildHotspotOverlapFinding(context),
    buildOnboardingFinding(context),
  ]);
}

function buildOwnershipFinding(context: ArtifactContext): ArtifactFinding | null {
  const { busFactor, teamRoles } = context;
  if (busFactor > 2 || teamRoles.length === 0) {
    return null;
  }

  return {
    category: "change-risk",
    confidence: 76,
    evidence: buildOwnershipEvidence(teamRoles),
    id: "ownership-concentration",
    score: clamp(70 + teamRoles[0]!.share / 2, 0, 100),
    severity: teamRoles[0]!.share >= 60 ? "CRITICAL" : "HIGH",
    suggestedNextChange:
      "Spread ownership around the highest-risk files with reviews, pairing, and small runbooks.",
    summary: `Bus factor is ${busFactor}, with visible ownership concentrated around ${teamRoles[0]!.login}.`,
    title: "Knowledge concentration creates delivery risk",
    whyItMatters:
      "A small contributor set increases fragility when urgent fixes land in central modules.",
  };
}

function buildSecurityFinding(context: ArtifactContext): ArtifactFinding | null {
  const { metrics } = context;
  if (metrics.securityFindings.length === 0) {
    return null;
  }

  return {
    category: "security",
    confidence: 95,
    evidence: buildSecurityEvidence(metrics),
    id: "secret-signals",
    score: clamp(65 + metrics.securityFindings.length * 6, 0, 100),
    severity: metrics.securityFindings.some((finding) => finding.severity === "error")
      ? "HIGH"
      : "MODERATE",
    suggestedNextChange:
      "Review the flagged files, remove accidental secrets or secret-like fixtures, and replace them with safe placeholders.",
    summary: `${metrics.securityFindings.length} security scanner signals were detected.`,
    title: "Secret exposure signals need manual review",
    whyItMatters:
      "False positives cost trust, and real leaks can turn generated output into a security incident multiplier.",
  };
}

function buildDuplicationFinding(context: ArtifactContext): ArtifactFinding | null {
  const { evidence, metrics } = context;
  if (metrics.duplicationPercentage < 8) {
    return null;
  }

  return {
    category: "maintainability",
    confidence: 82,
    evidence: buildEvidence(
      evidence.hotspotSignals.length > 0
        ? evidence.hotspotSignals.map((signal) => signal.path)
        : metrics.mostComplexFiles
    ),
    id: "duplication-pressure",
    score: clamp(metrics.duplicationPercentage * 6, 0, 100),
    severity: metrics.duplicationPercentage >= 15 ? "HIGH" : "MODERATE",
    suggestedNextChange:
      "Extract one repeated workflow into a reusable abstraction before the duplication spreads.",
    summary: `Approximate duplication is ${metrics.duplicationPercentage}% of analyzed source lines.`,
    title: "Duplication is increasing maintenance cost",
    whyItMatters:
      "Repeated logic multiplies bug-fix effort and often hides behavior drift across similar flows.",
  };
}

function buildHotspotOverlapFinding(context: ArtifactContext): ArtifactFinding | null {
  const { metrics, riskHotspotPaths } = context;
  if (
    metrics.churnHotspots == null ||
    metrics.churnHotspots.length === 0 ||
    riskHotspotPaths.length === 0
  ) {
    return null;
  }

  const churnPaths = new Set(metrics.churnHotspots.map((candidate) => candidate.path));
  const overlap = riskHotspotPaths.filter((path) => churnPaths.has(path));
  if (overlap.length === 0) {
    return null;
  }

  return {
    category: "hotspot",
    confidence: 80,
    evidence: buildOverlapEvidence(overlap),
    id: "churn-static-overlap",
    score: clamp(60 + overlap.length * 8, 0, 100),
    severity: "HIGH",
    suggestedNextChange:
      "Treat overlap files as change-management priorities: smaller PRs, tests around edits, and ownership clarity.",
    summary: `Files appear both in static hotspots and frequent recent commits: ${overlap.join(", ")}.`,
    title: "Hotspots align with recent change frequency",
    whyItMatters:
      "When complex central files also change often, regressions and merge conflicts concentrate in the riskiest areas.",
  };
}

function buildOnboardingFinding(context: ArtifactContext): ArtifactFinding | null {
  const { evidence, metrics, primaryEntrypoints } = context;
  const onboardingRiskScore =
    (metrics.docDensity < 10 ? 40 : 0) +
    (primaryEntrypoints.length === 0 ? 30 : 0) +
    (evidence.configs.length === 0 ? 15 : 0) +
    (evidence.orphanModules.length > 4 ? 15 : 0);

  if (onboardingRiskScore < 30) {
    return null;
  }

  return {
    category: "onboarding",
    confidence: 68,
    evidence: buildEvidence(
      primaryEntrypoints.length > 0 ? primaryEntrypoints : evidence.orphanModules,
      "Onboarding starting point"
    ),
    id: "onboarding-friction",
    score: clamp(onboardingRiskScore, 0, 100),
    severity: onboardingRiskScore >= 60 ? "HIGH" : "MODERATE",
    suggestedNextChange:
      "Document the main entrypoints, runtime config map, and the first files a newcomer should inspect.",
    summary:
      primaryEntrypoints.length === 0
        ? "The analyzer could not confidently infer clear project entrypoints."
        : `Documentation density is ${metrics.docDensity}%, which is low for fast onboarding.`,
    title: "Project context is expensive to reconstruct",
    whyItMatters:
      "When entrypoints and config flow stay implicit, onboarding and incident response both slow down.",
  };
}

function sortFindingsBySeverity(findings: ArtifactFinding[]) {
  return [...findings].sort((left, right) => {
    return (
      FINDING_SEVERITY_WEIGHT[right.severity] - FINDING_SEVERITY_WEIGHT[left.severity] ||
      right.score - left.score
    );
  });
}

function buildArtifactContext(params: ArtifactBuildParams): ArtifactContext {
  const { busFactor, evidence, metrics, teamRoles } = params;
  const riskBody = buildRiskSectionBody(evidence, {
    changeCoupling: metrics.changeCoupling,
    complexityScore: metrics.complexityScore,
    graphReliability: metrics.graphReliability,
    hotspotSignals: metrics.hotspotSignals,
  });
  const primaryEntrypoints = getPrimaryEntrypointPaths(evidence.entrypoints);
  const moduleMap = getPrimaryArchitectureModules(evidence.modules);
  const publicSurfacePaths = Array.from(
    new Set(evidence.publicSurface.map((symbol) => symbol.path))
  ).sort((left, right) => left.localeCompare(right));
  const referenceEvidence = buildReferenceEvidencePaths({
    fallbackPaths: metrics.mostComplexFiles,
    modules: moduleMap,
    primaryEntrypoints,
  });

  return {
    busFactor,
    evidence,
    metrics,
    moduleMap,
    primaryEntrypoints,
    publicSurfacePaths,
    referenceEvidence,
    riskFindings: riskBody.findings,
    riskHotspotPaths: riskBody.hotspots.map((signal) => signal.path),
    teamRoles,
  };
}

function buildFacts(context: ArtifactContext): ArtifactFact[] {
  return [
    ...buildCoreFacts(context),
    ...buildArchitectureFacts(context),
    ...buildFrameworkFacts(context),
    ...buildApiFacts(context),
    ...buildOperationalFacts(context),
    ...buildSecurityFacts(context),
  ];
}

function buildFindings(context: ArtifactContext): ArtifactFinding[] {
  return sortFindingsBySeverity([...context.riskFindings, ...buildManualFindings(context)]);
}

// Builds compact facts/findings for the report layer without re-deriving architecture outside the canonical builders.
export function buildRepositoryArtifacts(params: ArtifactBuildParams): ArtifactBuildResult {
  const context = buildArtifactContext(params);
  const result: ArtifactBuildResult = {
    facts: buildFacts(context)
      .slice(0, MAX_FACTS)
      .map((fact) => ({
        ...fact,
        evidence: fact.evidence.slice(0, MAX_FACT_EVIDENCE),
      })),
    findings: buildFindings(context)
      .slice(0, MAX_FINDINGS)
      .map((finding) => ({
        ...finding,
        evidence: finding.evidence.slice(0, MAX_FINDING_EVIDENCE),
      })),
  };
  dumpDebug("artifacts-facts-findings", result);
  return result;
}

import type { HotspotSignal, RepositoryEvidence } from "../core/discovery.types";
import type { ArchitectureSectionBody, DocumentationInputModel } from "../core/documentation.types";
import { selectRepositoryFrameworkFacts } from "../core/framework-catalog";
import type { RepoMetrics } from "../core/metrics.types";
import { ProjectPolicy } from "../core/project-policy";
import {
  getPrimaryArchitectureModules,
  getPrimaryEntrypointPaths,
  getSecondaryEntrypointPaths,
} from "./report-helpers";
import { buildRiskSectionBody } from "./risk-model";

type FrameworkFactInput = DocumentationInputModel["api"]["frameworkFacts"][number];
type EntrypointInput = DocumentationInputModel["api"]["entrypoints"][number];
type RouteInventoryInput = DocumentationInputModel["api"]["routeInventory"];
type HotspotInput = DocumentationInputModel["risks"]["hotspots"][number];
type ArchitectureModuleInput = ArchitectureSectionBody["modules"][number];

export type DocumentationContext = {
  architectureModules: ArchitectureModuleInput[];
  entrypoints: EntrypointInput[];
  frameworkFacts: FrameworkFactInput[];
  graphReliability: RepositoryEvidence["dependencyGraph"];
  hotspots: HotspotInput[];
  primaryEntrypoints: string[];
  risksBody: DocumentationInputModel["sections"]["risks"]["body"];
  routeInventory: RouteInventoryInput;
  secondaryEntrypoints: string[];
  stackProfile: string[];
};

function buildFrameworkFacts(
  evidence: RepositoryEvidence,
  metrics: RepoMetrics
): FrameworkFactInput[] {
  return selectRepositoryFrameworkFacts(
    evidence.frameworkFacts.length > 0 ? evidence.frameworkFacts : (metrics.frameworkFacts ?? [])
  ).map((fact) => ({
    category: fact.category as FrameworkFactInput["category"],
    confidence: fact.confidence,
    name: fact.name,
    sources: fact.sources,
  }));
}

function buildEntrypoints(evidence: RepositoryEvidence, metrics: RepoMetrics): EntrypointInput[] {
  const canonicalEntrypoints =
    evidence.entrypoints.length > 0 ? evidence.entrypoints : (metrics.entrypointDetails ?? []);

  return canonicalEntrypoints
    .filter((entrypoint) => {
      if (entrypoint.kind === "library" || entrypoint.kind === "runtime") {
        return ProjectPolicy.isPrimaryEntrypoint(entrypoint.path);
      }

      return !ProjectPolicy.isPrimaryContourExcluded(entrypoint.path);
    })
    .map((entrypoint) => ({
      confidence: entrypoint.confidence,
      kind: entrypoint.kind,
      path: entrypoint.path,
      reason: entrypoint.reason,
    }));
}

function buildRouteInventory(
  evidence: RepositoryEvidence,
  metrics: RepoMetrics,
  frameworkFacts: FrameworkFactInput[]
): RouteInventoryInput {
  const inventory = metrics.routeInventory ?? evidence.routeInventory;

  const filteredRoutes = inventory.httpRoutes.filter((route) =>
    ProjectPolicy.isPrimaryApiSurface(route.sourcePath)
  );
  const filteredSourceFiles = ProjectPolicy.filterPrimaryApiSurfacePaths(inventory.sourceFiles, 48);

  return {
    ...inventory,
    estimatedOperations:
      filteredRoutes.length > 0 || filteredSourceFiles.length > 0
        ? filteredRoutes.length + inventory.rpcProcedures
        : 0,
    frameworks: frameworkFacts.map((fact) => fact.name),
    httpRoutes: filteredRoutes,
    rpcProcedures: filteredSourceFiles.length > 0 ? inventory.rpcProcedures : 0,
    sourceFiles: filteredSourceFiles,
  };
}

function buildHotspots(evidence: RepositoryEvidence, metrics: RepoMetrics): HotspotInput[] {
  const hotspotCandidates =
    evidence.hotspotSignals.length > 0 ? evidence.hotspotSignals : (metrics.hotspotSignals ?? []);

  return hotspotCandidates.map<HotspotInput>((signal) => ({
    categories: signal.categories as HotspotInput["categories"],
    churnScore: signal.churnScore,
    complexity: signal.complexity,
    confidence: signal.confidence,
    inbound: signal.inbound,
    outbound: signal.outbound,
    path: signal.path,
    score: signal.score,
    source: signal.source as HotspotSignal["source"],
  }));
}

function buildArchitectureModules(evidence: RepositoryEvidence): ArchitectureModuleInput[] {
  return getPrimaryArchitectureModules(evidence.modules).map((module) => ({
    apiSurface: module.apiSurface,
    categories: module.categories,
    exports: module.exports,
    parseTier: module.parseTier,
    path: module.path,
  }));
}

function buildStackProfile(
  frameworkFacts: FrameworkFactInput[],
  metrics: RepoMetrics,
  routeInventory: RouteInventoryInput
) {
  return Array.from(
    new Set([
      ...frameworkFacts.map((fact) => fact.name),
      ...metrics.techStack,
      ...(routeInventory.source !== "extracted" ? ["OpenAPI"] : []),
    ])
  ).sort((left, right) => left.localeCompare(right));
}

function mergeGraphReliability(
  evidence: RepositoryEvidence,
  metrics: RepoMetrics
): RepositoryEvidence["dependencyGraph"] {
  if (metrics.graphReliability == null) {
    return evidence.dependencyGraph;
  }

  return {
    ...evidence.dependencyGraph,
    resolvedEdges: metrics.graphReliability.resolvedEdges,
    unresolvedImportSpecifiers: metrics.graphReliability.unresolvedImportSpecifiers,
    unresolvedSamples: metrics.graphReliability.unresolvedSamples,
  };
}

export function buildDocumentationContext(
  evidence: RepositoryEvidence,
  metrics: RepoMetrics
): DocumentationContext {
  const graphReliability = mergeGraphReliability(evidence, metrics);
  const frameworkFacts = buildFrameworkFacts(evidence, metrics);
  const entrypoints = buildEntrypoints(evidence, metrics);
  const routeInventory = buildRouteInventory(evidence, metrics, frameworkFacts);
  const hotspots = buildHotspots(evidence, metrics);
  const architectureModules = buildArchitectureModules(evidence);
  const primaryEntrypoints = getPrimaryEntrypointPaths(entrypoints);
  const secondaryEntrypoints = getSecondaryEntrypointPaths(entrypoints);
  const stackProfile = buildStackProfile(frameworkFacts, metrics, routeInventory);
  const risksBody = buildRiskSectionBody(evidence, {
    changeCoupling: metrics.changeCoupling,
    complexityScore: metrics.complexityScore,
    graphReliability,
    hotspotSignals: metrics.hotspotSignals,
  });

  return {
    architectureModules,
    entrypoints,
    frameworkFacts,
    graphReliability,
    hotspots,
    primaryEntrypoints,
    risksBody,
    routeInventory,
    secondaryEntrypoints,
    stackProfile,
  };
}

import { uniquePaths } from "../../lib/array-utils";
import type { RepositoryEvidence } from "../core/discovery.types";
import type {
  ApiReferenceSectionBody,
  DocumentationInputModel,
  OnboardingSectionBody,
  OverviewSectionBody,
} from "../core/documentation.types";
import type { RepoMetrics } from "../core/metrics.types";
import { ProjectPolicy } from "../core/project-policy";
import type { DocumentationContext } from "./documentation-input-context";
import { buildSectionInput, inferRepositoryKind } from "./report-helpers";

type DocumentationSections = DocumentationInputModel["sections"];

function buildOverviewSection(
  evidence: RepositoryEvidence,
  context: DocumentationContext
): DocumentationInputModel["sections"]["overview"] {
  const body: OverviewSectionBody = {
    configFiles: evidence.configs.map((config) => config.path),
    primaryEntrypoints: context.primaryEntrypoints,
    primaryModules: context.architectureModules.slice(0, 8).map((module) => module.path),
    repositoryKind: inferRepositoryKind({
      primaryEntrypoints: context.primaryEntrypoints,
      routeInventory: context.routeInventory,
    }),
    stackProfile: context.stackProfile,
  };

  return buildSectionInput({
    audience: "mixed",
    body,
    confidence:
      60 +
      (body.primaryEntrypoints.length > 0 ? 15 : 0) +
      (body.stackProfile.length > 0 ? 15 : 0) +
      (body.primaryModules.length > 0 ? 10 : 0),
    evidencePaths: [
      ...body.primaryEntrypoints,
      ...body.primaryModules,
      ...body.configFiles.slice(0, 6),
    ],
    section: "overview",
    summary: [
      `Repository kind inferred as ${body.repositoryKind}.`,
      body.stackProfile.length > 0
        ? `Stack profile: ${body.stackProfile.slice(0, 8).join(", ")}.`
        : "Stack profile is only partially known.",
      body.primaryEntrypoints.length > 0
        ? `Primary entrypoints: ${body.primaryEntrypoints.slice(0, 5).join(", ")}.`
        : "Primary entrypoints are only partially known.",
    ],
    title: "Overview",
    unknowns: [
      ...(body.primaryEntrypoints.length === 0
        ? ["Primary entrypoints are only partially known."]
        : []),
      ...(body.stackProfile.length === 0
        ? ["Framework/runtime stack is only partially known."]
        : []),
      ...(body.repositoryKind === "unknown"
        ? ["Repository kind could not be inferred confidently."]
        : []),
    ],
  });
}

function buildArchitectureSection(
  evidence: RepositoryEvidence,
  metrics: RepoMetrics,
  context: DocumentationContext
): DocumentationInputModel["sections"]["architecture"] {
  const body = {
    dependencyCycles: evidence.dependencyCycles,
    dependencyHotspots: metrics.dependencyHotspots,
    graphReliability: context.graphReliability,
    modules: context.architectureModules,
    orphanModules: evidence.orphanModules,
    primaryEntrypoints: context.primaryEntrypoints,
  };

  return buildSectionInput({
    audience: "mixed",
    body,
    confidence:
      62 +
      (body.modules.length > 0 ? 18 : 0) +
      (body.primaryEntrypoints.length > 0 ? 10 : 0) -
      Math.min(20, context.graphReliability.unresolvedImportSpecifiers),
    evidencePaths: [
      ...body.primaryEntrypoints,
      ...body.modules.slice(0, 10).map((module) => module.path),
      ...body.orphanModules.slice(0, 4),
    ],
    section: "architecture",
    summary: [
      body.modules.length > 0
        ? `Primary runtime-relevant modules: ${body.modules
            .slice(0, 5)
            .map((module) => module.path)
            .join(", ")}.`
        : "Primary runtime module boundaries are only partially known.",
      body.dependencyCycles.length > 0
        ? `Dependency cycle groups detected: ${body.dependencyCycles.length}.`
        : "No dependency cycles were detected in the analyzed graph.",
      `Resolved dependency edges: ${body.graphReliability.resolvedEdges}.`,
    ],
    title: "Architecture",
    unknowns: [
      ...(context.graphReliability.unresolvedImportSpecifiers > 0
        ? [
            "Dependency graph has unresolved internal imports, so some relationships may be partial.",
          ]
        : []),
      ...(evidence.orphanModules.length > 0
        ? ["Some runtime-relevant modules sit outside clear inbound dependency flows."]
        : []),
    ],
  });
}

function buildApiReferenceSection(
  evidence: RepositoryEvidence,
  context: DocumentationContext
): DocumentationInputModel["sections"]["api_reference"] {
  const apiEntrypoints = context.entrypoints
    .filter((entrypoint) => entrypoint.kind === "library" || entrypoint.kind === "runtime")
    .filter((entrypoint) => ProjectPolicy.isPrimaryApiSurface(entrypoint.path))
    .slice(0, 24);
  const publicSurfacePaths = uniquePaths(
    evidence.publicSurface.length > 0
      ? evidence.publicSurface
          .map((symbol) => symbol.path)
          .filter((path) => ProjectPolicy.isPrimaryApiSurface(path))
      : context.entrypoints
          .filter((entrypoint) => entrypoint.kind === "library")
          .map((entrypoint) => entrypoint.path)
          .filter((path) => ProjectPolicy.isPrimaryApiSurface(path)),
    48
  );
  const hasConcreteRuntimeApi =
    context.routeInventory.sourceFiles.length > 0 &&
    (context.routeInventory.httpRoutes.length > 0 || context.routeInventory.rpcProcedures > 0);
  const body: ApiReferenceSectionBody = {
    entrypoints: apiEntrypoints,
    frameworkFacts: context.frameworkFacts,
    publicSurfacePaths,
    routeInventory: context.routeInventory,
    sourceOfTruth: hasConcreteRuntimeApi ? context.routeInventory.source : "unknown",
  };

  return buildSectionInput({
    audience: "mixed",
    body,
    confidence:
      55 +
      (hasConcreteRuntimeApi ? 20 : 0) +
      (body.publicSurfacePaths.length > 0 ? 15 : 0) +
      (context.frameworkFacts.length > 0 ? 10 : 0),
    evidencePaths: [
      ...body.entrypoints.map((entrypoint) => entrypoint.path),
      ...body.publicSurfacePaths,
      ...context.routeInventory.sourceFiles,
    ],
    section: "api_reference",
    summary: [
      hasConcreteRuntimeApi && context.routeInventory.estimatedOperations > 0
        ? `Estimated public API operations: ${context.routeInventory.estimatedOperations}.`
        : body.publicSurfacePaths.length > 0
          ? "Repository exposes a framework/library public surface rather than a concrete application HTTP API."
          : "No explicit HTTP operation inventory was extracted.",
      body.publicSurfacePaths.length > 0
        ? `Public interface paths: ${body.publicSurfacePaths.slice(0, 5).join(", ")}.`
        : "Public interface paths are only partially known.",
      `API/reference source of truth: ${body.sourceOfTruth}.`,
    ],
    title: "API/Reference",
    unknowns: [
      ...(context.routeInventory.sourceFiles.length === 0 && body.publicSurfacePaths.length === 0
        ? ["Public interface surface could not be identified confidently."]
        : []),
      ...(!hasConcreteRuntimeApi && body.publicSurfacePaths.length > 0
        ? [
            "This repository looks more like a framework/library public surface than a concrete application API.",
          ]
        : []),
      ...(context.routeInventory.source === "extracted" &&
      context.routeInventory.estimatedOperations === 0
        ? [
            "HTTP operation inventory is intentionally treated as partial because no strong runtime route evidence was found.",
          ]
        : []),
    ],
  });
}

function buildOnboardingSection(
  evidence: RepositoryEvidence,
  apiReferenceSection: DocumentationInputModel["sections"]["api_reference"],
  context: DocumentationContext
): DocumentationInputModel["sections"]["onboarding"] {
  const firstLookPaths = uniquePaths(
    [
      ...context.primaryEntrypoints,
      ...context.architectureModules.slice(0, 6).map((module) => module.path),
      ...evidence.configs.slice(0, 4).map((config) => config.path),
    ],
    12
  );
  const body: OnboardingSectionBody = {
    apiPaths: uniquePaths(
      [
        ...context.routeInventory.sourceFiles,
        ...apiReferenceSection.body.publicSurfacePaths.slice(0, 8),
      ],
      12
    ),
    configPaths: evidence.configs.map((config) => config.path).slice(0, 12),
    firstLookPaths,
    newcomerSteps: [
      context.primaryEntrypoints.length > 0
        ? `Start with the primary entrypoints: ${context.primaryEntrypoints.slice(0, 3).join(", ")}.`
        : "Start with the highest-signal runtime modules because no clear primary entrypoint was inferred.",
      evidence.configs.length > 0
        ? `Review runtime and build configuration in: ${evidence.configs
            .slice(0, 3)
            .map((config) => config.path)
            .join(", ")}.`
        : "Configuration files were not confidently identified from the analyzed selection.",
      context.routeInventory.sourceFiles.length > 0 ||
      apiReferenceSection.body.publicSurfacePaths.length > 0
        ? `Inspect the public interface via: ${[...context.routeInventory.sourceFiles, ...apiReferenceSection.body.publicSurfacePaths].slice(0, 3).join(", ")}.`
        : "Public API/reference entry files were not confidently identified from the analyzed selection.",
      context.risksBody.hotspots.length > 0
        ? `Before making changes, inspect the highest-risk files: ${context.risksBody.hotspots
            .slice(0, 3)
            .map((signal) => signal.path)
            .join(", ")}.`
        : "No strong structural hotspots were identified from the analyzed selection.",
    ],
    riskPaths: context.risksBody.hotspots.slice(0, 8).map((signal) => signal.path),
  };

  return buildSectionInput({
    audience: "newcomer",
    body,
    confidence:
      58 +
      (body.firstLookPaths.length > 0 ? 18 : 0) +
      (body.configPaths.length > 0 ? 10 : 0) +
      (body.apiPaths.length > 0 ? 8 : 0),
    evidencePaths: [
      ...body.firstLookPaths,
      ...body.configPaths,
      ...body.apiPaths,
      ...body.riskPaths,
    ],
    section: "onboarding",
    summary: [
      body.firstLookPaths.length > 0
        ? `Suggested first-look paths: ${body.firstLookPaths.slice(0, 5).join(", ")}.`
        : "No clear first-look paths were inferred.",
      body.riskPaths.length > 0
        ? `Inspect risky files early: ${body.riskPaths.slice(0, 4).join(", ")}.`
        : "No strong risk paths were inferred for onboarding.",
    ],
    title: "Onboarding Map",
    unknowns: [
      ...(context.primaryEntrypoints.length === 0
        ? ["Onboarding path starts from modules rather than a clear bootstrap file."]
        : []),
      ...(evidence.configs.length === 0
        ? ["Configuration starting points are not confidently known."]
        : []),
    ],
  });
}

function buildRisksSection(
  context: DocumentationContext
): DocumentationInputModel["sections"]["risks"] {
  return buildSectionInput({
    audience: "tech-lead",
    body: context.risksBody,
    confidence:
      55 +
      Math.round(context.risksBody.derivedScores.overallRisk * 0.25) +
      (context.risksBody.findings.length > 0 ? 8 : 0),
    evidencePaths: context.risksBody.findings.flatMap((finding) =>
      finding.evidence.map((item) => item.path)
    ),
    section: "risks",
    summary: [
      context.risksBody.findings.length > 0
        ? `Top risk signals: ${context.risksBody.findings
            .slice(0, 3)
            .map((finding) => finding.title)
            .join("; ")}.`
        : "No strong structural hotspots were inferred.",
      context.risksBody.rawMetrics.dependencyCycleGroups > 0
        ? `Dependency cycles detected: ${context.risksBody.rawMetrics.dependencyCycleGroups}.`
        : "No dependency cycles were detected.",
      context.risksBody.rawMetrics.changeCouplingPairs > 0
        ? `Change coupling pairs detected: ${context.risksBody.rawMetrics.changeCouplingPairs}.`
        : "No strong change-coupling pairs were detected.",
    ],
    title: "Risks",
    unknowns: [
      ...(context.risksBody.rawMetrics.changeCouplingPairs === 0
        ? ["Change coupling is unavailable or not strong enough to surface."]
        : []),
      ...(context.risksBody.rawMetrics.hotspotCount === 0
        ? ["Structural hotspots were not confidently identified."]
        : []),
      ...(context.risksBody.rawMetrics.unresolvedInternalImports > 0
        ? [
            "Some internal dependencies remain unresolved, so architectural risk is only partially known.",
          ]
        : []),
    ],
  });
}

export function buildDocumentationSections(
  evidence: RepositoryEvidence,
  metrics: RepoMetrics,
  context: DocumentationContext
): DocumentationSections {
  const overview = buildOverviewSection(evidence, context);
  const architecture = buildArchitectureSection(evidence, metrics, context);
  const apiReference = buildApiReferenceSection(evidence, context);
  const onboarding = buildOnboardingSection(evidence, apiReference, context);
  const risks = buildRisksSection(context);

  return {
    api_reference: apiReference,
    architecture,
    onboarding,
    overview,
    risks,
  };
}

import type { RepositoryEvidence } from "../core/discovery.types";
import { REPORT_FOCUS_SECTIONS, type DocumentationInputModel } from "../core/documentation.types";
import type { RepoMetrics } from "../core/metrics.types";
import {
  buildDocumentationContext,
  type DocumentationContext,
} from "./documentation-input-context";
import { buildDocumentationSections } from "./documentation-input-sections";

function buildApiInput(
  context: DocumentationContext,
  sections: DocumentationInputModel["sections"]
): DocumentationInputModel["api"] {
  return {
    entrypoints: context.entrypoints,
    frameworkFacts: context.frameworkFacts,
    publicSurfacePaths: sections.api_reference.body.publicSurfacePaths,
    routeInventory: context.routeInventory,
  };
}

function buildArchitectureInput(
  evidence: RepositoryEvidence,
  metrics: RepoMetrics,
  context: DocumentationContext
): DocumentationInputModel["architecture"] {
  return {
    dependencyCycles: evidence.dependencyCycles,
    dependencyHotspots: metrics.dependencyHotspots,
    graphReliability: context.graphReliability,
    modules: context.architectureModules,
    orphanModules: evidence.orphanModules,
  };
}

function buildCodebaseInput(
  evidence: RepositoryEvidence,
  metrics: RepoMetrics,
  context: DocumentationContext
): DocumentationInputModel["codebase"] {
  const fileCategoryBreakdown =
    evidence.fileCategoryBreakdown.length > 0
      ? evidence.fileCategoryBreakdown
      : (metrics.fileCategoryBreakdown ?? []);

  return {
    configFiles: evidence.configs.map((config) => config.path),
    fileCategoryBreakdown: fileCategoryBreakdown.map((item) => ({
      category: item.category,
      count: item.count,
    })),
    frameworkFacts: context.frameworkFacts,
    languages: metrics.analysisCoverage.languagesByMode,
    totalFiles: metrics.fileCount,
  };
}

function buildReportInput(context: DocumentationContext): DocumentationInputModel["report"] {
  return {
    audiences: ["newcomer", "tech-lead"],
    focusSections: [...REPORT_FOCUS_SECTIONS],
    primaryEntrypoints: context.primaryEntrypoints,
    secondaryEntrypoints: context.secondaryEntrypoints,
    stackProfile: context.stackProfile,
  };
}

function buildRiskInput(context: DocumentationContext): DocumentationInputModel["risks"] {
  return {
    changeCoupling: context.risksBody.changeCoupling,
    hotspots: context.hotspots.length > 0 ? context.hotspots : context.risksBody.hotspots,
  };
}

// Canonical bridge from deterministic backend analysis to section-first report inputs for docs and AI writers.
export function buildDocumentationInputModel(
  evidence: RepositoryEvidence,
  metrics: RepoMetrics
): DocumentationInputModel {
  const context = buildDocumentationContext(evidence, metrics);
  const sections = buildDocumentationSections(evidence, metrics, context);

  return {
    api: buildApiInput(context, sections),
    architecture: buildArchitectureInput(evidence, metrics, context),
    codebase: buildCodebaseInput(evidence, metrics, context),
    report: buildReportInput(context),
    risks: buildRiskInput(context),
    sections,
  };
}

import { uniquePaths } from "../../lib/array-utils";
import type { EntrypointRef, ModuleRef, RouteInventory } from "../core/discovery.types";
import type {
  DocumentationAudience,
  ReportSectionInput,
  ReportSectionKind,
} from "../core/documentation.types";
import { ProjectPolicy } from "../core/project-policy";

type SectionBuilderArgs<TBody> = {
  audience: "mixed" | DocumentationAudience;
  body: TBody;
  confidence: number;
  evidencePaths: Array<false | null | string | undefined>;
  section: ReportSectionKind;
  summary: string[];
  title: string;
  unknowns: string[];
};

type RankedModule = Pick<ModuleRef, "apiSurface" | "exports" | "path" | "routeCount" | "symbols">;

export function clampSectionConfidence(value: number) {
  return Math.max(0, Math.min(100, Math.round(value)));
}

export function rankArchitectureModule(module: RankedModule) {
  return module.apiSurface * 6 + module.routeCount * 5 + module.exports * 2 + module.symbols.length;
}

export function sortArchitectureModules<TModule extends RankedModule>(modules: TModule[]) {
  return [...modules].sort(
    (left, right) =>
      rankArchitectureModule(right) - rankArchitectureModule(left) ||
      left.path.localeCompare(right.path)
  );
}

function isPrimaryArchitectureModule(module: Pick<ModuleRef, "categories">) {
  return ProjectPolicy.isPrimaryArchitectureCategories(module.categories);
}

export function getPrimaryArchitectureModules(modules: ModuleRef[], limit = 24) {
  return sortArchitectureModules(
    modules.filter((module) => isPrimaryArchitectureModule(module))
  ).slice(0, limit);
}

export function getPrimaryEntrypointPaths(entrypoints: EntrypointRef[]) {
  return ProjectPolicy.filterPrimaryEntrypointPaths(
    entrypoints
      .filter((entrypoint) => entrypoint.kind === "library" || entrypoint.kind === "runtime")
      .map((entrypoint) => entrypoint.path)
  );
}

export function getSecondaryEntrypointPaths(entrypoints: EntrypointRef[]) {
  return entrypoints
    .filter((entrypoint) => entrypoint.kind !== "library" && entrypoint.kind !== "runtime")
    .map((entrypoint) => entrypoint.path);
}

export function inferRepositoryKind(params: {
  primaryEntrypoints: string[];
  routeInventory: RouteInventory;
}) {
  const hasRuntimeEntrypoint = params.primaryEntrypoints.some(
    (path) => !/\/index\.[cm]?[jt]sx?$/iu.test(path)
  );
  const hasLibrarySurface = params.primaryEntrypoints.some((path) =>
    /\/index\.[cm]?[jt]sx?$/iu.test(path)
  );
  const hasApiSurface = params.routeInventory.estimatedOperations > 0;

  if ((hasRuntimeEntrypoint || hasApiSurface) && hasLibrarySurface) return "mixed";
  if (hasRuntimeEntrypoint || hasApiSurface) return "service";
  if (hasLibrarySurface) return "library";
  return "unknown";
}

export function buildSectionInput<TBody>(
  args: SectionBuilderArgs<TBody>
): ReportSectionInput<TBody> {
  return {
    audience: args.audience,
    body: args.body,
    confidence: clampSectionConfidence(args.confidence),
    evidencePaths: uniquePaths(args.evidencePaths),
    section: args.section,
    summary: args.summary,
    title: args.title,
    unknowns: args.unknowns,
  };
}

export function buildReferenceEvidencePaths(params: {
  fallbackPaths?: string[];
  limit?: number;
  modules: RankedModule[];
  primaryEntrypoints: string[];
}) {
  if (params.primaryEntrypoints.length > 0) {
    return uniquePaths(params.primaryEntrypoints, params.limit);
  }

  const modulePaths = sortArchitectureModules(params.modules)
    .slice(0, params.limit ?? 12)
    .map((module) => module.path);

  return uniquePaths(
    modulePaths.length > 0 ? modulePaths : (params.fallbackPaths ?? []),
    params.limit
  );
}

import { dumpDebug } from "../../lib/debug-logger";
import { buildEvidence, clamp } from "../core/common";
import type {
  ChangeCouplingRef,
  DependencyGraphEvidence,
  HotspotSignal,
  RepositoryEvidence,
  RiskDerivedScores,
  RiskFindingRef,
  RiskRawMetrics,
} from "../core/discovery.types";
import type { RisksSectionBody } from "../core/documentation.types";
import type { RepoMetrics } from "../core/metrics.types";
import { RISK_SCORING } from "../core/scoring-constants";

function severityForScore(score: number): RiskFindingRef["severity"] {
  if (score >= 85) return "CRITICAL";
  if (score >= 65) return "HIGH";
  if (score >= 40) return "MODERATE";
  return "LOW";
}

function buildGraphReliability(
  evidence: RepositoryEvidence,
  metrics: Pick<RepoMetrics, "graphReliability">
): DependencyGraphEvidence {
  if (metrics.graphReliability == null) {
    return evidence.dependencyGraph;
  }

  return {
    ...evidence.dependencyGraph,
    resolvedEdges: metrics.graphReliability.resolvedEdges,
    unresolvedImportSpecifiers: metrics.graphReliability.unresolvedImportSpecifiers,
    unresolvedSamples: metrics.graphReliability.unresolvedSamples,
  };
}

function buildRiskRawMetrics(
  evidence: RepositoryEvidence,
  hotspots: HotspotSignal[],
  changeCoupling: ChangeCouplingRef[],
  graphReliability: DependencyGraphEvidence
): RiskRawMetrics {
  return {
    changeCouplingPairs: changeCoupling.length,
    dependencyCycleGroups: evidence.dependencyCycles.length,
    hotspotCount: hotspots.length,
    orphanModuleCount: evidence.orphanModules.length,
    resolvedEdges: graphReliability.resolvedEdges,
    strongestChangeCouplingCommits: Math.max(0, ...changeCoupling.map((pair) => pair.commits)),
    strongestHotspotScore: Math.max(0, ...hotspots.map((signal) => signal.score)),
    unresolvedInternalImports: graphReliability.unresolvedImportSpecifiers,
  };
}

function buildRiskDerivedScores(
  rawMetrics: RiskRawMetrics,
  metrics: Pick<RepoMetrics, "complexityScore">
): RiskDerivedScores {
  const derivedScores: RiskDerivedScores = {
    changeCouplingRisk: clamp(
      RISK_SCORING.changeCouplingBase +
        rawMetrics.strongestChangeCouplingCommits * RISK_SCORING.strongestCommitMultiplier +
        rawMetrics.changeCouplingPairs * RISK_SCORING.pairMultiplier,
      0,
      100
    ),
    dependencyCycleRisk: clamp(
      RISK_SCORING.dependencyCycleBase +
        rawMetrics.dependencyCycleGroups * RISK_SCORING.cycleMultiplier,
      0,
      100
    ),
    graphReliabilityRisk: clamp(
      rawMetrics.unresolvedInternalImports * RISK_SCORING.unresolvedImportMultiplier,
      0,
      100
    ),
    hotspotRisk: clamp(
      Math.round(
        rawMetrics.strongestHotspotScore * RISK_SCORING.hotspotScoreMultiplier +
          rawMetrics.hotspotCount * RISK_SCORING.hotspotCountMultiplier +
          metrics.complexityScore * RISK_SCORING.complexityWeightInHotspot
      ),
      0,
      100
    ),
    orphanModuleRisk: clamp(
      RISK_SCORING.orphanModuleBase +
        rawMetrics.orphanModuleCount * RISK_SCORING.orphanCountMultiplier,
      0,
      100
    ),
    overallRisk: 0,
  };

  derivedScores.overallRisk = clamp(
    Math.round(
      (derivedScores.changeCouplingRisk +
        derivedScores.dependencyCycleRisk +
        derivedScores.graphReliabilityRisk +
        derivedScores.hotspotRisk +
        derivedScores.orphanModuleRisk) /
        5
    ),
    0,
    100
  );

  return derivedScores;
}

function createRiskFinding(
  input: Omit<RiskFindingRef, "severity"> & { score: number }
): RiskFindingRef {
  return {
    ...input,
    severity: severityForScore(input.score),
  };
}

function buildDependencyCycleFinding(
  evidence: RepositoryEvidence,
  derivedScores: RiskDerivedScores
): null | RiskFindingRef {
  if (evidence.dependencyCycles.length === 0) return null;

  return createRiskFinding({
    category: "architecture",
    confidence: 92,
    evidence: buildEvidence(evidence.dependencyCycles[0] ?? [], "Break this cycle first"),
    id: "risk-dependency-cycles",
    score: derivedScores.dependencyCycleRisk,
    signal: "dependency-cycle",
    suggestedNextChange:
      "Break one cycle first by extracting a lower-level shared module or a small boundary interface.",
    summary: `Detected ${evidence.dependencyCycles.length} dependency cycle groups in the analyzed graph.`,
    title: "Dependency cycles increase architectural drag",
    whyItMatters:
      "Cycles increase blast radius, weaken isolation, and make safe refactoring harder across multiple modules.",
  });
}

function buildHotspotFinding(
  hotspots: HotspotSignal[],
  derivedScores: RiskDerivedScores
): null | RiskFindingRef {
  if (hotspots.length === 0) return null;

  return createRiskFinding({
    category: "hotspot",
    confidence: 78,
    evidence: buildEvidence(
      hotspots.slice(0, 10).map((signal) => signal.path),
      "Static hotspot candidate"
    ),
    id: "risk-hotspots",
    score: derivedScores.hotspotRisk,
    signal: "hotspot",
    suggestedNextChange:
      "Refactor the first hotspot by shrinking responsibilities or extracting lower-risk helpers around the core flow.",
    summary: `Top hotspots combine complexity, centrality, and API weight: ${hotspots
      .slice(0, 8)
      .map((signal) => signal.path)
      .join(", ")}.`,
    title: "A small set of files dominates change risk",
    whyItMatters:
      "When central and complex files keep growing, routine edits become slower, harder to review, and more error-prone.",
  });
}

function buildChangeCouplingFinding(
  changeCoupling: ChangeCouplingRef[],
  derivedScores: RiskDerivedScores
): null | RiskFindingRef {
  if (changeCoupling.length === 0) return null;

  const strongestPairs = changeCoupling.slice(0, 6);

  return createRiskFinding({
    category: "change-risk",
    confidence: 80,
    evidence: strongestPairs.flatMap((pair) => [
      {
        note: `${pair.commits} shared commits with ${pair.toPath}`,
        path: pair.fromPath,
      },
      {
        note: `${pair.commits} shared commits with ${pair.fromPath}`,
        path: pair.toPath,
      },
    ]),
    id: "risk-change-coupling",
    score: derivedScores.changeCouplingRisk,
    signal: "change-coupling",
    suggestedNextChange:
      "Review the strongest co-change pairs and decide whether shared abstractions or boundary cleanup would reduce coordinated edits.",
    summary: `Frequent co-change pairs suggest hidden coupling across ${strongestPairs.length} file pairs.`,
    title: "Change coupling reveals hidden coordination costs",
    whyItMatters:
      "Files that change together repeatedly often share an implicit responsibility that the static module graph does not explain well enough.",
  });
}

function buildOrphanModuleFinding(
  evidence: RepositoryEvidence,
  derivedScores: RiskDerivedScores
): null | RiskFindingRef {
  if (evidence.orphanModules.length === 0) return null;

  return createRiskFinding({
    category: "maintainability",
    confidence: 72,
    evidence: buildEvidence(evidence.orphanModules.slice(0, 8), "Orphan module candidate"),
    id: "risk-orphan-modules",
    score: derivedScores.orphanModuleRisk,
    signal: "orphan-module",
    suggestedNextChange:
      "Review orphan modules for dead code, implicit entrypoints, or boundaries that should be documented explicitly.",
    summary: `Detected ${evidence.orphanModules.length} runtime-relevant modules without inbound references or primary-entrypoint status.`,
    title: "Orphan modules make architecture harder to reason about",
    whyItMatters:
      "Modules that sit outside clear dependency flows often confuse newcomers and hide dead or poorly integrated code paths.",
  });
}

function buildGraphReliabilityFinding(
  graphReliability: DependencyGraphEvidence,
  derivedScores: RiskDerivedScores
): null | RiskFindingRef {
  if (graphReliability.unresolvedImportSpecifiers === 0) return null;

  return createRiskFinding({
    category: "architecture",
    confidence: 70,
    evidence: graphReliability.unresolvedSamples.map((sample) => ({
      note: `unresolved import: ${sample.specifier}`,
      path: sample.fromPath,
    })),
    id: "risk-graph-reliability",
    score: derivedScores.graphReliabilityRisk,
    signal: "graph-reliability",
    suggestedNextChange:
      "Improve import/path resolution so the architectural graph is more complete and the resulting docs are more trustworthy.",
    summary: `${graphReliability.unresolvedImportSpecifiers} internal import paths could not be mapped to analyzed files.`,
    title: "Dependency graph reliability is partial",
    whyItMatters:
      "When internal imports remain unresolved, architectural conclusions and refactoring guidance become less reliable.",
  });
}

function buildRiskFindings(
  evidence: RepositoryEvidence,
  hotspots: HotspotSignal[],
  changeCoupling: ChangeCouplingRef[],
  graphReliability: DependencyGraphEvidence,
  derivedScores: RiskDerivedScores
) {
  return [
    buildDependencyCycleFinding(evidence, derivedScores),
    buildHotspotFinding(hotspots, derivedScores),
    buildChangeCouplingFinding(changeCoupling, derivedScores),
    buildOrphanModuleFinding(evidence, derivedScores),
    buildGraphReliabilityFinding(graphReliability, derivedScores),
  ]
    .filter((finding): finding is RiskFindingRef => finding != null)
    .sort((left, right) => right.score - left.score);
}

export function buildRiskSectionBody(
  evidence: RepositoryEvidence,
  metrics: Pick<
    RepoMetrics,
    "changeCoupling" | "complexityScore" | "graphReliability" | "hotspotSignals"
  >
): RisksSectionBody {
  const hotspots =
    evidence.hotspotSignals.length > 0 ? evidence.hotspotSignals : (metrics.hotspotSignals ?? []);
  const changeCoupling = metrics.changeCoupling ?? [];
  const graphReliability = buildGraphReliability(evidence, metrics);
  const rawMetrics = buildRiskRawMetrics(evidence, hotspots, changeCoupling, graphReliability);
  const derivedScores = buildRiskDerivedScores(rawMetrics, metrics);
  const findings = buildRiskFindings(
    evidence,
    hotspots,
    changeCoupling,
    graphReliability,
    derivedScores
  );

  const riskBody: RisksSectionBody = {
    changeCoupling,
    dependencyCycles: evidence.dependencyCycles,
    derivedScores,
    findings,
    graphReliability,
    hotspots,
    orphanModules: evidence.orphanModules,
    rawMetrics,
  };

  void dumpDebug("risk-model", riskBody);
  return riskBody;
}

