import { existsSync } from "node:fs";
import fs from "node:fs/promises";
import type { Repo } from "@prisma/client";
import gitUrlParse from "git-url-parse";
import simpleGit from "simple-git";

import { prisma } from "@/server/shared/infrastructure/db";
import { executeWithFallback } from "@/server/shared/infrastructure/github/github-api";
import {
  GitHubAuthRequiredError,
  resolveClientContext,
} from "@/server/shared/infrastructure/github/github-provider";

const PRIVATE_REPO_AUTH_MESSAGE =
  "This is a private repository. Please install Doxynix App or connect GitHub.";

function assertPrivateRepoAccess(
  repo: Repo,
  clientType: "app" | "installation" | "oauth" | "public"
) {
  if (repo.visibility === "PRIVATE" && (clientType === "app" || clientType === "public")) {
    throw new Error(PRIVATE_REPO_AUTH_MESSAGE);
  }
}

async function resolveAuthToken(client: {
  auth: (() => Promise<unknown>) & ((options?: unknown) => Promise<unknown>);
}): Promise<null | string> {
  try {
    const auth = (await client.auth({ type: "installation" })) as { token?: string };
    return auth.token ?? null;
  } catch {
    try {
      const auth = (await client.auth()) as { token?: string };
      return auth.token ?? null;
    } catch {
      return null;
    }
  }
}

export async function getAnalysisContext(
  analysisId: string,
  userId: number,
  forceRefresh?: boolean
) {
  const analysis = await prisma.analysis.findUnique({
    include: {
      repo: {
        include: {
          analyses: {
            orderBy: { createdAt: "desc" },
            take: 1,
            where: { status: "DONE" },
          },
        },
      },
    },
    where: { publicId: analysisId },
  });

  if (analysis == null) throw new Error("Analysis not found");

  const repo = analysis.repo;
  const lastSuccessfulAnalysis = repo.analyses[0];

  let octokit;
  let clientType: "app" | "installation" | "oauth" | "public";

  try {
    const clientContext = await resolveClientContext(prisma, userId, {
      allowPublicFallback: true,
      allowSystemFallback: true,
      owner: repo.owner,
    });
    octokit = clientContext.octokit;
    clientType = clientContext.type;
  } catch (error) {
    if (error instanceof GitHubAuthRequiredError) {
      throw new Error(PRIVATE_REPO_AUTH_MESSAGE);
    }
    throw error;
  }

  assertPrivateRepoAccess(repo, clientType);

  const { currentSha, token } = await executeWithFallback(
    prisma,
    userId,
    octokit,
    clientType,
    async (client) => {
      const { data: refData } = await client.rest.git.getRef({
        owner: repo.owner,
        ref: `heads/${repo.defaultBranch}`,
        repo: repo.name,
      });

      const resolvedToken = await resolveAuthToken(client);
      return { currentSha: refData.object.sha, token: resolvedToken };
    }
  );

  if (repo.visibility === "PRIVATE" && token == null) {
    throw new Error("Unable to resolve GitHub token for private repository.");
  }

  if (forceRefresh === false && lastSuccessfulAnalysis?.commitSha === currentSha) {
    return { currentSha, repo: null, token };
  }

  return { currentSha, repo, token };
}

export async function cloneRepository(
  repo: Repo,
  token: null | string | undefined,
  targetPath: string,
  selectedBranch?: string
) {
  if (existsSync(targetPath)) {
    await fs.rm(targetPath, { force: true, recursive: true });
  }
  await fs.mkdir(targetPath, { recursive: true });

  const git = simpleGit();
  const branchToClone = selectedBranch ?? repo.defaultBranch;

  const parsed = gitUrlParse(repo.url);

  let repoUrl = repo.url;
  if (token != null) {
    repoUrl = `https://x-access-token:${token}@${parsed.resource}/${parsed.full_name}.git`;
  }

  const options = ["--filter=blob:none", "--single-branch", "--branch", branchToClone, "--no-tags"];

  try {
    await git.clone(repoUrl, targetPath, options);

    await git.cwd(targetPath);
  } catch (error) {
    if (existsSync(targetPath)) {
      await fs.rm(targetPath, { force: true, recursive: true });
    }
    throw new Error(
      `Failed to clone repository: ${error instanceof Error ? error.message : String(error)}`
    );
  }
}

import type { RestEndpointMethodTypes } from "@octokit/rest";
import { Visibility, type Repo } from "@prisma/client";

import type { RepoItemFields } from "@/shared/types/repo.types";

import { ProjectPolicy } from "../../engine/core/project-policy";
import { isOctokitError } from "../../lib/handle-error";
import { getLanguageColor } from "../../lib/language-metadata";
import type { DbClient } from "../db";
import { logger } from "../logger";
import {
  getInstallationClient,
  getUserClient,
  GitHubAuthRequiredError,
  resolveClientContext,
  type OctokitInstance,
} from "./github-provider";

type SearchRepoItem =
  RestEndpointMethodTypes["search"]["repos"]["response"]["data"]["items"][number];
type ListRepoItem =
  RestEndpointMethodTypes["repos"]["listForAuthenticatedUser"]["response"]["data"][number];
type InstallationRepoItem =
  RestEndpointMethodTypes["apps"]["listReposAccessibleToInstallation"]["response"]["data"]["repositories"][number];
type GitHubRepoResponse = InstallationRepoItem | ListRepoItem | SearchRepoItem;
type GitHubContextType = "app" | "installation" | "oauth" | "public";
const FALLBACK_RETRYABLE_STATUSES = new Set([401, 403, 404]);
/**
 * Validates repository access and returns metadata
 * Throws GitHubAuthRequiredError for unauthorized access to private repos
 * Complexity: 6 branches
 */

async function getRepoDataOrAuthError(
  client: OctokitInstance,
  owner: string,
  name: string,
  type: GitHubContextType
) {
  const isPublicContext = type === "app" || type === "public";

  try {
    const { data } = await client.rest.repos.get({ owner, repo: name });

    if (isPublicContext && data.private) {
      throw new GitHubAuthRequiredError();
    }

    return data;
  } catch (error) {
    if (isPublicContext && isOctokitError(error) && error.status === 403) {
      throw new GitHubAuthRequiredError();
    }
    throw error;
  }
}
/**
 * Transforms GitHub API repo objects to RepoItemFields
 */

export function mapRepos(data: GitHubRepoResponse[]): RepoItemFields[] {
  return data.map((repo) => ({
    description: repo.description ?? null,
    fullName: repo.full_name,
    language: repo.language ?? null,
    languageColor: getLanguageColor(repo.language),
    stars: repo.stargazers_count,
    updatedAt: repo.updated_at ?? new Date().toISOString(),
    visibility: repo.private ? Visibility.PRIVATE : Visibility.PUBLIC,
  }));
}

function dedupeReposByFullName(repos: RepoItemFields[]) {
  return Array.from(new Map(repos.map((repo) => [repo.fullName, repo])).values());
}

async function fetchInstallationRepos(installationId: number): Promise<RepoItemFields[]> {
  try {
    const octokit = getInstallationClient(installationId);
    const repos = await octokit.paginate(octokit.rest.apps.listReposAccessibleToInstallation);
    return mapRepos(repos as GitHubRepoResponse[]);
  } catch (error) {
    logger.error({ error, installationId, msg: "Failed installation fetch" });
    return [];
  }
}

async function fetchOauthRepos(account: { access_token: null | string; id: number | string }) {
  if (account.access_token == null) return [];
  try {
    const octokit = getUserClient(account.access_token);
    const repos = await octokit.paginate(octokit.rest.repos.listForAuthenticatedUser, {
      per_page: 100,
      visibility: "all",
    });
    return mapRepos(repos);
  } catch (error) {
    logger.error({ accountId: account.id, error, msg: "Failed OAuth fetch" });
    return [];
  }
}
/**
 * Lists all repositories accessible to user through:
 * - GitHub App installations
 * - OAuth tokens
 * Returns deduplicated list by fullName
 * Complexity: 8 branches
 */

export async function getMyRepos(prisma: DbClient, userId: number): Promise<RepoItemFields[]> {
  try {
    const [installations, oauthAccounts] = await Promise.all([
      prisma.githubInstallation.findMany({
        where: { isSuspended: false, userId },
      }),
      prisma.account.findMany({
        where: { access_token: { not: null }, provider: "github", userId },
      }),
    ]);

    if (installations.length === 0 && oauthAccounts.length === 0) return [];

    const installationTasks = installations.map((installation) =>
      fetchInstallationRepos(Number(installation.id))
    );
    const oauthTasks = oauthAccounts.map((account) => fetchOauthRepos(account));

    const results = await Promise.allSettled([...installationTasks, ...oauthTasks]);
    const allRepos = results.flatMap((result) =>
      result.status === "fulfilled" ? result.value : []
    );

    // Deduplicate by fullName
    return dedupeReposByFullName(allRepos);
  } catch (error) {
    logger.error({ error, msg: "Error fetching combined repositories", userId });
    return [];
  }
}
/**
 * Searches public/accessible repositories
 * For public contexts: filters to public repos only
 * Query length must be 2-256 chars
 * Complexity: 7 branches
 */

export async function searchRepos(
  prisma: DbClient,
  userId: number,
  query: string,
  limit: number | undefined
): Promise<RepoItemFields[]> {
  if (query.length < 2 || query.length > 256) return [];

  const context = await resolveClientContext(prisma, userId, {
    allowPublicFallback: true,
    allowSystemFallback: true,
  });

  const octokit = context.octokit;
  const queryWithVisibility =
    context.type === "app" || context.type === "public" ? `${query} is:public` : query;

  try {
    const { data } = await octokit.rest.search.repos({
      per_page: limit ?? 10,
      q: queryWithVisibility,
    });

    const items =
      context.type === "app" || context.type === "public"
        ? data.items.filter((repo) => !repo.private)
        : data.items;

    return mapRepos(items as GitHubRepoResponse[]);
  } catch (error) {
    logger.error({ error, msg: "GitHub search error" });
    return [];
  }
}
/**
 * Gets repository metadata (name, visibility, default branch, etc)
 * Validates access for public contexts
 * Retries with fallback on auth errors
 */

export async function getRepoInfo(prisma: DbClient, userId: number, owner: string, name: string) {
  const context = await resolveRepoClientContext(prisma, userId, owner);

  return executeWithFallback(prisma, userId, context.octokit, context.type, async (client) => {
    return await getRepoDataOrAuthError(client, owner, name, context.type);
  });
}
/**
 * Lists branch names for repository
 * For public contexts: validates repo access first
 * Pagination: 100 per page
 */

export async function getRepoBranches(
  prisma: DbClient,
  userId: number,
  owner: string,
  name: string
) {
  const context = await resolveRepoClientContext(prisma, userId, owner);

  return executeWithFallback(prisma, userId, context.octokit, context.type, async (client) => {
    if (context.type === "app" || context.type === "public") {
      await getRepoDataOrAuthError(client, owner, name, context.type);
    }

    const branches = await client.paginate(client.rest.repos.listBranches, {
      owner,
      per_page: 100,
      repo: name,
    });

    return branches.map((b) => b.name);
  });
}
/**
 * Gets repository file tree (blob entries only, recursively)
 * Filters ignored files via ProjectPolicy
 * Returns: {path, sha, type}[]
 * Complexity: 8 branches (error handling)
 */

export async function getRepoTree(
  prisma: DbClient,
  userId: number,
  owner: string,
  name: string,
  branch?: string
) {
  const context = await resolveRepoClientContext(prisma, userId, owner);

  try {
    return await executeWithFallback(
      prisma,
      userId,
      context.octokit,
      context.type,
      async (client) => {
        const repoData = await getRepoDataOrAuthError(client, owner, name, context.type);
        const treeSha = branch ?? repoData.default_branch;

        const { data } = await client.rest.git.getTree({
          owner,
          recursive: "1",
          repo: name,
          tree_sha: treeSha,
        });

        return data.tree
          .filter((item) => {
            if (!item.path) return false;
            if (item.type !== "blob") return false;
            return !ProjectPolicy.isIgnored(item.path);
          })
          .map((item) => ({ path: item.path, sha: item.sha, type: item.type }));
      }
    );
  } catch (error) {
    if (isOctokitError(error)) {
      logger.info({ msg: "Repo empty or not found", status: error.status });
      return [];
    }
    logger.error({ error, msg: "Error fetching repo tree" });
    throw error;
  }
}
export type GitHubFileResponse = {
  content: string;
  meta: {
    name: string;
    sha: string;
    size: number;
    url: null | string;
  };
};
/**
 * Retrieves file content from repository
 * Decodes base64 response to UTF-8
 * Validates that path is a file (not directory)
 * Retries with fallback on auth errors
 */

export async function getFileContent(
  prisma: DbClient,
  userId: number,
  owner: string,
  name: string,
  path: string,
  branch?: string
): Promise<GitHubFileResponse> {
  const context = await resolveRepoClientContext(prisma, userId, owner);

  return await executeWithFallback(
    prisma,
    userId,
    context.octokit,
    context.type,
    async (client) => {
      const { data } = await client.rest.repos.getContent({
        owner,
        path,
        ref: branch,
        repo: name,
      });

      if (Array.isArray(data) || data.type !== "file") {
        throw new Error("Target path is not a file");
      }

      return {
        content: Buffer.from(data.content, "base64").toString("utf8"),
        meta: {
          name: data.name,
          sha: data.sha,
          size: data.size,
          url: data.html_url,
        },
      };
    }
  );
} /**
 * Executes operation with fallback retry on auth errors
 * For installation/oauth clients: tries available oauth tokens on 401/403/404
 * Cycles through all available oauth accounts
 * Complexity: 10 branches
 */

export async function executeWithFallback<T>(
  prisma: DbClient,
  userId: number,
  initialOctokit: OctokitInstance,
  initialType: GitHubContextType,
  operation: (client: OctokitInstance) => Promise<T>
): Promise<T> {
  try {
    return await operation(initialOctokit);
  } catch (error) {
    if (shouldRetryWithOauthFallback(initialType, error)) {
      // Fetch all available oauth accounts
      const oauthAccounts = await prisma.account.findMany({
        where: { access_token: { not: null }, provider: "github", userId },
      });

      // Try each oauth account
      for (const oauthAcc of oauthAccounts) {
        if (oauthAcc.access_token == null) continue;

        try {
          const fallbackOctokit = getUserClient(oauthAcc.access_token);
          return await operation(fallbackOctokit);
        } catch (fallbackError) {
          logger.error({ error: fallbackError, msg: "Token didn't work in fallback" });
          continue;
        }
      }
    }

    throw error;
  }
}
export type BusFactorResult = {
  busFactor: number;
  rawContributors: Array<{
    contributions: number;
    login: string;
  }>;
};
/**
 * Calculates bus factor for repository
 * - Fetches contributors (max 500)
 * - Sorts by commit count
 * - Finds minimum team size for 50% of commits
 * - Validates private repo access
 * Complexity: 12 branches (error handling + auth)
 */

export async function calculateBusFactor(
  repo: Repo,
  userId: number,
  prisma: DbClient
): Promise<BusFactorResult> {
  try {
    const context = await resolveRepoClientContext(prisma, userId, repo.owner);

    const octokit = context.octokit;
    const clientType = context.type;

    // Validate private repo access
    if (repo.visibility === "PRIVATE" && (clientType === "app" || clientType === "public")) {
      throw new GitHubAuthRequiredError();
    }

    const contributors = await executeWithFallback(
      prisma,
      userId,
      octokit,
      clientType,
      async (client) => {
        let fetchedContributors = 0;

        return await client.paginate(
          client.rest.repos.listContributors,
          { owner: repo.owner, per_page: 100, repo: repo.name },
          (
            response: Awaited<ReturnType<OctokitInstance["rest"]["repos"]["listContributors"]>>,
            done: () => void
          ) => {
            fetchedContributors += response.data.length;
            if (fetchedContributors >= 500) done();
            return response.data;
          }
        );
      }
    );

    // Normalize and sort contributors
    const rawContributors = contributors
      .map((contributor: (typeof contributors)[number]) => ({
        contributions: contributor.contributions,
        login: contributor.login ?? "unknown",
      }))
      .sort((left, right) => right.contributions - left.contributions);

    const totalCommits = rawContributors.reduce(
      (acc: number, contributor) => acc + contributor.contributions,
      0
    );

    if (totalCommits === 0) {
      return {
        busFactor: 0,
        rawContributors,
      };
    }

    // Calculate bus factor: min team size for 50% of commits
    let runningSum = 0;
    let busFactor = 0;

    for (const contributor of rawContributors) {
      runningSum += contributor.contributions;
      busFactor++;
      if (runningSum >= totalCommits * 0.5) break;
    }

    return {
      busFactor,
      rawContributors,
    };
  } catch (error) {
    // Extract HTTP status if available
    const status =
      typeof error === "object" && error !== null && "status" in error
        ? Number((error as { status?: number }).status)
        : undefined;

    const isMissingAuth = error instanceof GitHubAuthRequiredError;

    // Private repo requires auth
    if (repo.visibility === "PRIVATE" && (isMissingAuth || isRetryableGithubStatus(status))) {
      if (isMissingAuth) throw error;
      throw new GitHubAuthRequiredError();
    }

    // Public repo: log and return default
    if (isMissingAuth || isRetryableGithubStatus(status)) {
      logger.warn({
        error,
        msg: "Failed to fetch contributors for Bus Factor calculation. Defaulting to 0.",
        repoId: repo.id,
      });
      return { busFactor: 0, rawContributors: [] };
    }

    throw error;
  }
}

function isRetryableGithubStatus(status: number | undefined) {
  return status != null && FALLBACK_RETRYABLE_STATUSES.has(status);
}

function shouldRetryWithOauthFallback(initialType: GitHubContextType, error: unknown) {
  return (
    (initialType === "installation" || initialType === "oauth") &&
    isOctokitError(error) &&
    isRetryableGithubStatus(error.status)
  );
}

async function resolveRepoClientContext(prisma: DbClient, userId: number, owner: string) {
  return resolveClientContext(prisma, userId, {
    allowPublicFallback: true,
    allowSystemFallback: true,
    owner,
  });
}

import crypto from "node:crypto";
import { TRPCError } from "@trpc/server";

import type { DbClient, PrismaClientExtended } from "@/server/shared/infrastructure/db";
import { getMyRepos } from "@/server/shared/infrastructure/github/github-api";
import {
  getInstallationInfo,
  getUserClient,
} from "@/server/shared/infrastructure/github/github-provider";
import { logger } from "@/server/shared/infrastructure/logger";
import { isOctokitError } from "@/server/shared/lib/handle-error";

type OauthValidationStatus = "invalid" | "missing" | "valid";

async function resolveOauthValidationStatus(
  oauthAccounts: Array<{ access_token: null | string }>
): Promise<OauthValidationStatus> {
  if (oauthAccounts.length === 0) return "missing";

  let hasUnauthorized = false;
  for (const oauthAccount of oauthAccounts) {
    if (oauthAccount.access_token == null) continue;
    try {
      const userOctokit = getUserClient(oauthAccount.access_token);
      await userOctokit.rest.users.getAuthenticated();
      return "valid";
    } catch (error) {
      if (isOctokitError(error) && error.status === 401) {
        hasUnauthorized = true;
      } else {
        logger.warn({ error, msg: "GitHub OAuth validation failed" });
      }
    }
  }

  return hasUnauthorized ? "invalid" : "missing";
}

export const githubAppService = {
  async getInstallUrl(prisma: PrismaClientExtended, userId: number) {
    const state = crypto.randomBytes(32).toString("hex");

    await prisma.$transaction([
      prisma.verificationToken.deleteMany({
        where: { identifier: `github_install_${userId}` },
      }),
      prisma.verificationToken.create({
        data: {
          expires: new Date(Date.now() + 10 * 60 * 1000),
          identifier: `github_install_${userId}`,
          token: state,
        },
      }),
    ]);

    return `https://github.com/apps/doxynix/installations/new?state=${state}`;
  },

  async getMyRepos(db: DbClient, prisma: PrismaClientExtended, userId: number) {
    const installations = await db.githubInstallation.findMany({
      orderBy: { createdAt: "asc" },
      where: { isSuspended: false, userId },
    });

    const oauthAccounts = await db.account.findMany({
      where: { access_token: { not: null }, provider: "github", userId },
    });

    if (installations.length === 0 && oauthAccounts.length === 0) {
      return {
        installationId: null,
        isConnected: false,
        items: [],
        manageUrl: null,
        oauthStatus: "missing" as const,
      };
    }

    const mainInstall = installations.length > 0 ? installations[0] : null;

    const manageUrl = mainInstall != null ? (mainInstall.htmlUrl ?? null) : null;
    const installationId = mainInstall != null ? Number(mainInstall.id) : null;

    const oauthStatus = await resolveOauthValidationStatus(oauthAccounts);

    if (installationId == null && oauthStatus === "invalid") {
      return { installationId, isConnected: true, items: [], manageUrl, oauthStatus };
    }

    try {
      const repos = await getMyRepos(prisma, userId);
      return { installationId, isConnected: true, items: repos, manageUrl, oauthStatus };
    } catch (error) {
      logger.error({ error, msg: "Dashboard fetch failed", userId });
      return { installationId, isConnected: true, items: [], manageUrl, oauthStatus };
    }
  },

  async saveInstallation(
    prisma: PrismaClientExtended,
    userIdNum: number,
    installationId: string,
    state: string
  ) {
    const instIdBigInt = BigInt(installationId);
    const inputInstIdNum = Number(installationId);

    const consumedState = await prisma.verificationToken.deleteMany({
      where: {
        expires: { gt: new Date() },
        identifier: `github_install_${userIdNum}`,
        token: state,
      },
    });

    if (consumedState.count === 0) {
      logger.warn({ msg: "CSRF/Replay attack or expired state", userId: userIdNum });
      throw new TRPCError({
        code: "FORBIDDEN",
        message: "Invalid, expired, or already used security state. Please try installing again.",
      });
    }

    const oauthAccounts = await prisma.account.findMany({
      select: { access_token: true },
      where: { access_token: { not: null }, provider: "github", userId: userIdNum },
    });

    if (oauthAccounts.length === 0) {
      throw new TRPCError({
        code: "FORBIDDEN",
        message: "You must link your GitHub account before installing the app.",
      });
    }

    let hasAccess = false;
    let verifiedAtLeastOneAccount = false;
    let hasUnauthorized = false;

    for (const oauthAccount of oauthAccounts) {
      if (oauthAccount.access_token == null) continue;
      try {
        const userOctokit = getUserClient(oauthAccount.access_token);
        const userInstallations = await userOctokit.paginate(
          userOctokit.rest.apps.listInstallationsForAuthenticatedUser,
          { per_page: 100 }
        );

        verifiedAtLeastOneAccount = true;

        if (userInstallations.some((inst) => inst.id === inputInstIdNum)) {
          hasAccess = true;
          break;
        }
      } catch (error) {
        if (isOctokitError(error) && (error.status === 401 || error.status === 403)) {
          hasUnauthorized = true;
        }
        logger.warn({ error, msg: "GitHub API verification failed for one OAuth account" });
      }
    }

    if (!verifiedAtLeastOneAccount) {
      if (hasUnauthorized) {
        throw new TRPCError({
          code: "FORBIDDEN",
          message: "GitHub authorization expired. Please relink your GitHub account.",
        });
      }
      throw new TRPCError({
        code: "INTERNAL_SERVER_ERROR",
        message: "Failed to verify installation ownership via GitHub.",
      });
    }

    if (!hasAccess) {
      logger.warn({
        installationId,
        msg: "IDOR attempt: User tried to claim unowned installation",
        userId: userIdNum,
      });
      throw new TRPCError({
        code: "FORBIDDEN",
        message: "You do not have permission to claim this GitHub installation.",
      });
    }

    const installationInfo = await getInstallationInfo(inputInstIdNum);
    const account = installationInfo.account;
    const accountLogin = account !== null && "login" in account ? account.login : "Unknown";
    const accountAvatar = account !== null && "avatar_url" in account ? account.avatar_url : null;

    try {
      const updated = await prisma.githubInstallation.updateMany({
        data: {
          accountAvatar,
          accountLogin,
          htmlUrl: installationInfo.html_url,
          repositorySelection: installationInfo.repository_selection,
          userId: userIdNum,
        },
        where: {
          id: instIdBigInt,
          OR: [{ userId: null }, { userId: userIdNum }],
        },
      });

      if (updated.count === 0) {
        const created = await prisma.githubInstallation.createMany({
          data: [
            {
              accountAvatar,
              accountLogin,
              appId: installationInfo.app_id,
              htmlUrl: installationInfo.html_url,
              id: instIdBigInt,
              repositorySelection: installationInfo.repository_selection,
              targetId: BigInt(installationInfo.target_id),
              targetType: installationInfo.target_type || "Unknown",
              userId: userIdNum,
            },
          ],
          skipDuplicates: true,
        });

        if (created.count === 0) {
          const claimed = await prisma.githubInstallation.updateMany({
            data: {
              accountAvatar,
              accountLogin,
              repositorySelection: installationInfo.repository_selection,
              userId: userIdNum,
            },
            where: {
              id: instIdBigInt,
              OR: [{ userId: null }, { userId: userIdNum }],
            },
          });

          if (claimed.count === 0) {
            throw new TRPCError({
              code: "FORBIDDEN",
              message: "This installation is already linked to another workspace.",
            });
          }
        }
      }
    } catch (error) {
      if (error instanceof TRPCError) throw error;

      logger.error({ error, msg: "Failed to securely claim installation" });
      throw new TRPCError({
        code: "INTERNAL_SERVER_ERROR",
        message: "Failed to securely claim installation.",
      });
    }

    return { success: true };
  },
};

import { TRPCError } from "@trpc/server";

import { getFileScore } from "@/server/shared/engine/core/file-classifier";
import type { DbClient, PrismaClientExtended } from "@/server/shared/infrastructure/db";
import {
  getFileContent,
  getRepoBranches,
  getRepoTree,
  searchRepos,
} from "@/server/shared/infrastructure/github/github-api";
import { GitHubAuthRequiredError } from "@/server/shared/infrastructure/github/github-provider";
import { logger } from "@/server/shared/infrastructure/logger";
import { isOctokitError } from "@/server/shared/lib/handle-error";

function throwBrowseAccessError(params: {
  authMessage: string;
  forbiddenMessage: string;
  notFoundMessage: string;
  sourceError: unknown;
}) {
  if (params.sourceError instanceof GitHubAuthRequiredError) {
    throw new TRPCError({
      code: "FORBIDDEN",
      message: params.authMessage,
    });
  }
  if (isOctokitError(params.sourceError) && params.sourceError.status === 404) {
    throw new TRPCError({
      code: "NOT_FOUND",
      message: params.notFoundMessage,
    });
  }
  if (isOctokitError(params.sourceError) && params.sourceError.status === 403) {
    throw new TRPCError({
      code: "FORBIDDEN",
      message: params.forbiddenMessage,
    });
  }
  throw params.sourceError;
}

export const githubBrowseService = {
  async getBranches(prisma: PrismaClientExtended, userId: number, owner: string, name: string) {
    try {
      return await getRepoBranches(prisma, userId, owner, name);
    } catch (error) {
      throwBrowseAccessError({
        authMessage: "Connect your GitHub account or install the app to access branches.",
        forbiddenMessage: "GitHub denied access to repository branches.",
        notFoundMessage: "Repository or branch not found.",
        sourceError: error,
      });
      throw error;
    }
  },

  async getFileContent(
    db: DbClient,
    prisma: PrismaClientExtended,
    userId: number,
    repoId: string,
    path: string,
    branch?: string
  ) {
    const repo = await db.repo.findUnique({
      where: { publicId: repoId, userId },
    });

    if (repo == null) {
      throw new TRPCError({ code: "NOT_FOUND", message: "Repository not found" });
    }

    try {
      const fileData = await getFileContent(
        prisma,
        userId,
        repo.owner,
        repo.name,
        path,
        branch ?? repo.defaultBranch
      );

      return {
        content: fileData.content,
        meta: fileData.meta,
      };
    } catch (error) {
      logger.error({ error, msg: "Failed to fetch file content from GitHub", path });
      if (
        error instanceof GitHubAuthRequiredError ||
        (isOctokitError(error) && (error.status === 403 || error.status === 404))
      ) {
        throwBrowseAccessError({
          authMessage: "Connect your GitHub account or install the app to access this file.",
          forbiddenMessage: "GitHub denied access to this file.",
          notFoundMessage: "File or branch not found.",
          sourceError: error,
        });
      }

      if (!isOctokitError(error)) {
        throw new TRPCError({
          code: "INTERNAL_SERVER_ERROR",
          message: "Could not fetch file content from GitHub.",
        });
      }
      throw error;
    }
  },

  async getRepoFiles(
    prisma: PrismaClientExtended,
    userId: number,
    owner: string,
    name: string,
    branch?: string
  ) {
    let tree: Awaited<ReturnType<typeof getRepoTree>> | null = null;
    try {
      tree = await getRepoTree(prisma, userId, owner, name, branch);
    } catch (error) {
      throwBrowseAccessError({
        authMessage: "Connect your GitHub account or install the app to access repository files.",
        forbiddenMessage: "GitHub denied access to repository files.",
        notFoundMessage: "Repository or branch not found.",
        sourceError: error,
      });
    }

    if (tree == null) {
      throw new TRPCError({
        code: "INTERNAL_SERVER_ERROR",
        message: "Could not fetch repository files from GitHub.",
      });
    }

    return tree.map((file) => [
      file.path,
      file.type === "blob" ? 1 : 0,
      file.sha.slice(0, 7),
      getFileScore(file.path) > 40 ? 1 : 0,
    ]);
  },

  async searchGithub(prisma: PrismaClientExtended, userId: number, query: string) {
    try {
      return await searchRepos(prisma, userId, query, 10);
    } catch (error) {
      if (error instanceof GitHubAuthRequiredError) {
        throw new TRPCError({
          code: "FORBIDDEN",
          message: "Connect your GitHub account or install the app to search repositories.",
        });
      }
      throw error;
    }
  },
};

import { createAppAuth } from "@octokit/auth-app";
import { paginateRest } from "@octokit/plugin-paginate-rest";
import { retry } from "@octokit/plugin-retry";
import { throttling } from "@octokit/plugin-throttling";
import { Octokit } from "@octokit/rest";
import type { RequestOptions } from "@octokit/types";
import gitUrlParse from "git-url-parse";

import {
  GITHUB_APP_ID,
  GITHUB_APP_PRIVATE_KEY,
  GITHUB_SYSTEM_INSTALLATION_ID,
  GITHUB_SYSTEM_PAT,
} from "@/shared/constants/env.server";

import type { DbClient } from "../db";
import { logger } from "../logger";

const MyOctokit = Octokit.plugin(retry, throttling, paginateRest);
export type OctokitInstance = InstanceType<typeof MyOctokit>;

const getCommonConfig = () => ({
  log: {
    debug: (msg: string) => logger.debug({ msg }),
    error: (msg: string) => logger.error({ msg }),
    info: (msg: string) => logger.info({ msg }),
    warn: (msg: string) => logger.warn({ msg }),
  },
  retry: {
    doNotRetry: [400, 401, 403, 429, 409, 422, 451, 404],
  },
  throttle: {
    onRateLimit: (
      retryAfter: number,
      options: RequestOptions,
      octokit: any,
      retryCount: number
    ) => {
      octokit.log.warn(
        `Rate limit hit: ${options.method} ${options.url}. Retrying after ${retryAfter}s. (Attempt ${retryCount})`
      );
      return retryCount < 2;
    },

    onSecondaryRateLimit: (
      retryAfter: number,
      options: RequestOptions,
      octokit: any,
      retryCount = 0
    ) => {
      octokit.log.warn(
        `Secondary rate limit hit: ${options.method} ${options.url}. Retrying after ${retryAfter}s. (Attempt ${retryCount})`
      );
      return retryCount < 2;
    },
  },
  userAgent: "Doxynix/1.0.0",
});

export function getInstallationClient(installationId: number): OctokitInstance {
  return new MyOctokit({
    ...getCommonConfig(),
    auth: {
      appId: Number(GITHUB_APP_ID),
      installationId,
      privateKey: GITHUB_APP_PRIVATE_KEY,
    },
    authStrategy: createAppAuth,
  }) as OctokitInstance;
}

export function getPublicClient(token?: string): OctokitInstance {
  return new MyOctokit({
    ...getCommonConfig(),
    auth: token,
  }) as OctokitInstance;
}

export function getSystemClient(): OctokitInstance {
  return getInstallationClient(Number(GITHUB_SYSTEM_INSTALLATION_ID));
}

export function getUserClient(token: string): OctokitInstance {
  return getPublicClient(token);
}

export class GitHubAuthRequiredError extends Error {
  constructor() {
    super(
      "No valid GitHub authorization found. Please connect your GitHub account or install the app."
    );
    this.name = "GitHubAuthRequiredError";
  }
}

export type GitHubClientContext = (
  | { githubInstallationId: number; hasUserToken: false; type: "installation" }
  | { hasUserToken: false; type: "app" }
  | { hasUserToken: false; type: "public" }
  | { hasUserToken: true; type: "oauth" }
) & {
  octokit: OctokitInstance;
};

export type ClientContextOptions = {
  allowPublicFallback?: boolean;
  allowSystemFallback?: boolean;
  owner?: string;
};

/**
 * Resolves user's GitHub client context based on available credentials
 * Priority: specific installation > oauth > any installation
 * Throws GitHubAuthRequiredError if no context available
 */
export async function getClientContext(
  prisma: DbClient,
  userId: number,
  owner?: string
): Promise<GitHubClientContext> {
  // Try specific installation for owner
  if (owner != null) {
    const specificInstallation = await prisma.githubInstallation.findFirst({
      where: { accountLogin: { equals: owner, mode: "insensitive" }, isSuspended: false, userId },
    });

    if (specificInstallation != null) {
      return {
        githubInstallationId: Number(specificInstallation.id),
        hasUserToken: false,
        octokit: getInstallationClient(Number(specificInstallation.id)),
        type: "installation",
      };
    }
  }

  // Try oauth tokens
  const oauthAccounts = await prisma.account.findMany({
    where: { access_token: { not: null }, provider: "github", userId },
  });

  if (oauthAccounts.length > 0 && oauthAccounts[0]?.access_token != null) {
    return {
      hasUserToken: true,
      octokit: getUserClient(oauthAccounts[0].access_token),
      type: "oauth",
    };
  }

  // Try any installation (if owner not specified)
  if (owner == null) {
    const anyInstallation = await prisma.githubInstallation.findFirst({
      where: { isSuspended: false, userId },
    });

    if (anyInstallation != null) {
      return {
        githubInstallationId: Number(anyInstallation.id),
        hasUserToken: false,
        octokit: getInstallationClient(Number(anyInstallation.id)),
        type: "installation",
      };
    }
  }

  throw new GitHubAuthRequiredError();
}

/**
 * Resolves client context with fallback chain:
 * 1. Primary client context
 * 2. If auth fails: public PAT (if allowPublicFallback)
 * 3. If auth fails: system app (if allowSystemFallback)
 * 4. If auth fails: unauthenticated public (if allowPublicFallback)
 */
export async function resolveClientContext(
  prisma: DbClient,
  userId: number,
  options?: ClientContextOptions
): Promise<GitHubClientContext> {
  try {
    return await getClientContext(prisma, userId, options?.owner);
  } catch (error) {
    if (error instanceof GitHubAuthRequiredError) {
      // Fallback 1: System PAT for public queries
      if (options?.allowPublicFallback === true && GITHUB_SYSTEM_PAT != null) {
        return {
          hasUserToken: false,
          octokit: getPublicClient(GITHUB_SYSTEM_PAT),
          type: "public",
        };
      }

      // Fallback 2: System app installation
      if (options?.allowSystemFallback === true) {
        return {
          hasUserToken: false,
          octokit: getSystemClient(),
          type: "app",
        };
      }

      // Fallback 3: Unauthenticated public
      if (options?.allowPublicFallback === true) {
        return {
          hasUserToken: false,
          octokit: getPublicClient(),
          type: "public",
        };
      }
    }
    throw error;
  }
}

/**
 * Parses GitHub URL or owner/repo string
 * Validates and normalizes owner and name
 * Throws if format invalid
 */
export function parseUrl(input: string): { name: string; owner: string } {
  const trimmedInput = input.trim();
  if (trimmedInput === "") throw new Error("Field cannot be empty");

  try {
    const parsed = gitUrlParse(trimmedInput);

    if (parsed.owner == null || parsed.name == null) {
      throw new Error("Repo not found");
    }

    return {
      name: parsed.name,
      owner: parsed.owner,
    };
  } catch {
    throw new Error("Invalid format. Enter 'owner/repo' or repository URL");
  }
}

/**
 * Retrieves GitHub token for user and optional owner
 * Returns null if token unavailable (logs error)
 */
export async function getToken(
  prisma: DbClient,
  userId: number,
  owner?: string
): Promise<null | string> {
  try {
    const context = await getClientContext(prisma, userId, owner);
    const auth =
      context.type === "installation"
        ? ((await context.octokit.auth({ type: "installation" })) as { token: string })
        : ((await context.octokit.auth()) as { token: string });
    return auth.token;
  } catch (error) {
    logger.error({ error, msg: "Failed to resolve GitHub token", userId });
    return null;
  }
}
/**
 * Gets installation metadata from GitHub App
 * Requires system app credentials
 */
export async function getInstallationInfo(installationId: number) {
  const octokit = getSystemClient();
  const { data } = await octokit.rest.apps.getInstallation({
    installation_id: installationId,
  });
  return data;
}

import { Logger } from "next-axiom";
import pino from "pino";
import pretty from "pino-pretty";

import { IS_PROD } from "@/shared/constants/env.flags";

import { requestContext } from "@/server/shared/lib/request-context";
import { sanitizePayload } from "@/server/shared/lib/sanitize-payload";

type SerializedError = {
  kind: string;
  message: string;
  stack?: string;
};

type LogPayload = Record<string, unknown> & {
  error?: Error | unknown;
  msg: string;
};

const prepareData = (payload: LogPayload) => {
  const store = requestContext.getStore();

  const rawData = { ...store, ...payload };

  if (rawData.error instanceof Error) {
    rawData.error = {
      kind: rawData.error.name,
      message: rawData.error.message,
      stack: rawData.error.stack,
    } satisfies SerializedError;
  }

  return sanitizePayload(rawData) as Record<string, unknown>;
};

const createPinoLogger = () => {
  if (IS_PROD) {
    return pino({ level: "info" });
  }

  const stream = pretty({
    colorize: true,
    ignore: "pid,hostname",
    messageKey: "msg",
    translateTime: "HH:MM:ss",
  });

  return pino(
    {
      base: undefined,
      level: "debug",
    },
    stream
  );
};

const pinoLogger = createPinoLogger();

const axiomLogger = IS_PROD ? new Logger() : null;

const log = (level: "debug" | "error" | "info" | "warn", payload: LogPayload) => {
  const data = prepareData(payload);
  const { msg, ...rest } = data;

  const message = String(msg);

  if (IS_PROD && axiomLogger) {
    axiomLogger[level](message, rest);
  } else {
    pinoLogger[level](rest, message);
  }
};

export const logger = {
  debug: (payload: LogPayload) => log("debug", payload),
  error: (payload: LogPayload) => log("error", payload),
  flush: async () => {
    if (IS_PROD && axiomLogger) {
      await axiomLogger.flush();
    }
  },
  info: (payload: LogPayload) => log("info", payload),

  warn: (payload: LogPayload) => log("warn", payload),
};

