import { Prisma } from "@prisma/client";
import { TRPCError } from "@trpc/server";

import { logger } from "../infrastructure/logger";

type ErrorMapping = {
  [key: string]: Record<string, string> | string | undefined;
  defaultConflict?: string;
  notFound?: string;
  notNull?: string;
  uniqueConstraint?: Record<string, string>;
};

type PrismaErrorMeta = {
  code: TRPCError["code"];
  defaultMessage: string;
  mapKey?: keyof ErrorMapping;
};

const prismaErrorMap: Record<string, PrismaErrorMeta | undefined> = {
  P2000: {
    code: "BAD_REQUEST",
    defaultMessage: "Field value too long for database",
    mapKey: "custom",
  },
  P2002: {
    code: "CONFLICT",
    defaultMessage: "Record with this data already exists",
    mapKey: "uniqueConstraint",
  },
  P2003: {
    code: "BAD_REQUEST",
    defaultMessage: "Related record not found (invalid ID)",
    mapKey: "custom",
  },
  P2004: {
    code: "FORBIDDEN",
    defaultMessage: "Access denied by security policy",
    mapKey: "custom",
  },
  P2006: {
    code: "CONFLICT",
    defaultMessage: "Data was modified by another user",
    mapKey: "custom",
  },
  P2007: {
    code: "BAD_REQUEST",
    defaultMessage: "Required field is missing",
    mapKey: "notNull",
  },
  P2010: { code: "NOT_FOUND", defaultMessage: "Record not found", mapKey: "notFound" },
  P2016: { code: "NOT_FOUND", defaultMessage: "Record not found", mapKey: "notFound" },
  P2025: { code: "NOT_FOUND", defaultMessage: "Record not found", mapKey: "notFound" },
  P2030: {
    code: "BAD_REQUEST",
    defaultMessage: "Foreign key constraint failed",
    mapKey: "custom",
  },
  P2034: { code: "BAD_REQUEST", defaultMessage: "Data constraint error", mapKey: "custom" },
};

export function handlePrismaError(error: unknown, map?: ErrorMapping): never {
  if (error instanceof TRPCError) throw error;

  if (error instanceof Prisma.PrismaClientKnownRequestError) {
    const meta = prismaErrorMap[error.code];

    if (meta == null) {
      logger.error({ error, msg: "Unhandled Prisma Error Code:" + error.code });
      throw new TRPCError({ code: "INTERNAL_SERVER_ERROR", message: "Database error" });
    }

    let message: string = meta.defaultMessage;

    if (meta.mapKey != null) {
      const mapValue = map?.[meta.mapKey];

      if (meta.mapKey === "uniqueConstraint") {
        const targetRaw = error.meta?.target;
        const target: string[] = Array.isArray(targetRaw)
          ? (targetRaw as string[])
          : typeof targetRaw === "string"
            ? [targetRaw]
            : [];

        const field = target.find((f): f is string => map?.uniqueConstraint?.[f] != null);

        if (field != null && map?.uniqueConstraint?.[field] != null) {
          message = map.uniqueConstraint[field];
        } else if (map?.defaultConflict != null) {
          message = map.defaultConflict;
        }
      } else if (typeof mapValue === "string" && mapValue.length > 0) {
        message = mapValue;
      }
    }

    throw new TRPCError({ code: meta.code, message });
  }

  logger.error({ error, msg: "Unknown Prisma Error:" });
  throw new TRPCError({
    code: "INTERNAL_SERVER_ERROR",
    message: "Internal database error",
  });
}

type OctokitError = {
  message: string;
  status: number;
};

export function isOctokitError(error: unknown): error is OctokitError {
  return (
    typeof error === "object" &&
    error != null &&
    "status" in error &&
    typeof (error as Record<string, unknown>).status === "number" &&
    "message" in error &&
    typeof (error as Record<string, unknown>).message === "string"
  );
}

import "server-only";

import * as languages from "linguist-languages";

const DEFAULT_LANGUAGE_COLOR = "#cccccc";

type LinguistInfo = {
  readonly color?: string;
  readonly extensions?: readonly string[];
};

const languageByExtension = new Map<string, { color: null | string; name: string }>();

const languageData = languages as Record<string, LinguistInfo | undefined>;

for (const [name, info] of Object.entries(languages as Record<string, any>)) {
  for (const ext of info.extensions ?? []) {
    const normalized = ext.toLowerCase();
    if (!languageByExtension.has(normalized)) {
      languageByExtension.set(normalized, {
        color: info.color ?? null,
        name,
      });
    }
  }
}

const knownLanguageExtensions = Array.from(
  new Set(Object.values(languageData).flatMap((language) => language?.extensions ?? []))
);

function normalizeExtension(value: string) {
  return value.startsWith(".") ? value.toLowerCase() : `.${value.toLowerCase()}`;
}

function findLanguageByExtension(extension: string) {
  const normalizedExtension = normalizeExtension(extension);
  const entry = Object.entries(languageData).find(
    ([, info]) => info?.extensions?.includes(normalizedExtension) ?? false
  );

  if (entry == null) return null;

  return {
    color: entry[1]?.color ?? null,
    name: entry[0],
  };
}

export function getKnownLanguageExtensions() {
  return [...knownLanguageExtensions];
}

export function getLanguageColor(languageOrExtension: null | string): string {
  if (languageOrExtension == null || languageOrExtension === "") {
    return DEFAULT_LANGUAGE_COLOR;
  }

  const directMatch = languageData[languageOrExtension];
  if (directMatch?.color != null) {
    return directMatch.color;
  }

  return findLanguageByExtension(languageOrExtension)?.color ?? DEFAULT_LANGUAGE_COLOR;
}

export function normalizeLanguageName(extension: string): string {
  return findLanguageByExtension(extension)?.name ?? extension.toUpperCase();
}

import rehypeShiki from "@shikijs/rehype";
import rehypeAutolinkHeadings from "rehype-autolink-headings";
import rehypeExternalLinks from "rehype-external-links";
import rehypeKatex from "rehype-katex";
import rehypeSanitize, { defaultSchema } from "rehype-sanitize";
import rehypeSlug from "rehype-slug";
import rehypeStringify from "rehype-stringify";
import remarkBreaks from "remark-breaks";
import remarkEmoji from "remark-emoji";
import remarkGfm from "remark-gfm";
import remarkMath from "remark-math";
import remarkParse from "remark-parse";
import remarkRehype from "remark-rehype";
import remarkToc from "remark-toc";
import { unified } from "unified";

import { getHighlighter } from "@/shared/lib/shiki";

export async function markdownToHtml(content: string) {
  if (content === "") return "";
  const highlight = await getHighlighter();

  const result = await unified()
    .use(remarkParse)
    .use(remarkGfm)
    .use(remarkEmoji)
    .use(remarkBreaks)
    .use(remarkMath)
    .use(remarkToc, { heading: "содержание|table of contents|оглавление", tight: true })

    .use(remarkRehype, { allowDangerousHtml: true })

    .use(rehypeSanitize, {
      ...defaultSchema,
      attributes: {
        ...defaultSchema.attributes,
        "*": ["className", "style", "id", "ariaHidden"],
      },
      clobberPrefix: "",
      tagNames: [
        ...(defaultSchema.tagNames ?? []),
        "span",
        "div",
        "code",
        "pre",
        "math",
        "mi",
        "mn",
        "mo",
        "ms",
        "mspace",
        "mtext",
      ],
    })

    .use(rehypeKatex)
    .use(rehypeSlug)
    .use(rehypeAutolinkHeadings, {
      behavior: "append",
      content: {
        children: [{ type: "text", value: "#" }],
        properties: { className: ["hover-link", "ml-2", "opacity-30", "text-sm", "select-none"] },
        tagName: "span",
        type: "element",
      },
    })
    .use(rehypeExternalLinks, {
      rel: ["nofollow", "noopener", "noreferrer"],
      target: "_blank",
    })

    .use(rehypeShiki, {
      highlighter: highlight,
      themes: { dark: "github-dark-dimmed", light: "github-light" },
    })

    .use(rehypeStringify)
    .process(content);

  return String(result.value);
}

/**
 * Calculate percentile value from an array of numbers.
 *
 * @param values - Array of numbers
 * @param ratio - Percentile ratio (0-1, e.g. 0.5 for median, 0.95 for p95)
 * @returns The percentile value, or 0 for empty arrays
 */
export function percentile(values: number[], ratio: number): number {
  if (values.length === 0) return 0;

  const sorted = [...values].sort((a, b) => a - b);
  const index = Math.floor((sorted.length - 1) * ratio);

  const safeIndex = Math.max(0, Math.min(index, sorted.length - 1));

  return sorted[safeIndex] ?? 0;
}

/* eslint-disable sonarjs/slow-regex */
