import strip from "strip-comments";

type AiTextLike = {
  content?: unknown;
  output?: unknown;
  text?: unknown;
};

function isAiTextLike(v: unknown): v is AiTextLike {
  if (!(v instanceof Object) || Array.isArray(v)) return false;

  if (v instanceof Date || v instanceof RegExp) return false;

  const obj = v as Record<string, unknown>;
  return obj.text != null || obj.content != null || obj.output != null;
}

const REMOVED_MSG = "/* ...content truncated... */";

export const CodeOptimizer = {
  basicClean(code: string): string {
    return code
      .replaceAll(/^\s*[\n\r]/gm, "")
      .replaceAll(/[\t ]+$/gm, "")
      .trim();
  },

  optimize(code: string, fileName: string): string {
    let processed = strip(code, { preserveNewlines: false });

    processed = processed.replaceAll(
      /([\w%+.-]+@[\w.-]+\.[A-Za-z]{2,})|((?<!\d)(?:(?:25[0-5]|2[0-4]\d|[01]?\d\d?)\.){3}(?:25[0-5]|2[0-4]\d|[01]?\d\d?)(?!\d))|(eyJ[\w-]*\.[\w-]*\.[\w-]*)/g,
      (match, email, ip, jwt) => {
        if (email) return "<REDACTED_EMAIL>";
        if (ip) return "<REDACTED_IP>";
        if (jwt) return "<REDACTED_JWT>";
        return match;
      }
    );

    return processed.replaceAll(/^\s*[\n\r]/gm, "").trim();
  },

  redactSecrets(code: string): string {
    return code
      .replaceAll(/[\w%+.-]+@[\w.-]+\.[A-Za-z]{2,}/g, "<REDACTED_EMAIL>")
      .replaceAll(
        /(?<!\d)(?:(?:25[0-5]|2[0-4]\d|[01]?\d\d?)\.){3}(?:25[0-5]|2[0-4]\d|[01]?\d\d?)(?!\d)/g,
        "<REDACTED_IP>"
      )
      .replaceAll(/(["'])eyJ(?:[\w-]*\.){2}[\w-]*(["'])/g, "$1<REDACTED_JWT>$2");
  },

  removeLicenseHeaders(code: string): string {
    return code.replace(/^\s*\/\*[\S\s]*?(?:license|copyright)[\S\s]*?\*\//i, "");
  },

  truncateLargeDataStructures(code: string): string {
    return code.replaceAll(/\[\s*([\d\s,.-]{500,})\s*]/g, `[ /* large data array truncated */ ]`);
  },

  truncateLargeLiterals(code: string): string {
    let newCode = code.replaceAll(/(d\s*=\s*["'])([^"']{150,})(["'])/g, `$1${REMOVED_MSG}$3`);

    newCode = newCode.replaceAll(
      /(["']data:[^;]+;base64,)([^"']{50,})(["'])/g,
      `$1${REMOVED_MSG}$3`
    );

    return newCode;
  },
};

export function cleanCodeForAi(code: string, fileName: string = "unknown"): string {
  return CodeOptimizer.optimize(code, fileName);
}

export function unwrapAiText(value: unknown): string {
  if (value == null) return "";
  if (typeof value === "string") return value;
  if (isAiTextLike(value)) {
    const candidate = value.text ?? value.content ?? value.output;
    return typeof candidate === "string" ? candidate : JSON.stringify(value);
  }
  if (typeof value === "object" && !Array.isArray(value)) {
    return JSON.stringify(value);
  }
  if (Array.isArray(value)) return value.join("\n");
  return String(value);
}

export function skeletonizeCode(code: string): string {
  return code
    .replaceAll(/({[\S\s]*?})/gm, (match) => {
      if (match.length > 100) {
        return "{ /* ... implementation hidden to ... */ }";
      }
      return match;
    })
    .slice(0, 5000);
}

import { z } from "zod";

export const PaginationMetaSchema = z.object({
  currentPage: z.number().int().min(1),
  filteredCount: z.number().int().min(0),
  nextCursor: z.number().int().optional(),
  pageSize: z.number().int().positive(),
  searchQuery: z.string().optional(),
  totalCount: z.number().int().min(0),
  totalPages: z.number().int().min(1),
});

export function getPaginationMeta(params: {
  filteredCount: number;
  limit: number;
  page: number;
  search?: string;
  totalCount: number;
}) {
  if (!Number.isInteger(params.limit) || params.limit <= 0) {
    throw new Error("Pagination limit must be a positive integer");
  }
  if (!Number.isInteger(params.page) || params.page <= 0) {
    throw new Error("Pagination page must be a positive integer");
  }

  const totalPages = Math.max(1, Math.ceil(params.filteredCount / params.limit));

  return {
    currentPage: params.page,
    filteredCount: params.filteredCount,
    nextCursor: params.page < totalPages ? params.page + 1 : undefined,
    pageSize: params.limit,
    searchQuery: params.search,
    totalCount: params.totalCount,
    totalPages,
  };
}

export type PaginationMeta = ReturnType<typeof getPaginationMeta>;

import { compact, uniq } from "es-toolkit";
import { basename, extname } from "pathe";

import { normalizeRepoPath } from "../engine/core/common";

/**
 * Extract file extension from path (lowercase, with leading dot).
 */
export function getFileExtension(filePath: string): string {
  return extname(normalizeRepoPath(filePath));
}

/**
 * Extract file name from path (basename).
 */
export function getFileName(filePath: string): string {
  return basename(normalizeRepoPath(filePath));
}

/**
 * Unique normalized paths with limit.
 */
export function uniqueNormalizedPaths(paths: Iterable<string>, limit?: number): string[] {
  const list = uniq(compact(Array.from(paths).map((path) => normalizeRepoPath(path))));

  return limit != null ? list.slice(0, limit) : list;
}

/**
 * Unique object paths.
 */
export function uniqueObjectPaths<T extends { path: string }>(
  items: Iterable<T>,
  limit?: number
): string[] {
  const paths = Array.from(items).map((i) => i.path);
  return uniqueNormalizedPaths(paths, limit);
}

/**
 * Unique string paths from mixed.
 */
export function uniqueStringPaths(
  paths: Iterable<false | null | string | undefined>,
  limit?: number
): string[] {
  const cleanPaths = compact(Array.from(paths)) as string[];
  return uniqueNormalizedPaths(cleanPaths, limit);
}

/**
 * Exclude path from list.
 */
export function excludePath(
  paths: Iterable<string>,
  excludedPath: string,
  limit?: number
): string[] {
  const normalizedExcluded = normalizeRepoPath(excludedPath);

  const filtered = Array.from(paths).filter((p) => normalizeRepoPath(p) !== normalizedExcluded);

  return uniqueNormalizedPaths(filtered, limit);
}

/**
 * PromptBuilder
 * Fluent API for constructing system and user prompts with consistent structure.
 */

import { escapePromptXmlAttr, escapePromptXmlText } from "./string-utils";

export type PromptRole =
  | "api-documentarian"
  | "architect"
  | "architecture-writer"
  | "changelog-writer"
  | "code-analyzer"
  | "code-documenter"
  | "code-reviewer"
  | "contributing-writer"
  | "generic"
  | "readme-writer"
  | "security-sentinel";

export interface PromptSection {
  content: string;
  title: string;
}

/**
 * FluentPromptBuilder for consistent prompt construction
 * Supports method chaining for readability
 */
export class PromptBuilder {
  private sections: Map<string, string> = new Map();
  private role: PromptRole = "generic";
  private language: string = "English";

  constructor(role: PromptRole = "generic") {
    this.role = role;
  }

  /**
   * Set the target language for output
   */
  setLanguage(lang: string): this {
    this.language = lang;
    return this;
  }

  /**
   * Add role/persona section
   */
  withRole(description: string): this {
    this.sections.set("role", `# ROLE\n${description}`);
    return this;
  }

  /**
   * Add constraints/rules section
   */
  withConstraints(...rules: (string | undefined)[]): this {
    const filtered = rules.filter(Boolean);
    if (filtered.length > 0) {
      const content = filtered.map((r, i) => `${i + 1}. ${r}`).join("\n");
      this.sections.set("constraints", `# CONSTRAINTS\n${content}`);
    }
    return this;
  }

  /**
   * Add grounding rules section
   */
  withGrounding(...rules: (string | undefined)[]): this {
    const filtered = rules.filter(Boolean);
    if (filtered.length > 0) {
      const content = filtered.map((r) => `- ${r}`).join("\n");
      this.sections.set("grounding", `# GROUNDING\n${content}`);
    }
    return this;
  }

  /**
   * Add task description section
   */
  withTask(description: string): this {
    this.sections.set("task", `# TASK\n${description}`);
    return this;
  }

  /**
   * Add strategy/thinking protocol section
   */
  withStrategy(...steps: (string | undefined)[]): this {
    const filtered = steps.filter(Boolean);
    if (filtered.length > 0) {
      const content = filtered.map((s, i) => `${i + 1}. ${s}`).join("\n");
      this.sections.set("strategy", `# STRATEGY\n${content}`);
    }
    return this;
  }

  /**
   * Add output format section
   */
  withOutputFormat(format: string | { content: string; title: string }): this {
    if (typeof format === "string") {
      this.sections.set("output", `# OUTPUT\n${format}`);
    } else {
      this.sections.set("output", `# ${format.title}\n${format.content}`);
    }
    return this;
  }

  /**
   * Add JSON schema output specification
   */
  withJsonSchema(schema: Record<string, unknown>): this {
    this.sections.set(
      "output",
      `# OUTPUT_SCHEMA\nReturn ONLY a valid JSON object matching this structure:\n\`\`\`json\n${JSON.stringify(schema, null, 2)}\n\`\`\``
    );
    return this;
  }

  /**
   * Add custom section
   */
  addSection(title: string, content: string): this {
    this.sections.set(title.toLowerCase(), `# ${title.toUpperCase()}\n${content}`);
    return this;
  }

  /**
   * Set language awareness in output
   */
  withLanguageNotice(): this {
    if (this.language && this.language !== "English") {
      const notice = `\n## LANGUAGE\nOutput ALL text in **${this.language}**.`;
      const existing = Array.from(this.sections.values()).join("\n");
      this.sections.clear();
      this.sections.set("_combined", existing + notice);
    }
    return this;
  }

  /**
   * Build the final system prompt
   */
  buildSystem(): string {
    const sections: string[] = [];

    // Order matters: role → constraints → grounding → task → strategy → output
    const order = ["role", "constraints", "grounding", "task", "strategy", "output"];

    for (const key of order) {
      const section = this.sections.get(key);
      if (section != null) {
        sections.push(section);
      }
    }

    // Add any custom sections not in the standard order
    for (const [key, section] of this.sections.entries()) {
      if (!order.includes(key)) {
        sections.push(section);
      }
    }

    return sections.join("\n\n");
  }

  /**
   * Build individual sections (useful for debugging or testing)
   */
  getSections(): Map<string, string> {
    return new Map(this.sections);
  }

  /**
   * Clear all sections
   */
  reset(): this {
    this.sections.clear();
    return this;
  }
}

/**
 * UserPromptBuilder for constructing user prompts with structured data
 * Handles XML wrapping, escaping, and multi-part inputs
 */
export class UserPromptBuilder {
  private parts: Array<{ content: string; escape: boolean; tag?: string }> = [];

  /**
   * Add raw text (no escaping, no wrapping)
   */
  addRaw(text: string): this {
    this.parts.push({ content: text, escape: false });
    return this;
  }

  /**
   * Add XML-wrapped content (auto-escaped)
   */
  addXmlSection(tag: string, content: string, attributes?: Record<string, string>): this {
    const attrs =
      attributes && Object.keys(attributes).length > 0
        ? " " +
          Object.entries(attributes)
            .map(([k, v]) => `${k}="${escapePromptXmlAttr(v)}"`)
            .join(" ")
        : "";
    const escaped = escapePromptXmlText(content);
    this.parts.push({
      content: `<${tag}${attrs}>\n${escaped}\n</${tag}>`,
      escape: false,
      tag,
    });
    return this;
  }

  /**
   * Add JSON block (auto-escaped if needed)
   */
  addJsonBlock(data: object, tag = "data"): this {
    const json = JSON.stringify(data, null, 2);
    return this.addXmlSection(tag, json);
  }

  /**
   * Add heading
   */
  addHeading(level: 1 | 2 | 3 | 4, text: string): this {
    const hash = "#".repeat(level);
    return this.addRaw(`\n${hash} ${text}\n`);
  }

  /**
   * Add list items
   */
  addList(items: string[], ordered = false): this {
    const listItems = items
      .map((item, i) => (ordered ? `${i + 1}. ${item}` : `- ${item}`))
      .join("\n");
    return this.addRaw(listItems);
  }

  /**
   * Build final user prompt
   */
  build(): string {
    return this.parts.map((p) => p.content).join("\n");
  }

  /**
   * Reset builder
   */
  reset(): this {
    this.parts = [];
    return this;
  }
}

