/**
 * PromptRegistry
 * Central registry for all system and user prompts in the application.
 * Provides versioning, metadata, and dynamic retrieval of prompts.
 */

import type { LLMTaskType } from "../engine/core/scoring-constants";

/**
 * Metadata about a registered prompt
 */
export interface PromptMetadata {
  /** Created date */
  createdAt: Date;

  /** Description of what this prompt does */
  description: string;

  /** Unique prompt identifier */
  id: string;

  /** Maximum recommended input size in bytes */
  maxContextSize?: number;

  /** Last modified date */
  modifiedAt: Date;

  /** Human-readable name */
  name: string;

  /** Output format expected from LLM */
  outputFormat: "json" | "markdown" | "text" | "xml";

  /** Whether this prompt requires evidence/context input */
  requiresContext: boolean;

  /** Role/persona for this prompt */
  role: string;

  /** Tags for categorization */
  tags: string[];

  /** Type of task this prompt is used for LLM temperature strategy */
  taskType: LLMTaskType;

  /** Whether this is a system or user prompt */
  type: "both" | "system" | "user";

  /** Current version (for tracking updates) */
  version: string;
}

/**
 * Represents a registered prompt plus its builder function
 */
interface RegisteredPrompt {
  builderFn: (params: Record<string, unknown>) => string;
  metadata: PromptMetadata;
}

export const PROMPT_IDS = {
  API_DOC: "api-documentarian",
  ARCHITECT: "architect",
  README: "readme-writer",
  SENTINEL: "security-sentinel",
} as const;

type PromptId = (typeof PROMPT_IDS)[keyof typeof PROMPT_IDS];

/**
 * PromptRegistry: Central management of all prompts
 */
export class PromptRegistry {
  private prompts: Map<string, RegisteredPrompt> = new Map();
  private aliases: Map<string, string> = new Map(); // For backward compatibility

  /**
   * Register a new prompt
   */
  register(metadata: PromptMetadata, builderFn: (params: Record<string, unknown>) => string): this {
    if (this.prompts.has(metadata.id)) {
      throw new Error(`Prompt with ID "${metadata.id}" is already registered`);
    }

    this.prompts.set(metadata.id, { builderFn, metadata });
    return this;
  }

  /**
   * Create an alias for backward compatibility
   */
  alias(oldName: string, newPromptId: string): this {
    if (!this.prompts.has(newPromptId)) {
      throw new Error(`Target prompt "${newPromptId}" not found`);
    }
    this.aliases.set(oldName, newPromptId);
    return this;
  }

  /**
   * Get prompt metadata by ID
   */
  getMetadata(promptId: string): null | PromptMetadata {
    const resolved = this.aliases.get(promptId) ?? promptId;
    const prompt = this.prompts.get(resolved);
    return prompt?.metadata ?? null;
  }

  /**
   * Get all registered prompts
   */
  getAllMetadata(): PromptMetadata[] {
    return Array.from(this.prompts.values()).map((p) => p.metadata);
  }

  /**
   * Get all prompts by task type
   */
  getByTaskType(taskType: LLMTaskType): PromptMetadata[] {
    return Array.from(this.prompts.values())
      .filter((p) => p.metadata.taskType === taskType)
      .map((p) => p.metadata);
  }

  /**
   * Get all prompts by role
   */
  getByRole(role: string): PromptMetadata[] {
    return Array.from(this.prompts.values())
      .filter((p) => p.metadata.role === role)
      .map((p) => p.metadata);
  }

  /**
   * Build a prompt by ID with given parameters
   */
  build(promptId: PromptId, params: Record<string, unknown> = {}): string {
    const resolved = this.aliases.get(promptId) ?? promptId;
    const prompt = this.prompts.get(resolved);

    if (!prompt) {
      throw new Error(`Prompt "${promptId}" not found in registry`);
    }

    return prompt.builderFn(params);
  }

  /**
   * Check if a prompt is registered
   */
  has(promptId: string): boolean {
    const resolved = this.aliases.get(promptId) ?? promptId;
    return this.prompts.has(resolved);
  }

  /**
   * Get stats about registered prompts
   */
  getStats(): {
    byOutputFormat: Record<string, number>;
    byRole: Set<string>;
    byTaskType: Record<LLMTaskType, number>;
    totalPrompts: number;
  } {
    const stats = {
      byOutputFormat: {} as Record<string, number>,
      byRole: new Set<string>(),
      byTaskType: {} as Record<LLMTaskType, number>,
      totalPrompts: this.prompts.size,
    };

    for (const prompt of this.prompts.values()) {
      const { outputFormat, role, taskType } = prompt.metadata;

      stats.byTaskType[taskType] = stats.byTaskType[taskType] + 1;
      stats.byOutputFormat[outputFormat] = (stats.byOutputFormat[outputFormat] ?? 0) + 1;
      stats.byRole.add(role);
    }

    return stats;
  }

  /**
   * Export registry as JSON for documentation
   */
  exportAsJson(): object {
    const data: Record<string, unknown> = {};

    for (const [id, prompt] of this.prompts.entries()) {
      data[id] = {
        metadata: {
          ...prompt.metadata,
          createdAt: prompt.metadata.createdAt.toISOString(),
          modifiedAt: prompt.metadata.modifiedAt.toISOString(),
        },
      };
    }

    return data;
  }

  /**
   * Clear all registered prompts (for testing)
   */
  clear(): void {
    this.prompts.clear();
    this.aliases.clear();
  }
}

/**
 * Global prompt registry singleton
 */
let globalRegistry: null | PromptRegistry = null;

/**
 * Get or create global prompt registry
 */
export function getGlobalPromptRegistry(): PromptRegistry {
  if (!globalRegistry) {
    globalRegistry = new PromptRegistry();
  }
  return globalRegistry;
}

/**
 * Reset global registry (for testing)
 */
export function resetGlobalPromptRegistry(): void {
  globalRegistry = null;
}

/**
 * Helper to create prompt metadata
 */
export function createPromptMetadata(overrides: Partial<PromptMetadata>): PromptMetadata {
  const now = new Date();
  return {
    createdAt: now,
    description: "No description provided",
    id: "unknown",
    modifiedAt: now,
    name: "Unknown Prompt",
    outputFormat: "text",
    requiresContext: false,
    role: "generic",
    tags: [],
    taskType: "default",
    type: "system",
    version: "1.0.0",
    ...overrides,
  };
}

/**
 * PromptRuleLibrary
 * Centralized collection of reusable instruction rules and constraints.
 * Eliminates repetition across all LLM prompts in the system.
 */

// =============================================================================
// GROUNDING & DATA VALIDATION RULES
// =============================================================================

export const GroundingRules = {
  /** Rule: Treat supplied data as authoritative */
  authoritative: (dataType: string = "metrics") =>
    `Treat the supplied \`${dataType}\` as authoritative. Do not contradict or override it with inferences.`,

  /** Rule: Cite only from canonical sources */
  citeOnlyCanonical: (sourceType: "entrypoints" | "file paths" | "metrics" = "file paths") =>
    `Cite only from supplied ${sourceType} or evidence. Never invent new ${sourceType}.`,

  /** Rule: Handle missing data gracefully */
  missingDataHandler: `If evidence is missing or contradictory, write "unknown" or "not enough evidence" instead of guessing.`,

  /** Rule: Never invent or fabricate information */
  noInvention: `Never invent, fabricate, or guess. If information is missing or unclear, mark it as "unknown".`,

  /** Rule: Only use supplied evidence */
  onlySuppliedEvidence: `Use only the supplied evidence and code snippets. Do not assume or infer beyond what is explicitly provided.`,

  /** Rule: Mark uncertain paths */
  pathValidation: (source: string = "allowed_repository_paths") =>
    `When mentioning files or directories, use only paths from \`${source}\`. Never invent or assume paths.`,
};

// =============================================================================
// OUTPUT FORMAT RULES
// =============================================================================

export const OutputFormatRules = {
  /** Rule: JSON-only output */
  jsonOnly: `Return ONLY a valid JSON object. No markdown formatting, no explanation.`,

  /** Rule: Markdown-only output */
  markdownOnly: `Return ONLY raw Markdown. No JSON, no code blocks, no explanation.`,

  /** Rule: No modifications to code */
  noCodeModification: `DO NOT modify the code logic. Only modify documentation. Return the complete file with no omissions.`,

  /** Rule: Structured schema compliance */
  schemaCompliance: (schemaName: string) =>
    `Return ONLY a valid JSON object matching the \`${schemaName}\` schema exactly.`,

  /** Rule: Strict XML structure */
  xmlStructure: (rootTag: string) =>
    `Wrap the output in valid XML tags: <${rootTag}>...</${rootTag}>. Escape all special characters.`,
};

// =============================================================================
// LANGUAGE & TONE RULES
// =============================================================================

export const LanguageRules = {
  /** Rule: Conciseness */
  conciseness: (maxPoints?: number) =>
    `Be concise. ${maxPoints != null ? `Focus on the most important ${maxPoints} points.` : "Avoid unnecessary details."}`,

  /** Rule: Evidence-first approach */
  evidenceFirst: `Prefer explicit evidence over intuition. If a claim cannot be proven from input, omit it or mark it as "unknown".`,

  /** Rule: Target-specific language */
  targetLanguage: (language: string = "English") =>
    `Output ALL text in **${language}**. This is non-negotiable.`,

  /** Rule: Technical tone */
  technicalTone: `Tone: Technical, concise, professional. Avoid marketing language or vague abstractions.`,
};

// =============================================================================
// BEHAVIORAL RULES
// =============================================================================

export const BehavioralRules = {
  /** Rule: Framework-aware output */
  frameworkAware: (frameworks: string[] = []) =>
    frameworks.length > 0
      ? `Adapt output for the following frameworks: ${frameworks.join(", ")}.`
      : `Infer the target framework from evidence and adapt output accordingly.`,

  /** Rule: Merge duplicates */
  mergeDuplicates: `Merge duplicate observations rather than repeating them across sections.`,

  /** Rule: No hallucination */
  noHallucination: `Never hallucinate behavior, commands, environment variables, or configuration that is not explicitly supported by the input.`,

  /** Rule: No hidden assumptions */
  noHiddenAssumptions: `Do not invent business goals, stack trade-offs, environment variables, or commands that are not supported by the input.`,

  /** Rule: Primary artifact handling */
  primaryArtifact: `This is a **primary artifact**. Prefer precise reference over broad prose. It will be delivered to users as the source of truth.`,

  /** Rule: Secondary artifact handling */
  secondaryArtifact: `This is a **secondary compatibility document**. Keep it useful, but do not behave as if it is the core product artifact.`,
};

// =============================================================================
// VERIFICATION RULES
// =============================================================================

export const VerificationRules = {
  /** Rule: Categorical clarity */
  categoricalClarity: `If evidence is weak, state so directly instead of smoothing it over with abstract language.`,

  /** Rule: Confidence-based wording */
  confidenceWording: `Use confidence-friendly wording when evidence is partial. Distinguish between "known facts", "inferred", and "unknown".`,

  /** Rule: No contradiction of metrics */
  noMetricsContradiction: `Do not contradict or override supplied metrics with inferences.`,

  /** Rule: Verify against supplied evidence */
  verifyAgainstEvidence: `Verify claims against the supplied facts before including them in the output.`,
};

// =============================================================================
// HELPER FUNCTIONS
// =============================================================================

/**
 * Combine multiple rules into a formatted section
 * Useful for building composite rule sets
 */
export function combineRules(rules: (string | undefined)[]): string {
  return rules.filter(Boolean).join("\n");
}

/**
 * Build a "do not invent" section for a specific context
 */
export function buildNoInventionSection(context: string = "information"): string {
  return `
## GROUNDING (HARD)
- **${context}**: ${GroundingRules.noInvention}
- ${GroundingRules.onlySuppliedEvidence}
- ${GroundingRules.missingDataHandler}
`;
}

/**
 * Build safety constraints section
 */
export function buildSafetyConstraints(): string {
  return `
## CONSTRAINTS
- ${BehavioralRules.noHallucination}
- ${BehavioralRules.noHiddenAssumptions}
- ${VerificationRules.verifyAgainstEvidence}
`;
}

/**
 * Build format section
 */
export function buildFormatSection(format: "json" | "markdown" | "xml"): string {
  const rule =
    format === "json"
      ? OutputFormatRules.jsonOnly
      : format === "markdown"
        ? OutputFormatRules.markdownOnly
        : OutputFormatRules.xmlStructure("output");

  return `## OUTPUT\n${rule}`;
}

import { AsyncLocalStorage } from "node:async_hooks";
import type { NextRequest } from "next/server";

import { IS_PROD } from "@/shared/constants/env.flags";

export interface RequestStore {
  ip: string;
  method: string;
  origin?: string;

  path: string;
  referer?: string;
  requestId: string;
  userAgent: string;

  userId?: number;
  userRole?: string;

  // appVersion?: string;
}

export const requestContext = new AsyncLocalStorage<RequestStore>();

export function anonymizeIp(ip: null | string | undefined): string {
  if (ip == null || ip === "unknown" || ip === "127.0.0.1" || ip === "::1") return ip ?? "unknown";

  if (ip.includes(".")) {
    const parts = ip.split(".");
    if (parts.length === 4) return `${parts[0]}.${parts[1]}.${parts[2]}.0`;
  }

  if (ip.includes(":")) {
    const parts = ip.split(":");
    if (parts.length < 4) return "unknown";
    return `${parts.slice(0, 4).join(":")}::`;
  }

  return "unknown";
}

type VercelNextRequest = NextRequest & {
  geo?: {
    city?: string;
    country?: string;
    region?: string;
  };
  ip?: string;
};

export function getIp(request: NextRequest): string {
  return (
    (request as VercelNextRequest).ip ??
    request.headers.get("x-forwarded-for")?.split(",")[0] ??
    "127.0.0.1"
  );
}

export function getUa(request: NextRequest): string {
  return request.headers.get("user-agent") ?? "unknown";
}

export function getCountry(request: NextRequest): string {
  const geoCountry = (request as VercelNextRequest).geo?.country;
  if (geoCountry != null) return geoCountry;

  const vercelHeader = request.headers.get("x-vercel-ip-country");
  if (vercelHeader != null) return vercelHeader.toUpperCase();

  if (!IS_PROD) return "LOCAL";

  return "UNKNOWN";
}

type RequestContextInput = {
  method: string;
  path: string;
  req: NextRequest;
  requestId?: string;
  userId?: number;
  userRole?: string;
};

export function getRequestIdFromHeaders(request: NextRequest): string | undefined {
  return sanitizeRequestId(request.headers.get("x-request-id"));
}

export function generateRequestId(): string {
  if (typeof globalThis.crypto.randomUUID === "function") {
    return globalThis.crypto.randomUUID();
  }
  throw new Error("crypto.randomUUID is not available in this runtime");
}

export function sanitizeRequestId(value?: null | string): string | undefined {
  if (value == null) return undefined;
  const trimmed = value.trim();
  if (trimmed.length === 0 || trimmed.length > 64) return undefined;
  if (!/^[\w-]+$/.test(trimmed)) return undefined;
  return trimmed;
}

export function resolveRequestId(request?: NextRequest, existing?: string): string | undefined {
  if (existing != null) return sanitizeRequestId(existing);
  if (request == null) return undefined;
  return getRequestIdFromHeaders(request);
}

export function ensureRequestId(request: NextRequest, existing?: string): string {
  return sanitizeRequestId(existing) ?? getRequestIdFromHeaders(request) ?? generateRequestId();
}

export function buildRequestStore(input: RequestContextInput): RequestStore {
  const requestId = ensureRequestId(input.req, input.requestId);
  return {
    ip: anonymizeIp(getIp(input.req)),
    method: input.method,
    origin: input.req.headers.get("origin") ?? undefined,
    path: input.path,
    referer: input.req.headers.get("referer") ?? undefined,
    requestId,
    userAgent: getUa(input.req),
    userId: input.userId,
    userRole: input.userRole,
  };
}

/**
 * SafetyContext
 * Unified safety settings and data handling rules for LLM interactions.
 * Centralizes escaping, sanitization, and validation logic.
 */

import { logger } from "../infrastructure/logger";
import { escapePromptXmlAttr, escapePromptXmlText } from "./string-utils";

/**
 * Safety level for handling user input
 */
export type SafetyLevel = "moderate" | "permissive" | "strict";

/**
 * Data handling strategy
 */
export type DataHandlingStrategy = "escape-json" | "escape-xml" | "no-escape" | "sanitize-html";

/**
 * SafetyContext manages all data safety and escaping across LLM prompts
 */
export class SafetyContext {
  private level: SafetyLevel = "strict";
  private strategies: Map<string, DataHandlingStrategy> = new Map();

  constructor(level: SafetyLevel = "strict") {
    this.level = level;
    this.setupDefaultStrategies();
  }

  /**
   * Setup default escaping strategies per data type
   */
  private setupDefaultStrategies(): void {
    this.strategies.set("xml", "escape-xml");
    this.strategies.set("json", "escape-json");
    this.strategies.set("html", "sanitize-html");
    this.strategies.set("code", "no-escape");
  }

  /**
   * Set safety level
   */
  setSafetyLevel(level: SafetyLevel): this {
    this.level = level;
    return this;
  }

  /**
   * Register custom handling strategy for a data type
   */
  registerStrategy(dataType: string, strategy: DataHandlingStrategy): this {
    this.strategies.set(dataType, strategy);
    return this;
  }

  /**
   * Escape data based on context type
   */
  escape(data: string, context: "json" | "xml-attr" | "xml-text" = "xml-text"): string {
    if (this.level === "permissive") {
      return data;
    }

    switch (context) {
      case "xml-text": {
        return escapePromptXmlText(data);
      }
      case "xml-attr": {
        return escapePromptXmlAttr(data);
      }
      case "json": {
        return JSON.stringify(data);
      }
      default: {
        return data;
      }
    }
  }

  /**
   * Sanitize user input that will be embedded in prompts
   */
  sanitizeUserInput(input: string): string {
    if (this.level === "strict") {
      // Remove or reject potentially dangerous patterns
      const dangerous = [
        /prompt\s*injection/i,
        /system\s*prompt/i,
        /ignore.*instructions/i,
        /bypass/i,
        /jailbreak/i,
      ];

      for (const pattern of dangerous) {
        if (pattern.test(input)) {
          logger.warn({
            msg: "Potentially dangerous input pattern detected",
            pattern: pattern.toString(),
          });
          // eslint-disable-next-line @typescript-eslint/no-unnecessary-condition
          if (this.level === "strict") {
            throw new Error("Input contains potentially dangerous patterns");
          }
        }
      }
    }

    return this.escape(input, "xml-text");
  }

  /**
   * Prepare JSON for embedding in prompts
   */
  prepareJsonForPrompt(data: object, escape = true): string {
    const json = JSON.stringify(data, null, 2);
    return escape ? this.escape(json, "xml-text") : json;
  }

  /**
   * Prepare file content for embedding in prompts
   */
  prepareFileContent(
    filePath: string,
    content: string,
    maxLength = 50_000,
    escapeContext: "xml-attr" | "xml-text" = "xml-text"
  ): { content: string; path: string; truncated: boolean } {
    let truncated = false;
    let processedContent = content;

    if (content.length > maxLength) {
      processedContent = content.slice(0, maxLength) + "\n// [CONTENT TRUNCATED]";
      truncated = true;
    }

    return {
      content: this.escape(processedContent, escapeContext),
      path: this.escape(filePath, "xml-attr"),
      truncated,
    };
  }

  /**
   * Validate repository paths
   */
  validatePaths(
    paths: string[],
    allowedPaths?: Set<string>
  ): { invalid: string[]; valid: string[] } {
    if (!allowedPaths || allowedPaths.size === 0) {
      // If no restrictions, all paths are valid
      return { invalid: [], valid: paths };
    }

    const valid: string[] = [];
    const invalid: string[] = [];

    for (const path of paths) {
      if (allowedPaths.has(path)) {
        valid.push(path);
      } else {
        invalid.push(path);
      }
    }

    return { invalid, valid };
  }

  /**
   * Prepare allowed paths list for inclusion in prompts
   */
  prepareAllowedPaths(paths: string[]): string {
    const safe = paths.map((p) => this.escape(p, "xml-text"));
    return safe.join("\n");
  }

  /**
   * Create a safety-checked evidence block
   */
  createEvidenceBlock(
    tag: string,
    data: object,
    {
      allowedPaths,
      maxSize = 100_000,
      validatePaths = false,
    }: { allowedPaths?: Set<string>; maxSize?: number; validatePaths?: boolean } = {}
  ): { invalidPaths: string[]; truncated: boolean; xml: string } {
    const json = JSON.stringify(data, null, 2);
    let truncated = false;
    let content = json;
    let invalidPaths: string[] = [];

    // Check size
    if (content.length > maxSize) {
      content = content.slice(0, maxSize) + "\n// [DATA TRUNCATED]";
      truncated = true;
    }

    // Validate paths if requested
    if (validatePaths && "paths" in data && Array.isArray((data as { paths: unknown }).paths)) {
      const pathsData = (data as { paths: string[] }).paths;
      const validation = this.validatePaths(pathsData, allowedPaths);
      invalidPaths = validation.invalid;
    }

    const escaped = this.escape(content, "xml-text");
    return {
      invalidPaths,
      truncated,
      xml: `<${tag}>\n${escaped}\n</${tag}>`,
    };
  }

  /**
   * Get a safety report for an evidence block
   */
  generateSafetyReport(data: {
    maxDataSize?: number;
    pathsValidated?: number;
    userInputPresent?: boolean;
    xmlTags?: number;
  }): string {
    const report: string[] = [];
    if (data.xmlTags != null) report.push(`✓ XML tags properly escaped: ${data.xmlTags}`);
    if (data.maxDataSize != null)
      report.push(`✓ Max data size enforced: ${data.maxDataSize} bytes`);
    if (data.userInputPresent === true) report.push(`⚠ User input present (sanitized)`);
    if (data.pathsValidated != null) report.push(`✓ Paths validated: ${data.pathsValidated}`);
    return report.join("\n");
  }
}

/**
 * Global safety context singleton
 */
let globalSafetyContext: null | SafetyContext = null;

/**
 * Get or create global safety context
 */
export function getGlobalSafetyContext(level: SafetyLevel = "strict"): SafetyContext {
  if (!globalSafetyContext) {
    globalSafetyContext = new SafetyContext(level);
  }
  return globalSafetyContext;
}

/**
 * Reset global safety context (for testing)
 */
export function resetGlobalSafetyContext(): void {
  globalSafetyContext = null;
}

import "server-only";

import safeStringify from "fast-safe-stringify";

const SENSITIVE_KEYS = new Set([
  "access_token",
  "apikey",
  "authorization",
  "clientsecret",
  "cookie",
  "creditcard",
  "cvv",
  "gh_token",
  "hash",
  "hashedkey",
  "iban",
  "id_token",
  "identifier",
  "imagekey",
  "newpassword",
  "password",
  "passwordhash",
  "proxy-authorization",
  "refresh_token",
  "salt",
  "secret",
  "session_state",
  "sessiontoken",
  "set-cookie",
  "state",
  "token",
  "verificationtoken",
  "x-github-token",
]);

const GITHUB_TOKEN_REGEX = /(github_pat_\w+|gh[oprsu]_\w{36,})/g;
const BEARER_TOKEN_REGEX = /(\bbearer\s+)[^\s,;]+/gi;

function redactValue(key: string, value: unknown): unknown {
  const lowerKey = key.toLowerCase();
  const normalizedKey = lowerKey.replaceAll(/[_-]/g, "");

  if (SENSITIVE_KEYS.has(lowerKey) || SENSITIVE_KEYS.has(normalizedKey)) {
    return "[REDACTED]";
  }

  if (typeof value === "bigint") {
    return value.toString();
  }

  if (typeof value === "string") {
    let safeString = value;
    if (safeString.includes("gh") || safeString.includes("github_pat_")) {
      safeString = safeString.replaceAll(GITHUB_TOKEN_REGEX, "[REDACTED_GH_TOKEN]");
    }
    if (/bearer\s+/i.test(safeString)) {
      safeString = safeString.replaceAll(BEARER_TOKEN_REGEX, "$1[REDACTED]");
    }
    return safeString;
  }

  return value;
}

export function sanitizePayload(obj: unknown): unknown {
  if (typeof obj === "string") return redactValue("", obj);
  if (typeof obj === "bigint") return obj.toString();
  if (obj == null || typeof obj !== "object") return obj;

  try {
    return JSON.parse(safeStringify(obj, redactValue));
  } catch (error) {
    return {
      _sanitization_error: true,
      error_name: error instanceof Error ? error.name : "UnknownError",
      reason: "Sanitization failed",
      type_was: typeof obj,
    };
  }
}

const SEARCH_TOKEN_PATTERN = /[\p{L}\p{N}\p{M}]+/gu;
const MAX_SEARCH_TERMS = 8;
const MIN_SEARCH_TERM_LENGTH = 2;

export function normalizeSearchInput(search?: string): string | undefined {
  const normalized = search?.trim().normalize("NFC").toLowerCase();
  return normalized != null && normalized.length > 0 ? normalized : undefined;
}

export function tokenizeSearchInput(search?: string): string[] {
  const normalizedSearch = normalizeSearchInput(search);
  if (normalizedSearch == null) return [];

  const matches = normalizedSearch.match(SEARCH_TOKEN_PATTERN) ?? [];
  const uniqueTerms = new Set<string>();

  for (const match of matches) {
    if (match.length < MIN_SEARCH_TERM_LENGTH) continue;

    uniqueTerms.add(match);
    if (uniqueTerms.size >= MAX_SEARCH_TERMS) break;
  }

  return [...uniqueTerms];
}

import { compact, escape, uniq } from "es-toolkit";
import { basename, extname, normalize } from "pathe";

import { normalizeRepoPath } from "../engine/core/common";

/**
 * Type-safe guard for non-empty strings.
 */
export const hasText = (value: unknown): value is string =>
  typeof value === "string" && value.trim().length > 0;

/**
 * Check if empty/whitespace.
 */
export const isEmpty = (value: unknown): value is string =>
  typeof value === "string" && value.trim().length === 0;

/**
 * Escape XML text.
 */
export function escapePromptXmlText(value: string): string {
  return escape(value);
}

/**
 * Escape XML attr.
 */
export function escapePromptXmlAttr(value: string): string {
  return escape(value);
}

export function getFileExtension(filePath: string): string {
  const normalized = normalize(normalizeRepoPath(filePath));
  return extname(normalized);
}

export function getFileName(filePath: string): string {
  const normalized = normalize(normalizeRepoPath(filePath));
  return basename(normalized);
}

export function uniqueNormalizedPaths(paths: Iterable<string>, limit?: number): string[] {
  const list = compact(Array.from(paths).map((p) => normalize(normalizeRepoPath(p))));
  const result = uniq(list);

  return limit != null ? result.slice(0, limit) : result;
}

export function uniqueObjectPaths<T extends { path: string }>(
  items: Iterable<T>,
  limit?: number
): string[] {
  return uniqueNormalizedPaths(
    Array.from(items).map((i) => i.path),
    limit
  );
}

export function uniqueStringPaths(
  paths: Iterable<false | null | string | undefined>,
  limit?: number
): string[] {
  const list = compact(Array.from(paths)).map((p) => normalize(p as string));
  const result = uniq(list);

  return limit != null ? result.slice(0, limit) : result;
}

export function excludePath(
  paths: Iterable<string>,
  excludedPath: string,
  limit?: number
): string[] {
  const normalizedExcluded = normalize(normalizeRepoPath(excludedPath));

  const filtered = Array.from(paths).filter(
    (p) => normalize(normalizeRepoPath(p)) !== normalizedExcluded
  );

  return uniqueNormalizedPaths(filtered, limit);
}

import { getEncoding } from "js-tiktoken";

const encoding = getEncoding("o200k_base");

export async function countTokens(text: string): Promise<number> {
  if (!text || text.trim().length === 0) return 0;

  try {
    const baseCount = encoding.encode(text).length;

    const safetyFactor = 1.2;

    return Math.ceil(baseCount * safetyFactor);
  } catch (error) {
    console.error("Tokenization failed, using fallback:", error);
    return Math.ceil(text.length / 3);
  }
}

import fs from "node:fs/promises";
import path from "node:path";
import { compact } from "es-toolkit";
import fg from "fast-glob";
import { isBinaryFile } from "isbinaryfile";
import { normalize } from "pathe";

import { REALTIME_CONFIG } from "@/shared/constants/realtime";

import { ProjectPolicy } from "../engine/core/project-policy";
import { prisma } from "../infrastructure/db";
import { logger } from "../infrastructure/logger";
import { realtimeServer } from "../infrastructure/realtime";

export async function handleError(
  error: unknown,
  analysisId: string,
  channelName: string,
  tempPath: string
) {
  const message = error instanceof Error ? error.message : "Unknown error";
  logger.error({
    analysisId,
    error: error instanceof Error ? { message: error.message, stack: error.stack } : String(error),
    msg: "TASK_ERROR",
  });

  await cleanup(tempPath);

  await prisma.analysis.update({
    data: {
      error: message,
      message: "Analysis failed",
      status: "FAILED",
    },
    where: { publicId: analysisId },
  });

  await realtimeServer.channels
    .get(channelName)
    .publish(REALTIME_CONFIG.events.user.analysisProgress, {
      analysisId,
      message,
      status: "FAILED",
    });
}

export async function cleanup(dirPath: string) {
  const path = normalize(dirPath);
  await fs.rm(path, { force: true, recursive: true });
}

export async function readAndFilterFiles(basePath: string, selectedFiles: string[]) {
  const entries = await fg(selectedFiles, {
    absolute: false,
    cwd: basePath,
    dot: true,
    followSymbolicLinks: false,
    onlyFiles: true,
  });

  if (entries.length === 0) {
    throw new Error("No valid files found to analyze in the specified path");
  }

  const filePromises = selectedFiles.map(async (filePath) => {
    if (ProjectPolicy.isSensitive(filePath)) {
      logger.warn({
        filePath,
        msg: "Skipping sensitive file from analysis context",
      });
      return null;
    }

    const fullPath = path.join(basePath, filePath);

    try {
      const buffer = await fs.readFile(fullPath);
      const isBinary = await isBinaryFile(buffer);

      if (isBinary) return null;

      return { content: buffer.toString("utf-8"), path: filePath };
    } catch (error) {
      logger.warn({
        error:
          error instanceof Error ? { message: error.message, stack: error.stack } : String(error),
        filePath,
        msg: "Failed to read file",
      });
      return null;
    }
  });

  const settledFiles = await Promise.all(filePromises);

  const validFiles = compact(settledFiles);

  if (validFiles.length === 0) throw new Error("No valid text files found to analyze");
  return validFiles;
}

